#!/usr/bin/env python3

# =============================================================================
# MY-PLEX GLOSSARY
# Terms used in my-plex that differ from or extend Plex's own naming.
# =============================================================================
#
# KEY          A my-plex cache key uniquely identifying one Plex object.
#              Format: "<Type>:<plex_rating_key>"  e.g.  Movie:12345
#              Plex calls this the "rating key" or "ratingKey" internally;
#              my-plex prefixes it with the type for human readability.
#              Displayed as the first column in all tabular output.
#
# SERIES       A TV show / series.  Plex internally calls this "Show" and
#              uses metadata_type=2.  my-plex uses "series" everywhere in
#              user-facing text; "show" is accepted as a synonym.
#
# RATING       The external audience score for a media item.
#              Plex calls this "audienceRating".  Sources vary by library agent:
#                  tv.plex.agents.movie  → IMDB score  (+ RT Tomatometer if available)
#                  tv.plex.agents.series → TMDB vote average
#                  com.plexapp.agents.*  → depends on agent
#              my-plex always calls this "rating" (never "audienceRating").
#
# CRITICS      The Rotten Tomatoes Tomatometer score.
#              Plex calls this "criticsRating".  Only populated for libraries
#              using tv.plex.agents.movie.  Empty for IMDB/TMDB agents.
#              my-plex calls this "critics" (filter: critics>80).
#
# STARS        The user's personal Plex star rating (0–5, half-star steps).
#              Plex stores this as "userRating" on a 0–10 scale internally;
#              my-plex exposes it as 0–5 stars (filter: stars>3.5).
#
# LIBRARY      A Plex library section (e.g. "movies.en", ",unsorted").
#              Identified by its title string.  my-plex uses the library name
#              as a scope prefix: my-plex movies.en --problems
#
# SCOPE        An optional prefix to any command that narrows its target:
#              a library name, a title/filename, a KEY, or filter tokens.
#              e.g.  my-plex ,unsorted --broken
#                    my-plex "Ted Lasso" --missing
#                    my-plex type:series lang:de --list
#
# FILTER TOKEN A key:value or key>value expression used as a SCOPE to select
#              a subset of media items without specifying a library:
#                  type:movie      watched:no      lang:de
#                  bitrate>2       resolution:1080p codec:h265
#                  rating>7        critics>80       stars>3.5
#                  year>2015       added>2024       size>1gb
#              Tokens are combined with AND (implicit).  See --help media.
#
# ON-DISK LABEL   A label embedded in a filename or sidecar file on disk,
#              as opposed to a Plex label stored only in the Plex database.
#              Example: a file named "Movie [reencode].mkv" carries the
#              on-disk label "reencode".  Used by --reencode --mark.
#
# =============================================================================

# Coding guidelines, architecture docs, and test policies: see README.md
# errCode range: 1001..1070

# ---------------------------------------------------------------------------
# Venv bootstrap: ensure we run inside a venv with plexapi+readchar installed.
# If not, create the venv, install deps, and re-exec ourselves in it.
# ---------------------------------------------------------------------------
import os
import subprocess
import sys

VENV_DIR = os.path.expanduser("~/.python.venv/my-plex")
VENV_PYTHON = os.path.join(VENV_DIR, "bin", "python3")
VENV_DEPS = ["plexapi", "readchar"]


def _venv_has_deps():
    """Check if venv exists and has required packages."""
    if not os.path.isfile(VENV_PYTHON):
        return False
    site_packages = os.path.join(VENV_DIR, "lib")
    if not os.path.isdir(site_packages):
        return False
    # Check for plexapi AND readchar in site-packages
    found = set()
    for d in os.listdir(site_packages):
        pkg_dir = os.path.join(site_packages, d, "site-packages")
        if os.path.isdir(pkg_dir):
            for dep in VENV_DEPS:
                if os.path.isdir(os.path.join(pkg_dir, dep)):
                    found.add(dep)
    return found == set(VENV_DEPS)


def _bootstrap_venv():
    """Create venv, install deps, and re-exec."""
    print(f"\n >>> Creating python virtualenv '{VENV_DIR}'...\n", file=sys.stderr)

    rc = subprocess.call([sys.executable, "-m", "venv", VENV_DIR])
    if rc != 0:
        print(f"\n  ERROR: Failed to create venv at {VENV_DIR}\n", file=sys.stderr)
        sys.exit(1)

    pip = os.path.join(VENV_DIR, "bin", "pip")
    rc = subprocess.call([pip, "install"] + VENV_DEPS)
    if rc != 0:
        print(f"\n  ERROR: Failed to install dependencies: {', '.join(VENV_DEPS)}\n", file=sys.stderr)
        sys.exit(1)

    print(f"\n >>> DONE creating python virtualenv '{VENV_DIR}'.", file=sys.stderr)
    print("=" * 64, file=sys.stderr)

    # Re-exec with venv python, preserving all arguments
    os.execv(VENV_PYTHON, [VENV_PYTHON] + sys.argv)


# If we're not already running inside our venv, bootstrap it
if os.path.realpath(sys.executable) != os.path.realpath(VENV_PYTHON):
    if not _venv_has_deps():
        _bootstrap_venv()
    # Venv exists and has deps — re-exec inside it
    os.execv(VENV_PYTHON, [VENV_PYTHON] + sys.argv)


# ---------------------------------------------------------------------------
# Zsh completions: install/update on every run (fast no-op if unchanged)
# ---------------------------------------------------------------------------
def _install_zsh_completions():
    """Write zsh completion file and patch .zshrc fpath if needed."""
    completion_dir = os.path.expanduser("~/.zsh/completions")
    completion_file = os.path.join(completion_dir, "_my-plex")

    completion_content = r'''#compdef my-plex

# Filter token completions for key:value shorthand tokens
# e.g.  type:<TAB>  →  movie series
#        ty<TAB>    →  type:
_my-plex-filter-token() {
    local cur="$1"

    # Complete bare token names (ty → type:, la → lang:/label:, ...)
    # _describe format: 'completion-value:description shown in menu'
    local -a token_keys
    token_keys=(
        'type:filter by media type (movie/series)'
        'lang:filter by audio language (en/de/fr)'
        'watched:filter by watch status (yes/no)'
        'resolution:filter by resolution (1080p/4k/720p)'
        'codec:filter by video codec (h265/h264)'
        'year:filter by release year'
        'genre:filter by genre (action/drama/…)'
        'label:filter by Plex label'
        'size:filter by file size (e.g. >1gb)'
        'duration:filter by duration (e.g. >2h)'
        'stars:filter by personal star rating (e.g. >3.5, scale 0-5)'
        'rating:filter by audience score (e.g. >7)'
        'critics:filter by RT Tomatometer (e.g. >80)'
        'added:filter by year added (e.g. >2024)'
        'bitrate:filter by bitrate (e.g. >2mbps)'
    )

    case "$cur" in
        type:*)
            compadd -S '' -P 'type:' -- movie series show
            ;;
        lang:*|language:*)
            compadd -S '' -P "${cur%%:*}:" -- en de fr english german french
            ;;
        watched:*)
            compadd -S '' -P 'watched:' -- yes no
            ;;
        resolution:*)
            compadd -S '' -P 'resolution:' -- 1080p 4k 720p 480p 2160p
            ;;
        codec:*)
            compadd -S '' -P 'codec:' -- h265 h264 hevc avc av1 mpeg4
            ;;
        genre:*)
            # Fetch genres from cache via my-plex --complete-genres
            local -a genres
            genres=( ${(f)"$(my-plex --complete genres 2>/dev/null)"} )
            if [[ ${#genres} -gt 0 ]]; then
                compadd -S '' -P 'genre:' -- $genres
            fi
            ;;
        label:*)
            # Fetch labels from cache via my-plex --complete-labels
            local -a labels
            labels=( ${(f)"$(my-plex --complete labels 2>/dev/null)"} )
            if [[ ${#labels} -gt 0 ]]; then
                compadd -S '' -P 'label:' -- $labels
            fi
            ;;
        *)
            # Complete token key names — suffix ':' added automatically, no space after
            _describe -t filter-tokens 'filter token' token_keys -S ''
            ;;
    esac
}

_my-plex() {
    local curcontext="$curcontext" state line
    typeset -A opt_args

    local cur="${words[$CURRENT]}"

    # Handle key:value filter tokens for the current word
    if [[ "$cur" != -* ]]; then
        case "$cur" in
            type:*|lang:*|language:*|watched:*|resolution:*|codec:*|genre:*|label:*)
                _my-plex-filter-token "$cur"
                return
                ;;
            ty*|la*|wa*|re*|co*|ye*|ge*|si*|du*|ra*|ad*|bi*)
                # Could be a filter token prefix — offer token completions alongside other options
                _my-plex-filter-token "$cur"
                ;;
        esac
    fi

    local has_duplicates=0
    local has_list=0
    local has_update_cache=0
    local has_broken=0
    local has_resolve=0
    local has_problems=0
    for word in $words; do
        if [[ "$word" == "--list-duplicates" ]]; then
            has_duplicates=1
            has_list=1
        elif [[ "$word" == "--duplicates" ]]; then
            has_duplicates=1
            has_list=1
        elif [[ "$word" == "--broken" ]]; then
            has_broken=1
            has_list=1
        elif [[ "$word" == "--resolve" ]]; then
            has_resolve=1
            has_duplicates=1
            has_list=1
        elif [[ "$word" == "--list" ]]; then
            has_list=1
        elif [[ "$word" == "--update-cache" ]] || [[ "$word" == "--rebuild-cache" ]] || [[ "$word" == "-U" ]]; then
            has_update_cache=1
        fi
    done

    local -a args_spec
    args_spec=(
        '--info[Show system information (cache, server, libraries)]'
        '--verify-cache[Verify cache consistency with Plex server]'
        '(-U --update-cache --rebuild-cache)'{-U,--update-cache,--rebuild-cache}'[Update/rebuild cache from server]'
        '(-O --offline)'{-O,--offline}'[Work with cached information only (offline mode)]'
        '--plex-url[Plex server URL]:url:'
        '--plex-token[Plex authentication token]:token:'
        '--plex-xml-url[Plex XML URL from View XML]:xml-url:'
        '--list[List all media items]'
        '--filter[Synonym for --list; accepts filter expressions]'
        '--list-libraries[List all Plex libraries]'
        '--list-duplicates[List only duplicate media items]'
        '--broken[Show only potentially truncated/broken files]'
        '--excess-versions[List entries with too many file versions]:limit:'
        '--problems[Run all problem detection checks (add -V for details)]'
        '--reencode[List media files with unreasonably high bitrate (reencode candidates)]'
        '--mark[Detect high-bitrate candidates and write on-disk labels (use with --reencode; respects --try)]'
        '--detect[Deprecated alias for --reencode (candidates are now always listed)]'
        '--force[With --reencode --mark: also remove labels from items below threshold]'
        '--scan[Trigger Plex library scan + metadata refresh + cache update]'
        '--rename[Rename episode files according to EPISODE_NAME_PATTERN config]'
        '--resolve[Interactive duplicate resolution (auto-enables --list --duplicates)]'
        '(--collections --collection)'{--collections,--collection}'[List collections in a library]'
        '--list-labels[List all labels and item counts]'
        '--list-label[List media with specific label]:label:'
        '--add-label[Add label to media]:label and id:'
        '--remove-label[Remove label from media]:label and id:'
        '(--no-audio-language --no-language)'{--no-audio-language,--no-language}'[List media with missing audio language info]'
        '--en[List media with English audio]'
        '--de[List media with German audio]'
        '--fr[List media with French audio]'
        '--watched[List watched media items]'
        '--unwatched[List unwatched media items]'
        '(--remove --rm)'{--remove,--rm}'[Trash media files (optionally specify version indices/ranges)]:indices:'
        '(--delete --del)'{--delete,--del}'[Delete Plex entry (metadata only)]'
        '--test[Run regression tests]'
        '(- -V -VV --verbose --very-verbose)'{-V,--verbose}'[Verbose output]'
        '(- -V -VV --verbose --very-verbose)'{-VV,--very-verbose}'[Very verbose output]'
        '(- -D -DD --debug --deep-debug)'{-D,--debug}'[Debug mode]'
        '(- -D -DD --debug --deep-debug)'{-DD,--deep-debug}'[Deep debug mode]'
        '(- -h --help)'{-h,--help}'[Show help message]'
    )

    if [[ $has_update_cache -eq 1 ]]; then
        args_spec+=('--force[Force complete cache rebuild from scratch]')
    fi

    if [[ $has_list -eq 1 ]] && [[ $has_duplicates -eq 0 ]]; then
        args_spec+=('--duplicates[Filter --list to show only duplicates]')
    fi

    if [[ $has_list -eq 1 ]]; then
        args_spec+=('--type[Filter by media type]:type:(movie series show)')
    fi

    _arguments -s : '*::arg:_default' $args_spec
}

_my-plex "$@"
'''

    os.makedirs(completion_dir, exist_ok=True)

    # Only write if content changed
    try:
        with open(completion_file, 'r') as f:
            if f.read() == completion_content:
                return  # unchanged, nothing to do
    except FileNotFoundError:
        pass

    with open(completion_file, 'w') as f:
        f.write(completion_content)

    # Patch .zshrc fpath if needed
    zshrc = os.path.expanduser("~/.zshrc")
    if os.path.islink(zshrc):
        zshrc_real = os.path.realpath(zshrc)
    elif os.path.isfile(zshrc):
        zshrc_real = zshrc
    else:
        return  # no .zshrc to patch

    try:
        with open(zshrc_real, 'r') as f:
            zshrc_content = f.read()
    except Exception:
        return

    if '.zsh/completions' in zshrc_content:
        return  # already configured

    if 'source.*oh-my-zsh.sh' in zshrc_content or 'oh-my-zsh.sh' in zshrc_content:
        # Insert before oh-my-zsh source line
        import re as _re_boot
        zshrc_content = _re_boot.sub(
            r'(source.*oh-my-zsh\.sh)',
            f'# my-plex zsh completions\nfpath=({completion_dir} $fpath)\n\\1',
            zshrc_content, count=1)
        with open(zshrc_real, 'w') as f:
            f.write(zshrc_content)
    else:
        with open(zshrc_real, 'a') as f:
            f.write(f"\n# my-plex zsh completions\nfpath=({completion_dir} $fpath)\nautoload -Uz compinit && compinit\n")


_install_zsh_completions()

