    @staticmethod
    def detect_if_of_OBJ_TYPE(args, obj):   # return True or False - if obj is a <CLASSNAME> PLEX_OBJ
        # Fast path: check if obj is ID:<num> that matches cache — no API needed
        if obj.upper().startswith('ID:'):
            try:
                numeric_id = int(obj[3:])
                for key, cached_obj in PLEX_Media.OBJ_BY_ID.items():
                    if int(cached_obj.get('id', 0)) == numeric_id:
                        return True
                return False
            except (ValueError, TypeError):
                pass
        # Fast path: check if obj is a full cache key (e.g. "Show:4925", "Episode:2579")
        if obj in PLEX_Media.OBJ_BY_ID:
            return True
        # Recognize Type:digits pattern even if not yet in cache (e.g. key from another session)
        import re
        if re.match(r'^(Movie|Show|Season|Episode|Collection):\d+$', obj):
            return True
        # Fast path: cache title search (exact or partial, case-insensitive) — no API needed
        search_lower = obj.lower()
        for cached_obj in PLEX_Media.OBJ_BY_ID.values():
            title_lower = cached_obj.get('title', '').lower()
            orig_lower = (cached_obj.get('originalTitle', '') or '').lower()
            if search_lower == title_lower or search_lower == orig_lower:
                return True
            if search_lower in title_lower or (orig_lower and search_lower in orig_lower):
                return True
        # Fast path: cache filepath search — no API needed
        normalized = os.path.normpath(obj)
        for filepath in get_alternative_paths(normalized):
            if filepath in PLEX_Media.OBJ_BY_FILEPATH:
                return True
        return False

    @staticmethod
    def execute_cmd(args, obj, obj_args):         # Handling action(s) on media
        if obj_args.delete and not obj_args.remove:
            err(1082, "--del requires --rm (Plex API delete also removes files from disk).\n"
                "  Use --rm --del to explicitly confirm file removal.\n"
                "  See --help del for details.")
        if obj_args.info:               PLEX_Media.get_info(obj)
        if obj_args.refresh:            PLEX_Media.refresh(obj)
        if obj_args.remove:             PLEX_Media.remove(obj, rm_spec=obj_args.remove)
        if obj_args.delete:             PLEX_Media.delete(obj)
        if obj_args.get_watched:        PLEX_Media.get_watched_status(obj)
        if obj_args.get_view_offset:    PLEX_Media.get_view_offset(obj)
        if obj_args.get_user_rating:    PLEX_Media.get_user_rating(obj)
        if obj_args.clear_user_rating:  PLEX_Media.clear_user_rating(obj)
        if obj_args.set_unwatched:      PLEX_Media.set_unwatched(obj)
        if obj_args.set_watched:        PLEX_Media.set_watched(obj)
        if obj_args.set_view_offset:    PLEX_Media.set_view_offset(obj, int(obj_args.set_view_offset))
        if obj_args.set_user_rating:    PLEX_Media.set_user_rating(obj, float(obj_args.set_user_rating))
        if safe_getattr(obj_args, 'missing', False):
            # Resolve media object to a show — use cache, not API
            cmd_missing(obj, source_override=safe_getattr(obj_args, 'source', None))
        if safe_getattr(obj_args, 'unsorted', False):
            # Resolve media object to find the show key
            found_items = resolve_cache_items(obj) if isinstance(obj, str) else [obj]
            for item in found_items:
                if isinstance(item, tuple):
                    item_key, item = item
                else:
                    item_key = f"{item['type']}:{item['id']}"
                if item.get('type') == 'Show':
                    print(f"\n--- Unsorted Check for '{item.get('title', '?')}' ---")
                    PLEX_Media._list_unsorted(show_key_filter=item_key)
        if safe_getattr(obj_args, 'rename', False):
            dry_run = safe_getattr(obj_args, 'dry_run', False) or safe_getattr(args, 'dry_run', False)
            PLEX_Media.rename_episodes(obj, dry_run=dry_run)
        if safe_getattr(obj_args, 'reencode', False):
            dry_run = safe_getattr(obj_args, 'dry_run', False) or safe_getattr(args, 'dry_run', False)
            force_mark = safe_getattr(obj_args, 'mark', False)
            PLEX_Media.reencode_item(obj, dry_run=dry_run, force_mark=force_mark)

