    @staticmethod
    def rename_episodes(media_identifier, dry_run=False):
        """Rename episode files according to EPISODE_NAME_PATTERN config.
        media_identifier can be a string (title, ID:xxx, cache key) or a dict.
        Only works for Show and Episode objects."""
        # Resolve identifier to cache object(s) — same as --info
        if isinstance(media_identifier, dict):
            obj = media_identifier
            key = f"{obj['type']}:{obj['id']}"
        else:
            found_items = resolve_cache_items(media_identifier)
            if not found_items:
                print(f"ERROR: No items found matching '{media_identifier}'")
                return
            if len(found_items) > 1:
                # Multiple matches — filter to Show/Season/Episode only
                show_items = [(k, o) for k, o in found_items if o.get('type') in ('Show', 'Season', 'Episode')]
                if not show_items:
                    print(f"ERROR: Found {len(found_items)} items matching '{media_identifier}', but none are Show, Season, or Episode type")
                    return
                if len(show_items) > 1:
                    # Multiple shows/episodes — check if there's exactly one Show
                    shows = [(k, o) for k, o in show_items if o.get('type') == 'Show']
                    if len(shows) == 1:
                        key, obj = shows[0]
                    else:
                        print(f"Multiple items found matching '{media_identifier}':")
                        for k, o in show_items:
                            print(f"  {k}  {o.get('title', '')}")
                        print("Please specify a more precise identifier.")
                        return
                else:
                    key, obj = show_items[0]
            else:
                key, obj = found_items[0]

        # Check that the object belongs to a Show-type library
        obj_library = obj.get('library', '')
        lib_type = PLEX_Library.OBJ_DICT_TYPE.get(obj_library, '')
        if lib_type != 'Show':
            print(f"ERROR: --rename is only available for objects in Show libraries, not {lib_type} library '{obj_library}'")
            return

        pattern = EPISODE_NAME_PATTERN

        if obj['type'] == 'Show':
            show_key = key
            episode_keys = PLEX_Media._collect_episode_keys_for_show(show_key)
            print(f"\n{obj['title']} ({len(episode_keys)} episodes)")
        elif obj['type'] == 'Season':
            # Find the show this season belongs to, then collect episodes for this season only
            show_key = obj.get('show_key', '')
            S_str = obj.get('S_str', '')
            show_obj = PLEX_Media.OBJ_BY_ID.get(show_key, {})
            show_title = show_obj.get('title', '?')
            episode_keys = []
            season_episodes = PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key, {}).get(S_str, {})
            for e_str, versions in season_episodes.items():
                for version_str, ep_keys in versions.items():
                    episode_keys.extend(ep_keys)
            print(f"\n{show_title} {S_str} ({len(episode_keys)} episodes)")
        elif obj['type'] == 'Episode':
            episode_keys = [key]
        else:
            print(f"ERROR: --rename cannot operate on {obj['type']} objects (no episode files)")
            return

        renamed_count = 0
        skipped_count = 0
        error_count = 0
        for ep_key in sorted(episode_keys, key=lambda k: (PLEX_Media.OBJ_BY_ID.get(k, {}).get('S_idx', 0), PLEX_Media.OBJ_BY_ID.get(k, {}).get('E_idx', 0))):
            ep = PLEX_Media.OBJ_BY_ID.get(ep_key)
            if not ep:
                continue
            result = PLEX_Media._rename_single_episode(ep, ep_key, pattern, dry_run)
            if result == 'renamed':
                renamed_count += 1
            elif result == 'skipped':
                skipped_count += 1
            elif result == 'error':
                error_count += 1

        if not dry_run and renamed_count > 0:
            update_and_save_cache(build_media_cache_dict())

        pfx = "[DRY-RUN] " if dry_run else ""
        print(f"\n{pfx}{renamed_count} renamed, {skipped_count} already correct" + (f", {error_count} errors" if error_count else ""))

    @staticmethod
    def _collect_episode_keys_for_show(show_key):
        """Collect all episode cache keys for a show from OBJ_BY_SHOW_EPISODES."""
        keys = []
        show_episodes = PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key, {})
        for s_str, episodes_by_e in show_episodes.items():
            for e_str, versions in episodes_by_e.items():
                for version_str, ep_keys in versions.items():
                    keys.extend(ep_keys)
        return keys

    @staticmethod
    def _rename_single_episode(ep, ep_key, pattern, dry_run):
        """Rename a single episode file according to pattern.
        Returns 'renamed', 'skipped', or 'error'."""
        from datetime import datetime

        # Build variable dict for pattern substitution
        var = {}
        var['S0XE0X'] = ep.get('S0XE0X', '')
        var['TITLE'] = ep.get('title', '') or ''
        var['ORIGINALTITLE'] = ep.get('originalTitle', '') or ''
        var['SERIES'] = ep.get('series', '') or ''
        var['YEAR'] = str(ep.get('year', '')) if ep.get('year') else ''

        # Library language from cache
        lib_name = ep.get('library', '')
        lang = CACHE.get('library_stats', {}).get('language', {}).get(lib_name, '')
        if lang == 'xn':
            lang = 'none'
        var['LANG'] = lang

        # Watched status
        view_count = ep.get('viewCount', 0) or 0
        var['WATCHED'] = 'vu' if view_count > 0 else 'nv'
        var['VIEWCOUNT'] = str(view_count)

        last_viewed = ep.get('lastViewedAt')
        if last_viewed:
            try:
                var['WATCHEDDATE'] = datetime.fromtimestamp(last_viewed).strftime('%Y-%m-%d')
            except (OSError, ValueError):
                var['WATCHEDDATE'] = ''
        else:
            var['WATCHEDDATE'] = ''

        # Technical info
        var['RESOLUTION'] = ep.get('resolution', '') or ''
        var['VIDEO_CODEC'] = ep.get('video_codec', '') or ''
        var['AUDIO_CODEC'] = ep.get('audio_codec', '') or ''
        duration = ep.get('duration')
        var['DURATION'] = format_duration(duration, 'm') if duration else ''

        # Process each file version
        files = ep.get('files', {})
        if not files:
            # Single file
            filepath = ep.get('file', '')
            if not filepath:
                return 'skipped'
            files = {'_single_': {'filepath': filepath}}

        result = 'skipped'
        for version_str, file_info in files.items():
            filepath = file_info.get('filepath', '') if isinstance(file_info, dict) else file_info
            if not filepath:
                continue

            # Get extension from current file
            _, ext = os.path.splitext(filepath)
            ext = ext.lstrip('.')

            # Format the pattern
            try:
                new_basename = pattern.format(**var)
            except KeyError as e:
                print(f"  ERROR: Unknown pattern variable {e} in EPISODE_NAME_PATTERN")
                return 'error'

            # Strip trailing whitespace (e.g. if {TITLE} is empty: "Series S01E02 " → "Series S01E02")
            new_basename = new_basename.strip()

            # Sanitize filename: replace unsafe characters
            for ch in ['/', '\\', ':', '*', '?', '"', '<', '>', '|']:
                new_basename = new_basename.replace(ch, '_')

            # Add extension
            new_filename = f"{new_basename}.{ext}" if ext else new_basename

            # Compare with current filename
            current_filename = os.path.basename(filepath)
            if current_filename == new_filename:
                continue  # Already correct

            current_dir = os.path.dirname(filepath)
            new_filepath = os.path.join(current_dir, new_filename)

            pfx = "[DRY-RUN] " if dry_run else ""
            print(f"  {pfx}{new_filename}  \u2190  {current_filename}")

            if not dry_run:
                success, actual_new_path = rename_file(filepath, new_filename, remote_host=PLEX_DB_REMOTE_HOST)
                if success:
                    # Update cache
                    old_filepath = filepath
                    new_actual = actual_new_path if actual_new_path else new_filepath

                    # Update OBJ_BY_FILEPATH
                    if old_filepath in PLEX_Media.OBJ_BY_FILEPATH:
                        del PLEX_Media.OBJ_BY_FILEPATH[old_filepath]
                    PLEX_Media.OBJ_BY_FILEPATH[new_actual] = ep_key

                    # Update files dict
                    if version_str != '_single_':
                        if isinstance(ep['files'][version_str], dict):
                            ep['files'][version_str]['filepath'] = new_actual
                    ep['file'] = new_actual

                    # Update OBJ_BY_MOVIE / OBJ_BY_SHOW_EPISODES filepath references
                    # (OBJ_BY_MOVIE stores {version: filepath} for movies, not episodes)

                    result = 'renamed'
                else:
                    print(f"    ERROR: rename failed for {current_filename}")
                    result = 'error'
            else:
                result = 'renamed'

        return result

    ############################################################
    ###### REENCODE ITEM (force-mark a specific item):

    @staticmethod
    def reencode_item(media_identifier, dry_run=False, force_mark=False):
        """List reencode candidates for a specific item; with force_mark=True write on-disk label
        at the appropriate level (series dir, season dir, or episode file) regardless of threshold.

        media_identifier: cache key (e.g. 'Show:102639'), title string, or ID:xxx.
        """
        # Prefer direct cache key lookup to avoid broad title-search side effects
        if isinstance(media_identifier, str) and media_identifier in PLEX_Media.OBJ_BY_ID:
            found_items = [(media_identifier, PLEX_Media.OBJ_BY_ID[media_identifier])]
        elif isinstance(media_identifier, str):
            found_items = resolve_cache_items(media_identifier)
        else:
            found_items = [media_identifier]
        if not found_items:
            print(f"ERROR: No items found matching '{media_identifier}'")
            return

        # Collect all episode/movie keys for this item
        obj_keys = []
        for item in found_items:
            if isinstance(item, tuple):
                key, obj = item
            else:
                obj = item
                key = f"{obj['type']}:{obj['id']}"
            obj_type = obj.get('type', '')
            if obj_type == 'Show':
                obj_keys.extend(PLEX_Media._collect_episode_keys_for_show(key))
            elif obj_type == 'Season':
                show_key = obj.get('show_key', '')
                s_str = obj.get('S_str', '')
                if show_key and s_str:
                    season_eps = PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key, {}).get(s_str, {})
                    for e_str, versions in season_eps.items():
                        for ver, ep_keys in versions.items():
                            obj_keys.extend(ep_keys)
            elif obj_type in ('Movie', 'Movie*', 'Episode', 'Episode*'):
                obj_keys.append(key)

        if not obj_keys:
            print(f"  No media files found for '{media_identifier}'.")
            return

        reencode_cfg    = PROBLEMS2DISK.get('reencode', {})
        labeltext       = reencode_cfg.get('LABELTEXT_ON_DISK', 'reencode')
        remove_existing = reencode_cfg.get('REMOVE_EXISTING_LABELS', False)

        # Always show what candidates exist above threshold
        print(f"\n--- Reencode Candidates for '{media_identifier}' (threshold: {REENCODE_THRESHOLD_MBPS} Mbps) ---")
        PLEX_Media._list_reencode_candidates(obj_keys, library_name=None)

        if not force_mark:
            return

        # Force-mark: label at the highest applicable level (series → season → file),
        # bypassing the bitrate threshold. We derive the series/season/file path from obj_keys.
        pfx = "[DRY-RUN] " if dry_run else ""
        print(f"\n--- {pfx}Force-labeling with [{labeltext}] ---")

        label_marker  = f"{ONDISK_LABEL_START_MARKER}{labeltext}{ONDISK_LABEL_END_MARKER}"

        def _add_label(name):
            if label_marker in name:
                return name
            return name.rstrip() + f" {label_marker}"

        # Group episode keys by show → figure out highest level to label
        show_groups = {}  # show_key → {s_str → [fp, ...]}
        movie_fps   = []

        for key in set(obj_keys):
            obj = PLEX_Media.OBJ_BY_ID.get(key)
            if not obj:
                continue
            obj_type = obj.get('type', '')
            files_dict = obj.get('files', {})
            fps = [fi.get('filepath', '') for fi in files_dict.values() if fi.get('filepath')]
            if obj_type in ('Movie', 'Movie*'):
                movie_fps.extend(fps)
            elif obj_type in ('Episode', 'Episode*'):
                show_key = obj.get('show_key', '')
                s_str    = obj.get('S_str', 'S?')
                if show_key:
                    show_groups.setdefault(show_key, {}).setdefault(s_str, []).extend(fps)

        renamed = 0
        renamed_dirs = {}  # old_dir → new_dir (for updating cache filepaths)

        def _do_rename_tracked(path):
            """Rename and track old→new mapping for cache filepath updates."""
            parent = os.path.dirname(path)
            old_name = os.path.basename(path)
            new_name = _add_label(old_name)
            if new_name == old_name:
                print(f"  Already labeled: {old_name}")
                return True
            if dry_run:
                print(f"  {pfx}Would rename: {old_name}")
                print(f"              → {new_name}")
                renamed_dirs[path] = os.path.join(parent, new_name)
                return True
            # Use PLEX_DB_REMOTE_HOST for SSH writes (never assume local mount)
            ok, _ = my_plex_file_operation('RENAME', path, PLEX_DB_REMOTE_HOST, new_filename=new_name)
            if ok:
                print(f"  Renamed: {old_name}\n        → {new_name}")
                renamed_dirs[path] = os.path.join(parent, new_name)
            else:
                print(f"  WARNING: rename failed: {old_name}")
            return ok

        # Movies: label movie directory
        for fp in movie_fps:
            movie_dir = os.path.dirname(fp)
            if _do_rename_tracked(movie_dir):
                renamed += 1

        # Series: try to label at series dir level first; fall back to season/file
        for show_key, seasons in show_groups.items():
            all_seasons_data = PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key, {})
            non_special = [s for s in all_seasons_data if s != 'S00']
            flagged_non_special = [s for s in seasons if s != 'S00']
            show_obj  = PLEX_Media.OBJ_BY_ID.get(show_key, {})
            show_title = show_obj.get('title', show_key)

            # Sample a filepath to derive directories
            sample_fp = next((fp for s_fps in seasons.values() for fp in s_fps if fp), None)
            if not sample_fp:
                print(f"  WARNING: no filepath found for {show_key}")
                continue

            season_dir = os.path.dirname(sample_fp)
            series_dir = os.path.dirname(season_dir)

            if set(flagged_non_special) >= set(non_special) and non_special:
                # All seasons covered → label series directory
                if _do_rename_tracked(series_dir):
                    renamed += 1
            else:
                # Only some seasons → label each season directory
                for s_str, fps in seasons.items():
                    s_fp = next((fp for fp in fps if fp), None)
                    if not s_fp:
                        continue
                    s_dir = os.path.dirname(s_fp)
                    all_in_season = set(PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key, {}).get(s_str, {}).keys())
                    flagged_in_season = set(
                        obj.get('E_str', '')
                        for k in obj_keys
                        if (obj := PLEX_Media.OBJ_BY_ID.get(k)) and obj.get('show_key') == show_key and obj.get('S_str') == s_str
                    )
                    if flagged_in_season >= all_in_season and all_in_season:
                        # Whole season → label season directory
                        if _do_rename_tracked(s_dir):
                            renamed += 1
                    else:
                        # Individual episodes → label files
                        for fp in fps:
                            if _do_rename_tracked(fp):
                                renamed += 1

        print(f"\n  {'[DRY-RUN] ' if dry_run else ''}Total: {renamed} path(s) labeled with [{labeltext}]")

        # Update cache filepaths and ondisk_labels after successful rename(s)
        if renamed_dirs and not dry_run:
            # Update all filepaths in cache that contain renamed directory paths
            updated_fp_count = 0
            for key in obj_keys:
                obj = PLEX_Media.OBJ_BY_ID.get(key)
                if not obj:
                    continue
                # Update obj['file'] shortcut field
                obj_file = obj.get('file', '')
                if obj_file:
                    for old_dir, new_dir in renamed_dirs.items():
                        if obj_file.startswith(old_dir + '/') or obj_file == old_dir:
                            obj['file'] = new_dir + obj_file[len(old_dir):]
                            break
                # Update files[...]['filepath'] entries
                files_dict = obj.get('files', {})
                for fk, fi in files_dict.items():
                    fp = fi.get('filepath', '')
                    if not fp:
                        continue
                    for old_dir, new_dir in renamed_dirs.items():
                        if fp.startswith(old_dir + '/') or fp == old_dir:
                            fi['filepath'] = new_dir + fp[len(old_dir):]
                            updated_fp_count += 1
                            break
            print(f"  Updated {updated_fp_count} filepath(s) in cache.")
            # Refresh ondisk_labels from updated filepaths and save
            refresh_ondisk_labels_from_cache()
            update_and_save_cache({'obj_by_id': PLEX_Media.OBJ_BY_ID,
                                   'ondisk_labels_index': PLEX_Media.OBJ_BY_ONDISK_LABEL})
            print(f"  Cache saved. Run --scan to update Plex library paths.")

    ############################################################
    ###### HELPER FUNCTIONS:

    @staticmethod
    def _normalize_list_args(audio_filter, media_type, library_name, duplicates_only, broken_only, watched_only, unwatched_only, no_audio_language, excess_versions=None):
        if audio_filter:
            lang_map = {
                'en': 'en', 'english': 'en', 'eng': 'en',
                'de': 'de', 'german': 'de', 'deu': 'de', 'ger': 'de',
                'fr': 'fr', 'french': 'fr', 'fra': 'fr', 'fre': 'fr'
            }
            audio_filter = lang_map.get(audio_filter.lower(), audio_filter.lower())
        if media_type is not None:
            media_type = media_type.capitalize()
            if media_type in ("Series", "Show"):
                media_type = "Show"
        if media_type is not None and media_type not in ["Show", "Movie"]:
            err(1043, f"UNSUPPORTED media_type '{media_type}'. Valid types: movie, series (or show).")
        if library_name is not None and library_name not in PLEX_Media.OBJ_BY_LIBRARY.keys():
            err(1042, f"library_name='{library_name}', PLEX_Media.OBJ_BY_LIBRARY.keys() = {PLEX_Media.OBJ_BY_LIBRARY.keys()}")
        if library_name is None and not media_type and not duplicates_only and not broken_only and not watched_only and not unwatched_only and not audio_filter and not no_audio_language and not excess_versions:
            PLEX_Library.print()
            return audio_filter, media_type, False  # False = should not continue
        if library_name is None:
            if watched_only:
                err(1069, "--watched requires a library name.\nExample: my-plex ,unsorted --watched")
            if unwatched_only:
                err(1070, "--unwatched requires a library name.\nExample: my-plex ,unsorted --unwatched")
            if audio_filter:
                err(1071, "--audio/--en/--de/--fr requires a library name.\nExample: my-plex ,unsorted --en")
        return audio_filter, media_type, True  # True = continue

    @staticmethod
    def _print_list_header(library_name, media_type, broken_only, duplicates_only, watched_only, unwatched_only, audio_filter, no_audio_language):
        def _build_filters():
            filters = []
            if media_type:      filters.append(media_type)
            if watched_only:    filters.append("watched")
            elif unwatched_only: filters.append("unwatched")
            if audio_filter:    filters.append(f"audio: {audio_filter}")
            if no_audio_language: filters.append("no audio language")
            return filters

        if library_name is None:
            if broken_only:
                print(f"\nSearching for potentially truncated/broken files in all libraries:")
            elif duplicates_only:
                print(f"\nSearching for duplicates in all libraries:" if media_type is None else f"\nMedia of type '{media_type}' (duplicates only):")
            else:
                filters = _build_filters()
                filter_str = ", ".join(filters) if filters else "all"
                print(f"\nAll media:" if not filters else f"\nAll media ({filter_str}):")
        else:
            if broken_only:
                lib_suffix = f" in library '{library_name}'"
                type_prefix = f" of type '{media_type}'" if media_type else ""
                print(f"\nSearching for potentially truncated/broken files{type_prefix}{lib_suffix}:")
            elif duplicates_only:
                lib_suffix = f" in library '{library_name}'"
                type_prefix = f" of type '{media_type}'" if media_type else ""
                print(f"\nSearching for duplicates{type_prefix}{lib_suffix}:")
            else:
                filters = _build_filters()
                filter_str = ", ".join(filters) if filters else "all"
                if not filters:
                    if VRB: print(f"\nMedia in '{library_name}':")
                else:
                    if VRB: print(f"\nMedia in '{library_name}' ({filter_str}):")

    @staticmethod
    def _list_broken_files(obj_keys, library_name):
        broken_files = []
        seen_keys = set()
        for key in obj_keys:
            if key in seen_keys:
                continue
            seen_keys.add(key)
            obj = PLEX_Media.OBJ_BY_ID.get(key)
            if not obj or obj.get('type') not in ['Episode', 'Movie']:
                continue
            if library_name and obj.get('library') != library_name:
                continue
            plex_duration = obj.get('duration') or 0
            files_dict = obj.get('files', {})
            for file_info in files_dict.values():
                file_metadata = file_info.get('file_metadata')
                is_broken = False
                diff_pct = None
                severity = None
                if file_metadata:
                    if file_metadata.get('broken'):
                        is_broken = True
                        reason = file_metadata.get('reason', '')
                        severity = 'NOT FOUND' if reason == 'file_not_found' else 'PROBE ERR'
                    elif plex_duration > 0:
                        container_duration = file_metadata.get('container_duration')
                        if container_duration:
                            diff_pct = ((container_duration - plex_duration) / plex_duration) * 100
                            if diff_pct < -TRUNCATION_THRESHOLD_PCT:
                                # Cross-validate: if container and video stream durations agree
                                # (within 2s), the file is internally consistent — Plex just
                                # measured a different duration. Not a real truncation.
                                video_duration = file_metadata.get('video_duration')
                                if video_duration and abs(container_duration - video_duration) < 2000:
                                    pass  # File is healthy, Plex duration is just inaccurate
                                elif file_metadata.get('file_ends_cleanly'):
                                    pass  # No stream duration but file decodes cleanly to end
                                else:
                                    is_broken = True
                                    if diff_pct < -10:      severity = 'severe'
                                    elif diff_pct < -5:     severity = 'moderate'
                                    elif diff_pct < -1:     severity = 'mild'
                                    else:                   severity = 'borderline'
                if not is_broken and plex_duration > 60000:
                    filesize = file_info.get('filesize', 0)
                    if filesize:
                        avg_kbps = filesize / 1024 / (plex_duration / 1000)
                        if avg_kbps < 10:
                            is_broken = True
                            severity = 'severe'
                if is_broken:
                    broken_files.append((key, diff_pct, severity, file_info.get('filepath', '')))

        if not broken_files:
            print(f"No broken/truncated files{f' in {chr(39)}{library_name}{chr(39)}' if library_name else ''} found.")
            return 0

        severity_order = {'severe': 0, 'moderate': 1, 'mild': 2, 'borderline': 3, 'PROBE ERR': 5, 'NOT FOUND': 6, None: 4}
        broken_files.sort(key=lambda x: (severity_order.get(x[2], 4), x[1] if x[1] is not None else 0))

        print(f"\nDIFF% = (container_duration - plex_duration) / plex_duration. Negative = file shorter than expected.  V = number of file versions in Plex for this entry.")
        print(f"\n{'PLEX-ID':<10} | {'SEVERITY':<12} | {'DIFF%':<8} | {'DURATION':>10} | {'V':>4} | {'LIBRARY':<15} | FILEPATH")
        print("-" * 155)
        for key, diff_pct, severity, filepath in broken_files:
            obj = PLEX_Media.OBJ_BY_ID.get(key, {})
            library = obj.get('library', 'Unknown')[:15]
            plex_duration_raw = obj.get('duration') or 0
            plex_duration_min = plex_duration_raw / 60000 if plex_duration_raw > 0 else -1
            severity_str = severity.upper() if severity else 'BROKEN'
            diff_str = f"{diff_pct:.2f}%" if diff_pct is not None else "N/A"
            dur_str = f"{plex_duration_min:.1f} min" if plex_duration_raw > 0 else "-1"
            plex_id = obj.get('id', 'N/A')
            plex_id_str = f"ID:{plex_id}" if plex_id != 'N/A' else 'N/A'
            ver_count = len(obj.get('files', {}))
            ver_str = f"{ver_count:>4}" if ver_count > 1 else "    "
            print(f"{plex_id_str:<10} | {severity_str:<12} | {diff_str:<8} | {dur_str:>10} | {ver_str} | {library:<15} | {filepath}")
        print(f"\nTotal: {len(broken_files)} broken/truncated files found")
        print(f"Detection threshold: {TRUNCATION_THRESHOLD_PCT}%")
        return len(broken_files)

    @staticmethod
    def _list_excess_versions(obj_keys, library_name, version_limit):
        """List files belonging to entries with >= version_limit versions."""
        excess_files = []
        seen_keys = set()
        for key in obj_keys:
            if key in seen_keys:
                continue
            seen_keys.add(key)
            obj = PLEX_Media.OBJ_BY_ID.get(key)
            if not obj or obj.get('type') not in ['Episode', 'Movie']:
                continue
            if library_name and obj.get('library') != library_name:
                continue
            files_dict = obj.get('files', {})
            total = len(files_dict)
            if total < version_limit:
                continue
            title = obj.get('title', 'Unknown')
            # For episodes, show series + S##E## for better identification
            obj_type = obj.get('type', '')
            if obj_type in ('Episode', 'Episode*'):
                series = obj.get('series', '')
                s_str = obj.get('S_str', '')
                e_str = obj.get('E_str', '')
                title = f"{series} {s_str}{e_str}" + (f" {title}" if title else "")
            plex_id = obj.get('id', 'N/A')
            library = obj.get('library', 'Unknown')
            for idx, (version, file_info) in enumerate(files_dict.items(), 1):
                filepath = file_info.get('filepath', '')
                excess_files.append((plex_id, title, idx, total, library, filepath))

        if not excess_files:
            print(f"No entries with {version_limit}+ versions{f' in {chr(39)}{library_name}{chr(39)}' if library_name else ''} found.")
            return 0, 0

        excess_files.sort(key=lambda x: (x[4].lower(), x[1].lower(), x[0], x[2]))  # sort by library, title, plex_id, version nr

        # Group by entry (plex_id) and print versions together
        print()
        prev_plex_id = None
        entry_count = 0
        for plex_id, title, idx, total, library, filepath in excess_files:
            if plex_id != prev_plex_id:
                if prev_plex_id is not None:
                    print()  # blank line between entries
                entry_count += 1
                plex_id_str = f"ID:{plex_id}" if plex_id != 'N/A' else 'N/A'
                print(f"  {plex_id_str}  [{library}]  {title}  ({total} versions)")
                prev_plex_id = plex_id
            print(f"    {idx:>2}/{total}: {filepath}")

        print(f"\nTotal: {len(excess_files)} files across {entry_count} entries with {version_limit}+ versions")
        return len(excess_files), entry_count

    @staticmethod
    def _list_unmatched(obj_keys, library_name):
        """List items needing rematch in Plex: local:// guid (never matched) or
        matched but missing external IDs (no TMDB/TVDB → can't scrape episodes).
        Returns count of unmatched items."""
        if getattr(PLEX_Media, '_cache_missing_guid', False):
            print("  WARNING: Cache is missing 'guid' field — run: my-plex --update-cache --from-scratch")
            return 0
        unmatched = []       # (obj_type, plex_id, title, library, filepath, reason)
        missing_guid_count = 0
        seen_keys = set()
        for key in obj_keys:
            if key in seen_keys:
                continue
            seen_keys.add(key)
            obj = PLEX_Media.OBJ_BY_ID.get(key)
            if not obj:
                continue
            obj_type = obj.get('type')
            if obj_type not in ('Movie', 'Show'):
                continue
            if library_name and obj.get('library') != library_name:
                continue
            guid = obj.get('guid', '')
            title = obj.get('title', '?')
            plex_id = obj.get('id', '?')
            library = obj.get('library', '?')
            filepath = obj.get('file', '')
            if not guid:
                missing_guid_count += 1
            elif guid.startswith('local://'):
                unmatched.append((obj_type, plex_id, title, library, filepath, 'not matched'))
            elif obj_type == 'Show':
                # Matched but no external IDs → can't scrape episode data
                ext_ids = obj.get('external_ids', {})
                if not ext_ids:
                    unmatched.append((obj_type, plex_id, title, library, filepath, 'no external IDs'))

        if missing_guid_count > 0:
            scope = f" in '{library_name}'" if library_name else ""
            print(f"  WARNING: {missing_guid_count} item(s){scope} have no guid in cache — results incomplete.")
            print(f"  Run: my-plex --update-cache --from-scratch")

        if not unmatched:
            scope = f" in '{library_name}'" if library_name else ""
            if missing_guid_count == 0:
                print(f"  All items{scope} are matched — every item was identified by a Plex metadata agent.")
            return 0

        unmatched.sort(key=lambda x: (x[3].lower(), x[0], x[2].lower()))  # library, type, title

        print(f"\n  {'KEY':<17} {'TITLE':<45} {'LIBRARY':<20} {'REASON':<20} FILEPATH")
        print("  " + "-" * 160)
        for obj_type, plex_id, title, library, filepath, reason in unmatched:
            cache_key = f"{obj_type}:{plex_id}"
            print(f"  {cache_key:<17} {title[:45]:<45} {library:<20} {reason:<20} {filepath}")
        print(f"\n  {len(unmatched)} unmatched item(s) found.")
        return len(unmatched)

    @staticmethod
    def _list_unsorted(library_name=None, show_key_filter=None):
        """List shows with episodes directly in the show directory (no season subdirs).
        Plex needs season directories (e.g. 'Season 01/') for proper organization.
        Returns count of unsorted shows."""
        unsorted = []
        for show_key, seasons in PLEX_Media.OBJ_BY_SHOW_EPISODES.items():
            show = PLEX_Media.OBJ_BY_ID.get(show_key)
            if not show:
                continue
            if show.get('type') != 'Show':
                continue
            if library_name and show.get('library') != library_name:
                continue
            if show_key_filter and show_key != show_key_filter:
                continue
            show_dir = show.get('file', '')
            if not show_dir:
                continue
            title = show.get('title', '?')
            library = show.get('library', '?')
            # Check all episode filepaths: if dirname(filepath) == show_dir, it's unsorted
            unsorted_files = []
            for s_str, episodes in seasons.items():
                for e_str, versions in episodes.items():
                    for version, ep_keys in versions.items():
                        for ep_key in ep_keys:
                            ep = PLEX_Media.OBJ_BY_ID.get(ep_key)
                            if not ep:
                                continue
                            filepath = ep.get('file', '')
                            if not filepath:
                                continue
                            ep_dir = os.path.dirname(filepath)
                            if ep_dir == show_dir:
                                unsorted_files.append((s_str, e_str, filepath))
            if unsorted_files:
                unsorted.append((show_key, title, library, show_dir, unsorted_files))

        if not unsorted:
            scope = f" in '{library_name}'" if library_name else ""
            if not show_key_filter:
                print(f"  All shows{scope} have proper season directories.")
            return 0

        unsorted.sort(key=lambda x: (x[2].lower(), x[1].lower()))  # library, title

        for show_key, title, library, show_dir, files in unsorted:
            print(f"\n  {title:<45} {library:<20} {show_dir}")
            for s_str, e_str, filepath in sorted(files):
                print(f"    {s_str} {e_str}: {filepath}")

        total_files = sum(len(f) for _, _, _, _, f in unsorted)
        print(f"\n  {len(unsorted)} show(s) with {total_files} unsorted episode(s) found.")
        return len(unsorted)

    @staticmethod
    def _normalize_for_comparison(name):
        """Normalize a name for fuzzy comparison: lowercase, strip punctuation, collapse whitespace."""
        import re
        name = name.lower()
        # Remove year in parens like "(2016)"
        name = re.sub(r'\(\d{4}\)', '', name)
        # Replace dots, underscores, hyphens with spaces
        name = re.sub(r'[._\-]', ' ', name)
        # Strip common brackets and their content: [vu], [quiz], [from_...], etc.
        name = re.sub(r'\[.*?\]', '', name)
        # Remove punctuation
        name = re.sub(r"[^a-z0-9\s]", '', name)
        # Collapse whitespace
        name = re.sub(r'\s+', ' ', name).strip()
        return name

    @staticmethod
    def _title_similarity(dir_name, title, original_title=''):
        """Compute best similarity ratio between a directory name and a Plex title/originalTitle.
        Returns (best_ratio, matched_against) where matched_against is 'title' or 'originalTitle'.
        Uses difflib.SequenceMatcher for token-level similarity."""
        from difflib import SequenceMatcher
        norm_dir = PLEX_Media._normalize_for_comparison(dir_name)
        if not norm_dir:
            return 0.0, 'title'

        best_ratio = 0.0
        matched = 'title'
        for label, raw in [('title', title), ('originalTitle', original_title)]:
            if not raw:
                continue
            norm = PLEX_Media._normalize_for_comparison(raw)
            if not norm:
                continue
            # Check containment first (one is substring of the other)
            if norm_dir in norm or norm in norm_dir:
                ratio = 0.9  # high but not perfect (substring match)
            else:
                ratio = SequenceMatcher(None, norm_dir, norm).ratio()
            if ratio > best_ratio:
                best_ratio = ratio
                matched = label
        return best_ratio, matched

    @staticmethod
    def _list_potential_mismatches(obj_keys, library_name):
        """List items where the Plex title doesn't match the filesystem directory name.
        This detects potential Plex misidentifications (Fix Match needed).
        Returns count of potential mismatches."""
        MISMATCH_THRESHOLD = 0.35  # below this = likely mismatch

        mismatches = []
        seen_keys = set()
        for key in obj_keys:
            if key in seen_keys:
                continue
            seen_keys.add(key)
            obj = PLEX_Media.OBJ_BY_ID.get(key)
            if not obj:
                continue
            obj_type = obj.get('type')
            if obj_type not in ('Movie', 'Show'):
                continue
            if library_name and obj.get('library') != library_name:
                continue

            title = obj.get('title', '')
            original_title = obj.get('originalTitle', '')
            filepath = obj.get('file', '')
            if not filepath or not title:
                continue

            # Get scraped title if available
            scraped_title = ''
            if obj_type == 'Show':
                scraped_data = PLEX_Media.OBJ_BY_SHOW_SCRAPED.get(key, {})
                scraped_title = scraped_data.get('title', '')

            # Get the directory/file name to compare against
            if obj_type == 'Show':
                dir_name = os.path.basename(filepath)  # show_dir basename
            else:  # Movie
                parent_dir = os.path.basename(os.path.dirname(filepath))
                # If parent is the library root, use filename instead
                library = obj.get('library', '')
                if parent_dir == library or not parent_dir:
                    dir_name = os.path.splitext(os.path.basename(filepath))[0]
                else:
                    dir_name = parent_dir

            if not dir_name:
                continue

            # Always compare Plex title against directory name (strongest signal for user intent)
            dir_ratio, dir_matched = PLEX_Media._title_similarity(dir_name, title, original_title)
            comparison = f"DIR: {dir_name}"
            ratio = dir_ratio

            # If scraped title is also available and ALSO mismatches, note it
            if scraped_title:
                scraped_ratio, _ = PLEX_Media._title_similarity(scraped_title, title, original_title)
                if scraped_ratio < MISMATCH_THRESHOLD:
                    comparison += f" | SCRAPED-TITLE: {scraped_title}"

            if ratio < MISMATCH_THRESHOLD:
                library = obj.get('library', '?')
                mismatches.append((key, title, original_title, dir_name, comparison,
                                   library, filepath, ratio))

        if not mismatches:
            scope = f" in '{library_name}'" if library_name else ""
            print(f"  No potential mismatches found{scope} — all titles match their directory names.")
            return 0

        mismatches.sort(key=lambda x: (x[7], x[5].lower(), x[1].lower()))  # ratio, library, title

        print(f"\n  {'KEY':<14} {'LIBRARY':<15} {'PLEX TITLE':<35} {'SIM':>4}  COMPARISON")
        print("  " + "-" * 120)
        for cache_key, title, orig_title, dir_name, comparison, library, filepath, ratio in mismatches:
            pct = f"{ratio:.0%}"
            title_disp = title[:35]
            print(f"  {cache_key:<14} {library:<15} {title_disp:<35} {pct:>4}  {comparison}")
            if orig_title and orig_title != title:
                print(f"  {'':14} {'':15} originalTitle: {orig_title[:60]}")
            # Always show directory for context if comparison was against scraped title
            if comparison.startswith('SCRAPED-TITLE:'):
                print(f"  {'':14} {'':15} DIR: {dir_name}")

        print(f"\n  {len(mismatches)} potential mismatch(es) found (similarity < {MISMATCH_THRESHOLD:.0%}).")
        print(f"  SIM = similarity between Plex title and directory name (higher = better match).")
        print(f"  These items may need Fix Match in Plex.")
        return len(mismatches)

    @staticmethod
    def _list_episode_numbering_issues(library_name=None):
        """List shows where Plex and scraped episode numbering disagree.
        Returns count of issues found."""
        issues = []
        for show_key, scraped_data in PLEX_Media.OBJ_BY_SHOW_SCRAPED.items():
            show_issues = scraped_data.get('numbering_issues', [])
            if not show_issues:
                continue

            show_dict = PLEX_Media.OBJ_BY_ID.get(show_key)
            if not show_dict:
                continue
            if library_name and show_dict.get('library') != library_name:
                continue

            show_title = show_dict.get('title', '?')
            scraped_title = scraped_data.get('title', '')
            lib = show_dict.get('library', '?')
            source = scraped_data.get('source', '?')

            for issue in show_issues:
                issues.append({
                    'show_key': show_key,
                    'show_title': show_title,
                    'scraped_title': scraped_title,
                    'library': lib,
                    'source': source,
                    'season': issue['season'],
                    'episode_plex': issue['episode_plex'],
                    'episode_scraped': issue['episode_scraped'],
                    'reason': issue['reason'],
                })

        if not issues:
            scope = f" in '{library_name}'" if library_name else ""
            print(f"  No episode numbering issues found{scope}.")
            return 0

        issues.sort(key=lambda x: (x['library'].lower(), x['show_title'].lower(), x['season'], x['episode_plex']))

        print(f"\n  {'SHOW':<35} {'SEASON':<8} {'PLEX':<8} {'SCRAPED':<8} {'SOURCE':<18} {'LIBRARY':<15}")
        print("  " + "-" * 105)
        for issue in issues:
            title_disp = issue['show_title'][:35]
            print(f"  {title_disp:<35} {issue['season']:<8} {issue['episode_plex']:<8} {issue['episode_scraped']:<8} {issue['source']:<18} {issue['library']:<15}")

        print(f"\n  {len(issues)} episode numbering issue(s) found.")
        print(f"  These shows have conflicting episode numbers between Plex and the scraped source.")
        return len(issues)

    @staticmethod
    def _list_reencode_candidates(obj_keys, library_name):
        """List media files whose avg bitrate exceeds REENCODE_THRESHOLD_MBPS.
        For series: rolls up episodes → seasons → show when ALL items in a group are flagged.
        Columns: KEY  DETAILS(bitrate/size/duration)  LABELED  FILEPATH
        Returns total count of flagged files."""
        threshold  = REENCODE_THRESHOLD_MBPS
        labeltext  = PROBLEMS2DISK.get('reencode', {}).get('LABELTEXT_ON_DISK', 'reencode')
        lbl_marker = f"{ONDISK_LABEL_START_MARKER}{labeltext}{ONDISK_LABEL_END_MARKER}"

        flagged_movies = []
        # {show_key: {s_str: {e_str: [(bitrate, filesize, dur_ms, cache_key, ep_title, filepath, version, labeled)]}}}
        flagged_ep_by_show = {}
        show_meta = {}  # {show_key: (series_title, library)}

        for key in set(obj_keys):
            obj = PLEX_Media.OBJ_BY_ID.get(key)
            if not obj:
                continue
            obj_type = obj.get('type', '')
            if obj_type not in ('Movie', 'Movie*', 'Episode', 'Episode*'):
                continue
            if library_name and obj.get('library') != library_name:
                continue
            duration_ms = obj.get('duration') or 0
            if duration_ms < 60_000:  # skip clips < 1 min
                continue
            files_dict = obj.get('files', {})
            for version, file_info in files_dict.items():
                filesize = file_info.get('filesize') or 0
                if not filesize:
                    continue
                bitrate_mbps = (filesize * 8) / (duration_ms / 1000) / 1_000_000
                if bitrate_mbps < threshold:
                    continue
                filepath = file_info.get('filepath', '')
                if REENCODE_EXCLUDE_FILEPATH_CONTAINS and any(s in filepath for s in REENCODE_EXCLUDE_FILEPATH_CONTAINS):
                    continue
                lib = obj.get('library', '?')
                if obj_type in ('Movie', 'Movie*'):
                    title = obj.get('title', '?')
                    year = obj.get('year', 0)
                    # For movies: label may be on the file OR on the movie-dir (parent)
                    movie_dir = os.path.dirname(filepath) if filepath else ''
                    labeled = (labeltext in parse_ondisk_labels(os.path.basename(filepath)) or
                               labeltext in parse_ondisk_labels(os.path.basename(movie_dir)))
                    flagged_movies.append((bitrate_mbps, filesize, duration_ms, lib, title, year, key, filepath, version, labeled))
                else:
                    show_key = obj.get('show_key', '')
                    if not show_key:
                        continue
                    s_str = obj.get('S_str', 'S?')
                    e_str = obj.get('E_str', 'E?')
                    ep_title = obj.get('title', '')
                    if show_key not in flagged_ep_by_show:
                        flagged_ep_by_show[show_key] = {}
                        show_meta[show_key] = (obj.get('series', show_key), lib)
                    # Store filepath for level-specific labeled checks at render time
                    flagged_ep_by_show[show_key].setdefault(s_str, {}).setdefault(e_str, []).append(
                        (bitrate_mbps, filesize, duration_ms, key, ep_title, filepath, version, None)
                    )

        total_file_count = len(flagged_movies) + sum(
            len(eps) for show in flagged_ep_by_show.values()
            for season in show.values()
            for eps in season.values()
        )

        if not total_file_count:
            scope = f" in '{library_name}'" if library_name else ""
            print(f"  No reencode candidates{scope} found (threshold: {threshold} Mbps).")
            return 0

        def _fmt_item(br, sz, dur_ms):
            return f"{br:.1f} Mbps/{format_filesize(int(sz))}/{int(dur_ms/60000)}min"

        def _fmt_avg(items, n=None):
            n = n or len(items)
            avg_br = sum(i[0] for i in items) / n
            avg_sz = sum(i[1] for i in items) / n
            return f"avg {avg_br:.1f} Mbps/{format_filesize(int(avg_sz))} ({n} eps)"

        def _sample_fp(seasons_dict):
            for s_eps in seasons_dict.values():
                for e_items in s_eps.values():
                    if e_items:
                        return e_items[0][5]
            return ''

        def _labeled_at_dir(dirpath):
            """True if the label is on the directory itself (not inherited from parent/child)."""
            return labeltext in parse_ondisk_labels(os.path.basename(dirpath)) if dirpath else False

        def _labeled_at_file(filepath):
            """True if the label is on the episode filename itself."""
            return labeltext in parse_ondisk_labels(os.path.basename(filepath)) if filepath else False

        key_w = 20
        det_w = 30
        lbl_w = len(lbl_marker) + 2
        hdr   = f"  {'KEY':<{key_w}}  {'DETAILS':<{det_w}}  {'LABELED':<{lbl_w}}  FILE/PATH"
        sep   = "  " + "-" * (key_w + det_w + lbl_w + 14)

        def _row(cache_key, details, labeled, filepath, indent=0):
            pad = ' ' * (indent * 2)
            k   = f"{pad}{cache_key}"
            lbl = lbl_marker if labeled else ''
            print(f"  {k:<{key_w}}  {details:<{det_w}}  {lbl:<{lbl_w}}  {filepath}")

        # --- MOVIES ---
        if flagged_movies:
            flagged_movies.sort(key=lambda x: (-x[0], x[3].lower(), x[4].lower()))
            print(f"\n  MOVIES  ({len(flagged_movies)} file(s) above {threshold} Mbps)")
            print(hdr)
            print(sep)
            for br, sz, dur_ms, lib, title, year, cache_key, filepath, version, labeled in flagged_movies:
                _row(cache_key, _fmt_item(br, sz, dur_ms), labeled, filepath)

        # --- SERIES: rollup logic ---
        if flagged_ep_by_show:
            total_ep_files = sum(
                len(eps)
                for show in flagged_ep_by_show.values()
                for season in show.values()
                for eps in season.values()
            )
            print(f"\n  SERIES  ({total_ep_files} episode file(s) across {len(flagged_ep_by_show)} show(s) above {threshold} Mbps)")
            print(hdr)
            print(sep)

            for show_key in sorted(flagged_ep_by_show, key=lambda k: (show_meta[k][1].lower(), show_meta[k][0].lower())):
                series_title, lib = show_meta[show_key]
                flagged_seasons   = flagged_ep_by_show[show_key]

                all_seasons_data = PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key, {})
                all_season_keys  = [s for s in all_seasons_data if s != 'S00']

                season_rollup = {}
                for s_str, ep_dict_total in all_seasons_data.items():
                    if s_str not in flagged_seasons:
                        season_rollup[s_str] = 'none'
                        continue
                    season_rollup[s_str] = 'full' if set(flagged_seasons[s_str]) >= set(ep_dict_total) else 'partial'

                show_full = bool(all_season_keys) and all(season_rollup.get(s, 'none') == 'full' for s in all_season_keys)

                all_items_flat = [item for s in flagged_seasons.values() for eps in s.values() for item in eps]

                if show_full:
                    sample_fp  = _sample_fp(flagged_seasons)
                    series_dir = os.path.dirname(os.path.dirname(sample_fp)) if sample_fp else ''
                    labeled    = _labeled_at_dir(series_dir)   # labeled only if series DIR has the label
                    _row(show_key, _fmt_avg(all_items_flat), labeled, series_dir)
                else:
                    # Partial show: print show as group header, then seasons/episodes
                    print(f"  {show_key:<{key_w}}  [{lib}]  {series_title}")
                    for s_str in sorted(flagged_seasons.keys()):
                        ep_dict        = flagged_seasons[s_str]
                        rollup         = season_rollup.get(s_str, 'partial')
                        season_key     = (PLEX_Media.OBJ_BY_SHOW.get(show_key) or {}).get(s_str, s_str)
                        season_items   = [item for eps in ep_dict.values() for item in eps]
                        if rollup == 'full':
                            sample_fp  = next((i[5] for i in season_items if i[5]), '')
                            season_dir = os.path.dirname(sample_fp) if sample_fp else ''
                            labeled    = _labeled_at_dir(season_dir)   # labeled only if SEASON DIR has the label
                            _row(season_key, _fmt_avg(season_items), labeled, season_dir, indent=1)
                        else:
                            for e_str in sorted(ep_dict.keys()):
                                items    = ep_dict[e_str]
                                avg_br   = sum(i[0] for i in items) / len(items)
                                avg_sz   = sum(i[1] for i in items) / len(items)
                                avg_dur  = sum(i[2] for i in items) / len(items)
                                ep_key   = items[0][3]
                                ep_fp    = items[0][5]
                                labeled  = _labeled_at_file(ep_fp)   # labeled only if EPISODE FILE has the label
                                _row(ep_key, _fmt_item(avg_br, avg_sz, avg_dur), labeled, ep_fp, indent=1)

        print(f"\n  Total: {total_file_count} file(s) above {threshold} Mbps")
        return total_file_count

    @staticmethod
    def _parse_filter_sub_expr(sub_expr):
        """Parse a single filter sub-expression into a (field_label, fn(obj)->bool) pair.

        Supported sub-expressions:
          Bitrate:    '< 1'  '> 2Mbps'  '>= 400MB/hr'  'bitrate<1.5'
          Resolution: 'resolution:1080p'  'resolution:4k'  'resolution:720'
          Codec:      'codec:h265'  'codec:hevc'  'codec:h264'
          Year:       'year:2020'  'year>2015'  'year<2000'
          Label:      'label:reencode'
          Genre:      'genre:action'
          Size:       'size>1gb'  'size>500mb'  (filesize in bytes)
          Duration:   'duration>2h'  'duration>120min'  'duration>7200s'
          Stars:      'stars>3.5'  'stars>=4'  (your Plex star rating, 0–5 with half-star)
          Rating:     'rating>7'  'rating>=8'  (external: IMDB/TMDB audience score)
          Critics:    'critics>80'  (Rotten Tomatoes Tomatometer only; empty for IMDB/TMDB)
          Added:      'added>2024'  (year comparison on addedAt unix timestamp)

        Returns (display_label, fn) or None if not parseable.
        fn(obj) -> bool where obj is a cache dict (Movie or Episode level).
        fn takes an optional file_info dict as second arg for file-level fields.
        """
        _OPS = {
            '<': lambda a, b: a < b,
            '<=': lambda a, b: a <= b,
            '>': lambda a, b: a > b,
            '>=': lambda a, b: a >= b,
            '=': lambda a, b: abs(float(a) - float(b)) < 0.001 if isinstance(a, float) or isinstance(b, float) else a == b,
            '!=': lambda a, b: a != b,
        }

        sub = sub_expr.strip()

        # --- Bitrate: bare '<N' '>N' or 'bitrate OP N [unit]' ---
        _bitrate_re = re.match(
            r'^(?:(?:bitrate|mb_per_hour|mbph)\s*)?'
            r'(?P<op>[<>]=?|[!=]=)\s*'
            r'(?P<value>[\d.]+)\s*'
            r'(?P<unit>mbps|mb/h(?:our|r)?|mb_per_hour)?$',
            sub, re.IGNORECASE
        )
        if _bitrate_re:
            op    = _bitrate_re.group('op')
            value = float(_bitrate_re.group('value'))
            unit  = (_bitrate_re.group('unit') or '').lower()
            is_mbph = 'mb' in unit and 'h' in unit
            threshold = value / _MB_PER_HOUR_PER_MBPS if is_mbph else value
            cmp = _OPS.get(op, lambda a, b: False)
            unit_display = f"MB/hr" if is_mbph else "Mbps"
            label = f"bitrate {op} {value}{unit_display}"
            def _bitrate_fn(obj, fi, _t=threshold, _c=cmp):
                dur = obj.get('duration') or 0
                if dur < 60_000: return False
                fs = fi.get('filesize') or 0
                if not fs: return False
                br = (fs * 8) / (dur / 1000) / 1_000_000
                return _c(br, _t)
            return label, _bitrate_fn

        # --- Field:value or field OP value patterns ---
        _field_re = re.match(
            r'^(?P<field>resolution|codec|year|label|genre|size|duration|rating|stars|critics|added|watched|lang|language|subs|sub|subtitle|subtitles)'
            r'(?P<op>[<>]=?|[:=!]=?)(?P<val>.+)$',
            sub, re.IGNORECASE
        )
        if not _field_re:
            return None

        field = _field_re.group('field').lower()
        raw_op = _field_re.group('op')
        val   = _field_re.group('val').strip().strip("'\"")
        op    = '=' if raw_op in (':', '=', '==') else raw_op

        # --- Resolution ---
        if field == 'resolution':
            # Normalize: 4k→2160, uhd→2160
            alias = {'4k': '2160', 'uhd': '2160', 'fhd': '1080', 'hd': '720', 'sd': '480'}
            needle = alias.get(val.lower(), val.lower())
            label = f"resolution:{val}"
            def _res_fn(obj, fi, _n=needle):
                res = (obj.get('resolution_full') or obj.get('resolution') or '').lower()
                return _n in res
            return label, _res_fn

        # --- Codec ---
        if field == 'codec':
            alias = {'hevc': 'h265', 'h.265': 'h265', 'avc': 'h264', 'h.264': 'h264'}
            needle = alias.get(val.lower(), val.lower())
            label = f"codec:{val}"
            def _codec_fn(obj, fi, _n=needle):
                vc = (obj.get('video_codec') or '').lower()
                return _n in vc
            return label, _codec_fn

        # --- Year ---
        if field == 'year':
            try:
                yr = int(val)
            except ValueError:
                return None
            cmp = _OPS.get(op, lambda a, b: False)
            label = f"year {op} {yr}"
            def _year_fn(obj, fi, _yr=yr, _c=cmp):
                y = obj.get('year') or 0
                return bool(y) and _c(y, _yr)
            return label, _year_fn

        # --- Label (Plex labels list) ---
        if field == 'label':
            needle = val.lower()
            label_str = f"label:{val}"
            def _label_fn(obj, fi, _n=needle):
                return any(_n == str(l).lower() for l in (obj.get('labels') or []))
            return label_str, _label_fn

        # --- Genre ---
        if field == 'genre':
            # Genres are stored normalized (English) in cache — simple case-insensitive substring match
            needle = _normalize_genre(val).lower()
            label_str = f"genre:{val}"
            def _genre_fn(obj, fi, _n=needle):
                return any(_n in str(g).lower() for g in (obj.get('genres') or []))
            return label_str, _genre_fn

        # --- Size ---
        if field == 'size':
            _sz_re = re.match(r'^([\d.]+)\s*(gb|mb|kb)?$', val, re.IGNORECASE)
            if not _sz_re:
                return None
            sz_val = float(_sz_re.group(1))
            sz_unit = (_sz_re.group(2) or 'b').lower()
            multipliers = {'gb': 1024**3, 'mb': 1024**2, 'kb': 1024, 'b': 1}
            threshold = sz_val * multipliers[sz_unit]
            cmp = _OPS.get(op, lambda a, b: False)
            label = f"size {op} {val}"
            def _size_fn(obj, fi, _t=threshold, _c=cmp):
                fs = fi.get('filesize') or obj.get('filesize') or 0
                return bool(fs) and _c(fs, _t)
            return label, _size_fn

        # --- Duration ---
        if field == 'duration':
            _dur_re = re.match(r'^([\d.]+)\s*(h|hr|hour|hours|m|min|mins|minute|minutes|s|sec|secs|second|seconds)?$', val, re.IGNORECASE)
            if not _dur_re:
                return None
            dur_val = float(_dur_re.group(1))
            dur_unit = (_dur_re.group(2) or 'm').lower()
            ms_multipliers = {'h': 3_600_000, 'hr': 3_600_000, 'hour': 3_600_000, 'hours': 3_600_000,
                              'm': 60_000, 'min': 60_000, 'mins': 60_000, 'minute': 60_000, 'minutes': 60_000,
                              's': 1_000, 'sec': 1_000, 'secs': 1_000, 'second': 1_000, 'seconds': 1_000}
            threshold_ms = dur_val * ms_multipliers.get(dur_unit, 60_000)
            cmp = _OPS.get(op, lambda a, b: False)
            label = f"duration {op} {val}"
            def _dur_fn(obj, fi, _t=threshold_ms, _c=cmp):
                dur = obj.get('duration') or 0
                return _c(dur, _t)
            return label, _dur_fn

        # --- Stars (Plex personal user rating, 0–5 with half-star, stored 0–10 internally) ---
        if field == 'stars':
            try:
                r_val = float(val)
            except ValueError:
                return None
            cmp = _OPS.get(op, lambda a, b: False)
            label = f"stars {op} {r_val}"
            # Plex stores userRating as 0–10; UI shows 0–5 stars → multiply input by 2
            internal = r_val * 2.0
            def _stars_fn(obj, fi, _r=internal, _c=cmp):
                rating = obj.get('userRating') or 0
                return bool(rating) and _c(float(rating), _r)
            return label, _stars_fn

        # --- Rating (external / audience rating: IMDB score, RT Audience %, TMDB vote avg) ---
        if field == 'rating':
            try:
                r_val = float(val)
            except ValueError:
                return None
            cmp = _OPS.get(op, lambda a, b: False)
            label = f"rating {op} {r_val}"
            def _rating_fn(obj, fi, _r=r_val, _c=cmp):
                rating = obj.get('audienceRating') or 0
                return bool(rating) and _c(float(rating), _r)
            return label, _rating_fn

        # --- Critics (Rotten Tomatoes Tomatometer only; empty for IMDB/TMDB libraries) ---
        if field == 'critics':
            try:
                r_val = float(val)
            except ValueError:
                return None
            cmp = _OPS.get(op, lambda a, b: False)
            label = f"critics {op} {r_val}"
            def _critics_fn(obj, fi, _r=r_val, _c=cmp):
                rating = obj.get('criticsRating') or 0
                return bool(rating) and _c(float(rating), _r)
            return label, _critics_fn

        # --- Watched (watched=yes / watched=no / watched:no) ---
        if field == 'watched':
            yes = val.lower() in ('yes', 'true', '1', 'y')
            label = "watched" if yes else "unwatched"
            def _watched_fn(obj, fi, _yes=yes):
                count = obj.get('viewCount', 0) or 0
                return count > 0 if _yes else count == 0
            return label, _watched_fn

        # --- Lang (audio language: lang:de / lang:en / lang:fr) ---
        if field in ('lang', 'language'):
            lang_map = {'en': 'en', 'english': 'en', 'eng': 'en',
                        'de': 'de', 'german': 'de', 'deu': 'de', 'ger': 'de',
                        'fr': 'fr', 'french': 'fr', 'fra': 'fr', 'fre': 'fr'}
            needle = lang_map.get(val.lower(), val.lower())
            label_str = f"lang:{needle}"
            def _lang_fn(obj, fi, _n=needle):
                langs = [str(l).lower() for l in (obj.get('audio_languages') or [])]
                return _n in langs
            return label_str, _lang_fn

        # --- Subs (subtitle language: subs:de / sub:en) ---
        if field in ('subs', 'sub', 'subtitle', 'subtitles'):
            lang_map = {'en': 'en', 'english': 'en', 'eng': 'en',
                        'de': 'de', 'german': 'de', 'deu': 'de', 'ger': 'de',
                        'fr': 'fr', 'french': 'fr', 'fra': 'fr', 'fre': 'fr'}
            needle = lang_map.get(val.lower(), val.lower())
            label_str = f"subs:{needle}"
            def _subs_fn(obj, fi, _n=needle):
                langs = [str(l).lower() for l in (obj.get('subtitle_languages') or [])]
                return _n in langs
            return label_str, _subs_fn

        # --- Added (year comparison on addedAt unix timestamp) ---
        if field == 'added':
            try:
                yr = int(val)
            except ValueError:
                return None
            import datetime as _dt
            # Convert year to unix timestamp range
            if op in ('<', '<='):
                ts_threshold = int(_dt.datetime(yr, 1, 1).timestamp())
            elif op in ('>', '>='):
                ts_threshold = int(_dt.datetime(yr + (0 if op == '>=' else 1), 1, 1).timestamp()) - 1
            else:
                # '=' means year matches
                ts_start = int(_dt.datetime(yr, 1, 1).timestamp())
                ts_end   = int(_dt.datetime(yr + 1, 1, 1).timestamp()) - 1
                label = f"added:{yr}"
                def _added_eq_fn(obj, fi, _s=ts_start, _e=ts_end):
                    t = obj.get('addedAt') or 0
                    return _s <= t <= _e
                return label, _added_eq_fn
            cmp = _OPS.get(op, lambda a, b: False)
            label = f"added {op} {yr}"
            def _added_fn(obj, fi, _t=ts_threshold, _c=cmp):
                t = obj.get('addedAt') or 0
                return bool(t) and _c(t, _t)
            return label, _added_fn

        return None

    @staticmethod
    def _list_filtered(expr=None, library_name=None, media_type=None,
                       watched_only=False, unwatched_only=False, audio_filter=None):
        """List media items matching filter expressions joined by AND.

        expr: one or more sub-expressions separated by ' AND ', e.g.:
              'bitrate>2' or 'resolution:1080p AND codec:h265 AND year>2015'
              None or '' means no expression filter — list all (subject to other params).
        library_name: restrict to one library (None = all).
        media_type:   restrict to 'Movie' or 'Show' (None = all).
        watched_only / unwatched_only: filter by viewCount.
        audio_filter: 'en'/'de'/'fr' — filter by audio_languages list.
        """
        import datetime as _dt_mod

        # Normalise media_type
        if media_type:
            media_type = media_type.capitalize()
            if media_type == 'Series':
                media_type = 'Show'

        # Parse all sub-expressions (expr may be None/'' = no filter)
        sub_exprs = [s.strip() for s in re.split(r'\bAND\b', expr or '', flags=re.IGNORECASE) if s.strip()]
        filters = []  # list of (label, fn(obj, fi)->bool)
        for sub in sub_exprs:
            parsed = PLEX_Media._parse_filter_sub_expr(sub)
            if not parsed:
                err(1100, f"Cannot parse filter sub-expression: '{sub}'\n"
                          f"  Supported: bitrate<1  resolution:1080p  codec:h265  year>2015\n"
                          f"             label:reencode  genre:action  size>1gb  duration>2h\n"
                          f"             watched:no  lang:de  rating>8  added>2024")
                return
            filters.append(parsed)

        # Determine which fields are active (for smart column selection)
        # Map label prefixes returned by _parse_filter_sub_expr to canonical field names
        _LABEL_TO_FIELD = {
            'bitrate': 'bitrate', 'resolution': 'resolution', 'codec': 'codec',
            'year': 'year', 'label': 'label', 'genre': 'genre', 'size': 'size',
            'duration': 'duration', 'stars': 'stars', 'rating': 'rating',
            'critics': 'critics', 'added': 'added',
            'watched': 'watched', 'unwatched': 'unwatched',
            'lang': 'lang', 'language': 'lang',
            'subs': 'subs', 'sub': 'subs', 'subtitle': 'subs', 'subtitles': 'subs',
        }
        _active_fields = set()
        for lbl, _ in filters:
            tok = lbl.split()[0].split(':')[0].lower()
            field_name = _LABEL_TO_FIELD.get(tok, tok)
            _active_fields.add(field_name)
        if media_type:    _active_fields.add('type')
        if audio_filter:  _active_fields.add('lang')
        if watched_only:  _active_fields.add('watched')
        if unwatched_only: _active_fields.add('unwatched')

        # Build active filter label string
        active_labels = [lbl for lbl, _ in filters]
        if media_type:    active_labels.insert(0, f"type={media_type.lower()}")
        if audio_filter:  active_labels.append(f"lang={audio_filter}")
        if watched_only:   active_labels.append("watched")
        if unwatched_only: active_labels.append("unwatched")
        scope = f" in '{library_name}'" if library_name else ""
        # Metadata goes to stderr — keeps stdout clean for piping/head/grep
        if VRB: print(f" >>> Filter: {' AND '.join(active_labels)}{scope}")

        rows = []
        for key, obj in PLEX_Media.OBJ_BY_ID.items():
            obj_type = obj.get('type', '')
            if obj_type not in ('Movie', 'Movie*', 'Episode', 'Episode*'):
                continue
            if library_name and obj.get('library') != library_name:
                continue
            if media_type:
                if media_type == 'Movie' and obj_type not in ('Movie', 'Movie*'):
                    continue
                if media_type == 'Show' and obj_type not in ('Episode', 'Episode*'):
                    continue
            # watched/unwatched filter (legacy params — now also handled via sub-expr)
            view_count = obj.get('viewCount', 0) or 0
            if watched_only   and view_count == 0: continue
            if unwatched_only and view_count  > 0: continue
            # audio filter (legacy param)
            if audio_filter:
                langs = [str(l).lower() for l in (obj.get('audio_languages') or [])]
                if audio_filter.lower() not in langs:
                    continue

            # Apply per-file filters (bitrate, size) — match ANY file version
            files_dict = obj.get('files', {})
            file_matches = list(files_dict.values()) if files_dict else [{}]

            matched_fi = None
            for fi in file_matches:
                if all(fn(obj, fi) for _, fn in filters):
                    matched_fi = fi
                    break
            if matched_fi is None:
                continue

            lib       = obj.get('library', '?')
            dur_ms    = obj.get('duration') or 0
            fs_bytes  = matched_fi.get('filesize') or obj.get('filesize') or 0
            bitrate   = (fs_bytes * 8) / (dur_ms / 1000) / 1_000_000 if dur_ms > 0 and fs_bytes > 0 else 0.0
            filepath  = matched_fi.get('filepath', '')

            rows.append({
                'key':          key,
                'type':         obj_type.rstrip('*'),
                'lib':          lib,
                'bitrate':      bitrate,
                'filepath':     filepath,
                'resolution':   obj.get('resolution', ''),         # short: '1080p'
                'resolution_full': obj.get('resolution_full', ''), # full: '60min 1920x1080 (h264 aac) 2GB'
                'video_codec':  obj.get('video_codec', ''),
                'audio_codec':  obj.get('audio_codec', ''),
                'year':         obj.get('year', 0),
                'filesize':     fs_bytes,
                'duration':     dur_ms,
                'stars':        obj.get('userRating') or 0,        # 0–10 stored; display as 0–5
                'rating':       obj.get('audienceRating') or 0,    # external audience score
                'critics':      obj.get('criticsRating') or 0,     # RT Tomatometer only
                'added':        obj.get('addedAt') or 0,
                'audio_langs':  ', '.join(str(l) for l in (obj.get('audio_languages') or [])),
                'sub_langs':    ', '.join(str(l) for l in (obj.get('subtitle_languages') or [])),
                'genres':       ', '.join(str(g) for g in (obj.get('genres') or [])),
                'labels':       ', '.join(str(l) for l in (obj.get('labels') or [])),
                'last_watched': obj.get('lastViewedAt') or 0,
                'view_count':   obj.get('viewCount', 0) or 0,
            })

        if not rows:
            print(f"    > No items match the filter.")
            return

        # --- Smart column selection ---
        # Sort: bitrate desc if bitrate filter, else last_watched desc if watched:yes, else filepath
        has_bitrate    = 'bitrate'   in _active_fields
        has_watched    = 'watched'   in _active_fields    # watched:yes only
        has_unwatched  = 'unwatched' in _active_fields    # watched:no only — no LAST WATCHED col
        has_lang       = 'lang'      in _active_fields
        has_subs       = 'subs'      in _active_fields
        has_size     = 'size'     in _active_fields
        has_duration = 'duration' in _active_fields
        has_year     = 'year'     in _active_fields
        has_resolution = 'resolution' in _active_fields
        has_codec    = 'codec'    in _active_fields
        has_stars    = 'stars'    in _active_fields
        has_rating   = 'rating'   in _active_fields
        has_critics  = 'critics'  in _active_fields
        has_added    = 'added'    in _active_fields
        has_genre    = 'genre'    in _active_fields
        has_label    = 'label'    in _active_fields

        if has_bitrate:
            rows.sort(key=lambda r: r['bitrate'], reverse=True)
        elif has_watched:
            rows.sort(key=lambda r: r['last_watched'], reverse=True)  # most recently watched first
        elif has_year:
            rows.sort(key=lambda r: r['year'], reverse=True)
        elif has_added:
            rows.sort(key=lambda r: r['added'], reverse=True)
        elif has_rating:
            rows.sort(key=lambda r: r['rating'], reverse=True)
        elif has_stars:
            rows.sort(key=lambda r: r['stars'], reverse=True)
        else:
            rows.sort(key=lambda r: r['filepath'])

        def _fmt_ts(ts):
            if not ts: return '-'
            try: return _dt_mod.datetime.fromtimestamp(ts).strftime('%Y-%m-%d')
            except: return '-'
        def _fmt_dur(ms):
            if not ms: return '-'
            h, rem = divmod(int(ms) // 1000, 3600)
            m = rem // 60
            return f"{h}h{m:02d}m" if h else f"{m}m"
        def _fmt_size(b):
            if not b: return '-'
            gb = b / 1024**3
            return f"{gb:.1f}GB" if gb >= 1 else f"{b/1024**2:.0f}MB"

        # Build columns: always KEY first, FILEPATH last; extra cols in between.
        # For each filter, show ALL related Plex fields — not just the one filtered on.
        extra_cols = []  # list of (header, width, value_fn)

        # watched: viewCount (the completion counter) + lastViewedAt (any play activity)
        if has_watched or has_unwatched:
            extra_cols.append(('WATCH#',      6,  lambda r: str(r['view_count']) if r['view_count'] else '-'))
            extra_cols.append(('LAST-PLAYED', 11, lambda r: _fmt_ts(r['last_watched'])))

        # bitrate: already two columns (Mbps + MB/hr, both derived from filesize+duration)
        if has_bitrate:
            extra_cols.append(('BITRATE', 8, lambda r: f"{r['bitrate']:.2f}" if r['bitrate'] else 'N/A'))
            extra_cols.append(('MB/HR',   6, lambda r: str(int(r['bitrate'] * _MB_PER_HOUR_PER_MBPS)) if r['bitrate'] else 'N/A'))

        # resolution: short form (1080p) + full form (WxH codec acodec size)
        if has_resolution:
            extra_cols.append(('RES',          6,  lambda r: r['resolution'] or '-'))
            extra_cols.append(('RESOLUTION',   32, lambda r: r['resolution_full'] or '-'))

        # codec: video + audio codec (both stored in cache)
        if has_codec:
            extra_cols.append(('VCODEC', 6, lambda r: r['video_codec'] or '-'))
            extra_cols.append(('ACODEC', 6, lambda r: r['audio_codec'] or '-'))

        if has_year:
            extra_cols.append(('YEAR', 4, lambda r: str(r['year']) if r['year'] else '-'))
        if has_size:
            extra_cols.append(('SIZE', 7, lambda r: _fmt_size(r['filesize'])))
        if has_duration:
            extra_cols.append(('DURATION', 8, lambda r: _fmt_dur(r['duration'])))

        # stars: personal Plex rating — stored 0–10, shown 0–5; show both
        if has_stars:
            extra_cols.append(('STARS', 5, lambda r: f"{r['stars']/2:.1f}" if r['stars'] else '-'))
            extra_cols.append(('RAW',   4, lambda r: str(int(r['stars'])) if r['stars'] else '-'))

        # rating + critics: check whether any matched library uses RT (supports criticsRating)
        # Agents that provide critics (Rotten Tomatoes): tv.plex.agents.movie only
        _CRITICS_AGENTS = {'tv.plex.agents.movie'}
        if has_rating or has_critics:
            _lib_agents = CACHE.get('library_stats', {}).get('agent', {})
            # Determine which libraries are in the result set
            _result_libs = {r['lib'] for r in rows}
            # If scoped to one library, check that library; otherwise check all result libs
            _check_libs = {library_name} if library_name else _result_libs
            _any_critics = any(_lib_agents.get(lib, '') in _CRITICS_AGENTS for lib in _check_libs)
            if _any_critics:
                # Library has RT critics ratings — show both RATING and CRITICS columns
                extra_cols.append(('RATING',  7, lambda r: f"{r['rating']:.1f}" if r['rating'] else '-'))
                extra_cols.append(('CRITICS', 7, lambda r: f"{r['critics']:.0f}%" if r['critics'] else '-'))
            else:
                # No RT agent — audience score only, labelled RATING
                extra_cols.append(('RATING', 7, lambda r: f"{r['rating']:.1f}" if r['rating'] else '-'))

        if has_added:
            extra_cols.append(('ADDED', 10, lambda r: _fmt_ts(r['added'])))

        # lang: → AUDIO column only; subs: → SUBS column only; both → AUDIO + SUBS
        if has_lang:
            extra_cols.append(('AUDIO', 8,  lambda r: r['audio_langs'] or '-'))
        if has_subs:
            extra_cols.append(('SUBS',  8,  lambda r: r['sub_langs'] or '-'))

        if has_genre:
            extra_cols.append(('GENRE',  16, lambda r: r['genres'][:15] if r['genres'] else '-'))
        if has_label:
            extra_cols.append(('LABELS', 14, lambda r: r['labels'] or '-'))

        # --- Series rollup: compact episode output by season → show ---
        # Rule (user-specified): compare display column values (strings).
        #   Phase 1 — Season rollup: if all matched episodes of a season share the
        #             same display column values → emit one Season: row.
        #   Phase 2 — Show rollup: if all Season: rows for a show share the same
        #             display column values AND cover all seasons of the show
        #             (seasons with zero matches are OK if all their episodes lack
        #             audio-language metadata — detection gap, not genuine mismatch)
        #             → emit one Show: row.

        def _row_sig(r):
            """Tuple of display column values for a row — used for equality check."""
            return tuple(vfn(r) for _, _, vfn in extra_cols)

        # Build reverse mapping episode_key → (show_key, S_str)
        _ep_to_show_s = {}
        for _sk, _seasons in PLEX_Media.OBJ_BY_SHOW_EPISODES.items():
            for _s, _eps in _seasons.items():
                for _e, _vs in _eps.items():
                    for _ver, _ks in _vs.items():
                        for _ek in _ks:
                            _ep_to_show_s[_ek] = (_sk, _s)

        _movie_rows = [r for r in rows if r['type'] == 'Movie']
        _ep_rows    = [r for r in rows if r['type'] != 'Movie']

        if _ep_rows:
            from collections import defaultdict as _dd

            # Group episode rows by (show_key, S_str)
            _season_grps = _dd(list)
            _no_show = []
            for r in _ep_rows:
                m = _ep_to_show_s.get(r['key'])
                if m:
                    _season_grps[m].append(r)
                else:
                    _no_show.append(r)

            # Phase 1: season rollup — same display values → Season: row
            _show_rows = _dd(list)  # show_key → [season or individual episode rows]

            for (_sk, _s), _grp in _season_grps.items():
                _sigs = {_row_sig(r) for r in _grp}
                if len(_sigs) <= 1:  # all matched episodes share the same display values
                    _skey     = (PLEX_Media.OBJ_BY_SHOW.get(_sk) or {}).get(_s)
                    import os as _os
                    from collections import Counter as _Counter
                    _ep_dirs  = [_os.path.dirname(r['filepath']) for r in _grp if r['filepath']]
                    _season_dir = _Counter(_ep_dirs).most_common(1)[0][0] if _ep_dirs else ''
                    _sr           = dict(_grp[0])
                    _sr['key']    = _skey or f"{_sk}/{_s}"
                    _sr['filepath'] = _season_dir
                    _sr['_rtype'] = 'season'
                    _sr['_sk']    = _sk
                    _sr['_s']     = _s
                    _sr['_dir']   = _season_dir
                    _show_rows[_sk].append(_sr)
                else:
                    for r in _grp:
                        r['_rtype'] = 'ep'
                    _show_rows[_sk].extend(_grp)

            # Phase 2: show rollup — all Season: rows same values + all seasons covered
            _final_ep = []
            for _sk, _s_rows in _show_rows.items():
                _all_season = all(r.get('_rtype') == 'season' for r in _s_rows)
                if _all_season and len({_row_sig(r) for r in _s_rows}) <= 1:
                    _all_seasons_in_show = set((PLEX_Media.OBJ_BY_SHOW.get(_sk) or {}).keys())
                    _covered   = {r['_s'] for r in _s_rows}
                    _uncovered = _all_seasons_in_show - _covered
                    # Uncovered seasons (zero matches) are OK ONLY for lang: filters,
                    # where episodes lacking audio_languages metadata are a Plex detection
                    # gap — not a genuine exclusion from the filter.
                    # For other filters (watched:, genre:, …) an uncovered season means
                    # the show genuinely has seasons that don't match, so no rollup.
                    _uncovered_ok = has_lang and all(
                        all(not PLEX_Media.OBJ_BY_ID.get(_ek, {}).get('audio_languages')
                            for _e2, _vs2 in PLEX_Media.OBJ_BY_SHOW_EPISODES.get(_sk, {}).get(_s2, {}).items()
                            for _ver2, _ks2 in _vs2.items()
                            for _ek in _ks2)
                        for _s2 in _uncovered
                    )
                    if _covered and (_covered == _all_seasons_in_show or _uncovered_ok):
                        import os as _os
                        from collections import Counter as _Counter
                        _s_dirs  = [r.get('_dir', '') for r in _s_rows if r.get('_dir')]
                        _show_dir = _Counter([_os.path.dirname(d) for d in _s_dirs]).most_common(1)[0][0] if _s_dirs else ''
                        _wr = dict(_s_rows[0])
                        _wr['key']      = _sk
                        _wr['filepath'] = _show_dir
                        _wr.pop('_rtype', None); _wr.pop('_sk', None); _wr.pop('_s', None); _wr.pop('_dir', None)
                        _final_ep.append(_wr)
                        continue
                _final_ep.extend(_s_rows)

            _final_ep.extend(_no_show)
            rows = _movie_rows + _final_ep

        # Print header
        hdr  = f"{'KEY':<22}"
        sep  = "-" * 22
        for hname, hwidth, _ in extra_cols:
            hdr += f"  {hname:<{hwidth}}"
            sep += "  " + "-" * hwidth
        hdr += "  FILEPATH"
        sep += "  " + "-" * 40
        try:
            if VRB:
                print(hdr)
                print(sep)
            for r in rows:
                line = f"{r['key']:<22}"
                for _, hwidth, vfn in extra_cols:
                    val = vfn(r)
                    line += f"  {str(val):<{hwidth}}"
                line += f"  {r['filepath']}"
                print(line)
            if VRB: print(f"\n >>> {len(rows)} item(s)")
        except BrokenPipeError:
            pass

    @staticmethod
    def _list_ondisk_labeled(labeltext, library_name=None):
        """List cached objects that have labeltext in their ondisk_labels, with rollup.

        Episode → season → series rollup:
          All episodes in a season labeled  → show as one Season row
          All seasons in a show labeled     → show as one Series row
        Movies are listed individually.
        Uses OBJ_BY_ONDISK_LABEL index (populated by --update-cache).
        Returns count of display rows printed."""
        keys = set(PLEX_Media.OBJ_BY_ONDISK_LABEL.get(labeltext, []))
        if library_name:
            keys = {k for k in keys if (PLEX_Media.OBJ_BY_ID.get(k) or {}).get('library') == library_name}

        if not keys:
            scope = f" in '{library_name}'" if library_name else ""
            print(f"  No items with on-disk label '{labeltext}'{scope} found in cache.")
            print(f"  Run --update-cache to refresh, or --reencode --mark to detect and mark candidates.")
            return 0

        start = ONDISK_LABEL_START_MARKER
        end   = ONDISK_LABEL_END_MARKER

        # Separate movies from episodes
        movie_keys = []
        episode_keys = []
        for k in keys:
            obj = PLEX_Media.OBJ_BY_ID.get(k, {})
            t = obj.get('type', '')
            if t in ('Movie', 'Movie*'):
                movie_keys.append(k)
            elif t in ('Episode', 'Episode*'):
                episode_keys.append(k)

        # --- Episode rollup: group by show_key → season → episodes ---
        # Count all episodes per show and per season from cache
        show_ep_totals = {}   # show_key → total episode count in cache
        season_ep_totals = {} # (show_key, S_str) → total episode count in cache
        for show_key, seasons in PLEX_Media.OBJ_BY_SHOW_EPISODES.items():
            show_obj = PLEX_Media.OBJ_BY_ID.get(show_key, {})
            if library_name and show_obj.get('library') != library_name:
                continue
            total = 0
            for S_str, episodes in seasons.items():
                count = sum(len(v) for v in episodes.values())
                season_ep_totals[(show_key, S_str)] = count
                total += count
            show_ep_totals[show_key] = total

        # Group labeled episode keys by show_key → S_str
        labeled_by_show = {}  # show_key → {S_str → [ep_keys]}
        for k in episode_keys:
            obj = PLEX_Media.OBJ_BY_ID.get(k, {})
            show_key = obj.get('show_key', '')
            S_str    = obj.get('S_str', '')
            labeled_by_show.setdefault(show_key, {}).setdefault(S_str, []).append(k)

        # Build display rows
        rows = []  # list of (lib, type_label, title)
        for show_key, seasons_labeled in labeled_by_show.items():
            show_obj = PLEX_Media.OBJ_BY_ID.get(show_key, {})
            lib = show_obj.get('library', '?')
            show_title = show_obj.get('title', show_key)

            # Check show-level rollup: all seasons fully labeled?
            all_seasons_full = all(
                len(seasons_labeled.get(S_str, [])) >= season_ep_totals.get((show_key, S_str), 1)
                for S_str in (PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key) or {})
            ) and bool(PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key))
            labeled_ep_count = sum(len(v) for v in seasons_labeled.values())
            show_total = show_ep_totals.get(show_key, 0)
            if all_seasons_full or (show_total > 0 and labeled_ep_count >= show_total):
                rows.append((lib, 'Series', show_title))
                continue

            # Check season-level rollup per season
            seasons_in_show = PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key) or {}
            for S_str, ep_keys in sorted(seasons_labeled.items()):
                season_total = season_ep_totals.get((show_key, S_str), 0)
                if season_total > 0 and len(ep_keys) >= season_total:
                    rows.append((lib, 'Season', f"{show_title} {S_str}"))
                else:
                    for k in sorted(ep_keys):
                        obj = PLEX_Media.OBJ_BY_ID.get(k, {})
                        e_str = obj.get('E_str', '')
                        ep_title = obj.get('title', '')
                        rows.append((lib, 'Episode', f"{show_title} {S_str}{e_str} {ep_title}"))

        for k in sorted(movie_keys):
            obj = PLEX_Media.OBJ_BY_ID.get(k, {})
            lib = obj.get('library', '?')
            rows.append((lib, 'Movie', obj.get('title', k)))

        rows.sort(key=lambda r: (r[0], r[1], r[2]))
        print(f"\n  {'TYPE':<10}  {'LIBRARY':<16}  TITLE")
        print("  " + "-" * 70)
        for lib, type_label, title in rows:
            print(f"  {type_label:<10}  {lib[:16]:<16}  {title}")
        print(f"\n  Total: {len(rows)} item(s) with on-disk label {start}{labeltext}{end}")
        return len(rows)

    @staticmethod
    def _mark_reencode_candidates_on_disk(obj_keys, library_name, labeltext, remove_existing,
                                          dry_run=False, force=False):
        """Label or remove on-disk label for reencode candidates.

        Placement rules (same as detection rollup):
          - Movie          → label on movie directory
          - Show (all seasons flagged) → label on series directory
          - Season (all eps flagged)   → label on season directory
          - Individual episodes        → label on episode file(s) + sibling files

        dry_run: print what would happen but do not rename anything.
        force:   also REMOVE the label from items that are BELOW threshold.
        Prints WARNINGS for items that are labeled but below threshold.
        Always prints a SUMMARY at the end.
        """
        start = ONDISK_LABEL_START_MARKER
        end   = ONDISK_LABEL_END_MARKER
        label_marker = f"{start}{labeltext}{end}"
        pfx = "[DRY-RUN] " if dry_run else ""

        _label_pattern = re.escape(start) + r'(?:(?!' + re.escape(start) + r'|' + re.escape(end) + r').)+' + re.escape(end)

        def _strip_label(name):
            """Remove the specific labeltext marker from name."""
            return re.sub(re.escape(label_marker), '', name).strip()

        def _add_label_to_name(name):
            """Add [labeltext] to name if not already present."""
            base = name
            if remove_existing:
                base = re.sub(_label_pattern, '', base).strip()
            if label_marker in base:
                return base
            return base.rstrip() + f" {label_marker}"

        def _do_rename(path, new_name, remote_host):
            """Execute or simulate a rename. Returns (success, new_path)."""
            parent = os.path.dirname(path)
            old_name = os.path.basename(path)
            if new_name == old_name:
                return True, path
            if dry_run:
                print(f"  {pfx}Would rename: {old_name}")
                print(f"              → {new_name}")
                return True, os.path.join(parent, new_name)
            success, new_path = my_plex_file_operation('RENAME', path, remote_host, new_filename=new_name)
            if success:
                print(f"  Renamed: {old_name}\n        → {new_name}")
                return True, os.path.join(parent, new_name)
            print(f"  WARNING: rename failed: {old_name}")
            return False, path

        remote_host = None
        if not dry_run:
            try:
                remote_host = determine_remote_host(None)[0]
            except Exception:
                remote_host = None

        # --- Build above/below threshold sets from cache ---
        threshold = REENCODE_THRESHOLD_MBPS
        flagged_movies   = []  # (key, obj, fp)  — above threshold
        flagged_ep_by_show = {}  # show_key → {s_str → {e_str → fp}}
        show_meta = {}  # show_key → (series_title, lib)

        for key in set(obj_keys):
            obj = PLEX_Media.OBJ_BY_ID.get(key)
            if not obj:
                continue
            obj_type = obj.get('type', '')
            if obj_type not in ('Movie', 'Movie*', 'Episode', 'Episode*'):
                continue
            if library_name and obj.get('library') != library_name:
                continue
            duration_ms = obj.get('duration') or 0
            if duration_ms < 60_000:
                continue
            files_dict = obj.get('files', {})
            is_above = any(
                (fi.get('filesize') or 0) > 0 and
                (fi['filesize'] * 8) / (duration_ms / 1000) / 1_000_000 >= threshold
                for fi in files_dict.values()
            )
            fp = next((fi.get('filepath', '') for fi in files_dict.values() if fi.get('filepath')), '')
            if is_above:
                if obj_type in ('Movie', 'Movie*'):
                    flagged_movies.append((key, obj, fp))
                else:
                    show_key = obj.get('show_key', '')
                    if not show_key:
                        continue
                    s_str = obj.get('S_str', 'S?')
                    e_str = obj.get('E_str', 'E?')
                    flagged_ep_by_show.setdefault(show_key, {})
                    flagged_ep_by_show[show_key].setdefault(s_str, {})[e_str] = fp
                    show_meta[show_key] = (obj.get('series', show_key), obj.get('library', '?'))

        # --- Find labeled-but-below-threshold items (warnings for --mark; core action for --force) ---
        labeled_keys = set(PLEX_Media.OBJ_BY_ONDISK_LABEL.get(labeltext, []))
        if library_name:
            labeled_keys = {k for k in labeled_keys
                            if (PLEX_Media.OBJ_BY_ID.get(k) or {}).get('library') == library_name}
        above_keys = set(k for k, _, _ in flagged_movies) | set(
            key for show in flagged_ep_by_show.values()
            for s in show.values() for key in [
                next((k for k in labeled_keys
                      if (PLEX_Media.OBJ_BY_ID.get(k) or {}).get('show_key') == sk
                      and (PLEX_Media.OBJ_BY_ID.get(k) or {}).get('S_str') == ss
                      and (PLEX_Media.OBJ_BY_ID.get(k) or {}).get('E_str') == es), None)
                for sk, show in flagged_ep_by_show.items()
                for ss, s_eps in show.items()
                for es in s_eps
            ] if key
        )
        # Simpler: keys in labeled_keys that are NOT above threshold
        flagged_obj_keys = set()
        for key in set(obj_keys):
            obj = PLEX_Media.OBJ_BY_ID.get(key)
            if not obj: continue
            obj_type = obj.get('type', '')
            if obj_type not in ('Movie', 'Movie*', 'Episode', 'Episode*'): continue
            if library_name and obj.get('library') != library_name: continue
            duration_ms = obj.get('duration') or 0
            if duration_ms < 60_000: continue
            files_dict = obj.get('files', {})
            is_above = any(
                (fi.get('filesize') or 0) > 0 and
                (fi['filesize'] * 8) / (duration_ms / 1000) / 1_000_000 >= threshold
                for fi in files_dict.values()
            )
            if is_above:
                flagged_obj_keys.add(key)
        mislabeled_keys = labeled_keys - flagged_obj_keys  # labeled but below threshold

        renamed_count = 0
        remove_count  = 0
        skip_count    = 0
        fail_count    = 0

        # --- Warn / remove mislabeled items ---
        if mislabeled_keys:
            print(f"\n  {'[DRY-RUN] ' if dry_run else ''}WARNING: {len(mislabeled_keys)} item(s) have [{labeltext}] but are BELOW threshold ({threshold} Mbps):")
            for k in sorted(mislabeled_keys):
                obj = PLEX_Media.OBJ_BY_ID.get(k, {})
                obj_type = obj.get('type', '')
                lib = obj.get('library', '?')
                title = obj.get('title', k)
                files_dict = obj.get('files', {})
                fp = next((fi.get('filepath', '') for fi in files_dict.values() if fi.get('filepath')), '')
                duration_ms = obj.get('duration') or 1
                mbps = max(
                    ((fi.get('filesize') or 0) * 8) / (duration_ms / 1000) / 1_000_000
                    for fi in files_dict.values()
                ) if files_dict else 0.0
                print(f"    WARNING [{lib}]  {title}  ({mbps:.1f} Mbps — below {threshold} Mbps threshold)")
                if force:
                    # Remove label from the path where it lives
                    path = fp
                    # For movies, remove from dir; episodes same (label may be on dir)
                    for candidate in ([os.path.dirname(fp), fp] if fp else []):
                        cname = os.path.basename(candidate)
                        if label_marker in cname:
                            new_name = _strip_label(cname)
                            ok, _ = _do_rename(candidate, new_name, remote_host)
                            if ok:
                                remove_count += 1
                            else:
                                fail_count += 1
                            break

        # --- Add labels: Movies ---
        for key, obj, fp in flagged_movies:
            if not fp:
                skip_count += 1
                continue
            movie_dir = os.path.dirname(fp)
            new_name = _add_label_to_name(os.path.basename(movie_dir))
            ok, new_dir = _do_rename(movie_dir, new_name, remote_host)
            if ok and new_dir != movie_dir:
                renamed_count += 1
            elif not ok:
                fail_count += 1

        # --- Add labels: Episodes with rollup ---
        for show_key, flagged_seasons in flagged_ep_by_show.items():
            all_seasons_data = PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key, {})
            all_season_keys = [s for s in all_seasons_data if s != 'S00']

            season_rollup = {}
            for s_str, ep_dict_total in all_seasons_data.items():
                if s_str not in flagged_seasons:
                    season_rollup[s_str] = 'none'
                    continue
                flagged_e = set(flagged_seasons[s_str].keys())
                total_e   = set(ep_dict_total.keys())
                season_rollup[s_str] = 'full' if flagged_e >= total_e else 'partial'

            show_full = (bool(all_season_keys) and
                         all(season_rollup.get(s, 'none') == 'full' for s in all_season_keys))

            sample_fp = next((fp for s in flagged_seasons.values() for fp in s.values() if fp), None)
            if not sample_fp:
                skip_count += 1
                continue
            season_dir = os.path.dirname(sample_fp)
            series_dir = os.path.dirname(season_dir)

            if show_full:
                new_name = _add_label_to_name(os.path.basename(series_dir))
                ok, new_dir = _do_rename(series_dir, new_name, remote_host)
                if ok and new_dir != series_dir:
                    renamed_count += 1
                elif not ok:
                    fail_count += 1
            else:
                for s_str in flagged_seasons:
                    rollup = season_rollup.get(s_str, 'partial')
                    season_fp = next(iter(flagged_seasons[s_str].values()), None)
                    if not season_fp:
                        skip_count += 1
                        continue
                    s_season_dir = os.path.dirname(season_fp)
                    if rollup == 'full':
                        new_name = _add_label_to_name(os.path.basename(s_season_dir))
                        ok, new_dir = _do_rename(s_season_dir, new_name, remote_host)
                        if ok and new_dir != s_season_dir:
                            renamed_count += 1
                        elif not ok:
                            fail_count += 1
                    else:
                        for e_str, fp in flagged_seasons[s_str].items():
                            if not fp:
                                skip_count += 1
                                continue
                            new_name = _add_label_to_name(os.path.basename(fp))
                            ok, new_fp = _do_rename(fp, new_name, remote_host)
                            if ok and new_fp != fp:
                                renamed_count += 1
                                # Rename sibling files (.srt, .nfo, etc.)
                                base_no_ext = os.path.splitext(fp)[0]
                                new_base_no_ext = os.path.splitext(new_fp)[0]
                                parent = os.path.dirname(fp)
                                ok2, listing = my_plex_file_operation('LIST_DIR', parent, remote_host, maxdepth=1)
                                if ok2 and listing:
                                    for sibling in listing:
                                        if sibling != fp and sibling.startswith(base_no_ext + '.'):
                                            ext = sibling[len(base_no_ext):]
                                            sib_new = os.path.basename(new_base_no_ext + ext)
                                            _do_rename(sibling, sib_new, remote_host)
                            elif not ok:
                                fail_count += 1

        # --- SUMMARY ---
        total_candidates = len(flagged_movies) + sum(
            len(eps) for show in flagged_ep_by_show.values()
            for s in show.values() for eps in [s]
        )
        print()
        print("=" * 76)
        print(f"{pfx}REENCODE MARK SUMMARY")
        print("=" * 76)
        print(f"  Threshold:           {REENCODE_THRESHOLD_MBPS} Mbps / {int(REENCODE_THRESHOLD_MBPS * _MB_PER_HOUR_PER_MBPS)} MB/hr")
        print(f"  Candidates (above):  {total_candidates}")
        if dry_run:
            print(f"  Would label:         {renamed_count}")
        else:
            print(f"  Labeled:             {renamed_count}")
        if mislabeled_keys:
            if force:
                action = "Removed (--force)" if not dry_run else "Would remove (--force)"
                print(f"  {action}: {remove_count}  (were labeled but below threshold)")
            else:
                print(f"  WARNING below threshold: {len(mislabeled_keys)}  (use --force to remove labels)")
        if skip_count:
            print(f"  Skipped (no path):   {skip_count}")
        if fail_count:
            print(f"  Rename failures:     {fail_count}")
        if dry_run:
            print()
            print(f"  (Dry run — no files were renamed. Remove --try to apply.)")
        print("=" * 76)

        if not dry_run and renamed_count > 0:
            print(f"\n  Refreshing on-disk labels in cache...")
            refresh_ondisk_labels_from_cache()
            update_and_save_cache({'obj_by_id': PLEX_Media.OBJ_BY_ID,
                                   'ondisk_labels_index': PLEX_Media.OBJ_BY_ONDISK_LABEL})
            print(f"  Cache updated. Run --scan to update Plex library paths.")

    @staticmethod
    def _find_duplicates(obj_keys, library_name):
        key_to_group = {}
        items_with_duplicates = {}
        for okey in obj_keys:
            obj = PLEX_Media.OBJ_BY_ID.get(okey)
            if not obj: continue
            dup_keys = generate_duplicate_keys(obj)
            if not dup_keys:
                continue
            existing_group = None
            for dk in dup_keys:
                if dk in key_to_group:
                    existing_group = key_to_group[dk]
                    break
            if existing_group:
                items_with_duplicates[existing_group].append(okey)
                for dk in dup_keys:
                    key_to_group[dk] = existing_group
            else:
                canonical = dup_keys[0]
                items_with_duplicates[canonical] = [okey]
                for dk in dup_keys:
                    key_to_group[dk] = canonical

        multi_version_keys = set()
        true_multiversion_keys = set()
        for key in obj_keys:
            obj = PLEX_Media.OBJ_BY_ID.get(key)
            if not obj: continue
            files_dict = obj.get('files', {})
            if len(files_dict) > 1:
                classification = classify_multi_version(obj)
                if classification == 'true_multiversion':
                    true_multiversion_keys.add(key)
                    continue
                multi_version_keys.add(key)
                duplicate_key = generate_duplicate_key(obj)
                if duplicate_key and duplicate_key not in items_with_duplicates:
                    items_with_duplicates[duplicate_key] = [key]

        if library_name is not None:
            filtered_duplicates = {}
            for dup_key, keys in items_with_duplicates.items():
                if len(keys) > 1:
                    all_in_library = all(PLEX_Media.OBJ_BY_ID[k].get('library') == library_name for k in keys)
                    if all_in_library:
                        filtered_duplicates[dup_key] = keys
                elif len(keys) == 1 and keys[0] in multi_version_keys:
                    if PLEX_Media.OBJ_BY_ID[keys[0]].get('library') == library_name:
                        filtered_duplicates[dup_key] = keys
            items_with_duplicates = filtered_duplicates
        else:
            items_with_duplicates = {
                dup_key: keys for dup_key, keys in items_with_duplicates.items()
                if len(keys) > 1 or (len(keys) == 1 and keys[0] in multi_version_keys)
            }

        ignored_count = 0
        if DUPLICATES_IGNORE_LIBRARY_COMBINATIONS:
            filtered = {}
            for dup_key, keys in items_with_duplicates.items():
                if len(keys) <= 1:
                    filtered[dup_key] = keys
                    continue
                libs = set(PLEX_Media.OBJ_BY_ID[k].get('library', '') for k in keys)
                should_ignore = False
                for ignore_group in DUPLICATES_IGNORE_LIBRARY_COMBINATIONS:
                    if libs.issubset(set(ignore_group)):
                        should_ignore = True
                        break
                if should_ignore:
                    ignored_count += 1
                else:
                    filtered[dup_key] = keys
            items_with_duplicates = filtered

        return items_with_duplicates, multi_version_keys, true_multiversion_keys, ignored_count

    @staticmethod
    def _print_duplicate_list(sorted_duplicates, multi_version_keys, true_multiversion_keys, ignored_count):
        print(f"\n{'PLEX-ID':<10} | {'ORIGINAL TITLE':<60} |{'LANG':^4}| {'NR':<3} | {'FILESIZE':<10} | {'CODEC':<10} | {'RESOLUTION':<12} | {'FILETYPE':<10} | FILEPATH")
        print("-" * 220)
        for dup_key, keys in sorted_duplicates:
            nr = 0
            group_titles = set(PLEX_Media.OBJ_BY_ID[k].get('title', '') for k in keys)
            if len(group_titles) > 1:
                ot = None
                for k in keys:
                    ot = PLEX_Media.OBJ_BY_ID[k].get('originalTitle')
                    if ot: break
                if ot:
                    libs = ', '.join(sorted(set(PLEX_Media.OBJ_BY_ID[k].get('library', '') for k in keys)))
                    print(f"{'':10} | >>> originalTitle: {ot:<38} |{'':4}| {'':3} | {'':10} | {'':10} | {'':12} | {'':10} | libraries: {libs}")
            for key in keys:
                obj = PLEX_Media.OBJ_BY_ID[key]
                files_dict = obj.get('files', {})
                if len(files_dict) > 1 and key in multi_version_keys:
                    sorted_files = sorted(files_dict.items(), key=lambda x: x[1].get('filepath') if isinstance(x[1], dict) else x[1])
                    for version_str, file_info in sorted_files:
                        nr += 1
                        what = get_media_description_original(obj)
                        lang = get_media_language(obj)
                        plex_id = obj.get('id')
                        if plex_id is None:
                            err(1061, f"Plex object is missing 'id' (ratingKey) field. Object key: {key}, Object: {obj}")
                        if isinstance(file_info, str):
                            filepath = file_info
                            size_bytes = None
                        elif isinstance(file_info, dict):
                            filepath = file_info.get('filepath', 'N/A')
                            size_bytes = file_info.get('filesize', None)
                        else:
                            filepath = 'N/A'
                            size_bytes = None
                            if DBG: print(f"{DBGPFX}WARNING: Unexpected file_info type {type(file_info)} for key {key} version {version_str}")
                        resolution = 'N/A'
                        codec = 'N/A'
                        if version_str:
                            import re
                            res_match = re.search(r'(\d+x\d+)', version_str)
                            if res_match: resolution = res_match.group(1)
                            codec_match = re.search(r'\((\w+)', version_str)
                            if codec_match: codec = codec_match.group(1)
                        filesize = format_filesize(size_bytes, force_unit='MB') if size_bytes else 'N/A'
                        filetype = os.path.splitext(filepath)[1][1:].upper() or 'N/A' if filepath != 'N/A' else 'N/A'
                        if len(what) > 60: what = what[:57] + "..."
                        print(f"{plex_id:<10} | {what:<60} |{lang:^4}| {nr:<3} | {filesize:<10} | {codec:<10} | {resolution:<12} | {filetype:<10} | {filepath}")
                else:
                    nr += 1
                    what = get_media_description_original(obj)
                    lang = get_media_language(obj)
                    plex_id = obj.get('id')
                    if plex_id is None:
                        err(1061, f"Plex object is missing 'id' (ratingKey) field. Object key: {key}, Object: {obj}")
                    filepath = obj.get('file') or 'N/A'
                    codec = obj.get('video_codec') or 'N/A'
                    resolution = obj.get('resolution_full') or 'N/A'
                    size_bytes = obj.get('filesize', None)
                    filesize = format_filesize(size_bytes, force_unit='MB') if size_bytes else 'N/A'
                    filetype = os.path.splitext(filepath)[1][1:].upper() or 'N/A' if filepath != 'N/A' else 'N/A'
                    if len(what) > 60: what = what[:57] + "..."
                    print(f"{plex_id:<10} | {what:<60} |{lang:^4}| {nr:<3} | {filesize:<10} | {codec:<10} | {resolution:<12} | {filetype:<10} | {filepath}")
        if true_multiversion_keys or ignored_count:
            print()
        if true_multiversion_keys:
            print(f"({len(true_multiversion_keys)} true multi-version item(s) excluded — genuinely different content, not duplicates)")
        if ignored_count:
            print(f"({ignored_count} cross-library duplicate(s) excluded — matching DUPLICATES_IGNORE_LIBRARY_COMBINATIONS)")

    @staticmethod
    def _sort_duplicates(items_with_duplicates):
        def sort_duplicate_keys(dup_item):
            dup_key, keys = dup_item
            sorted_keys = sorted(keys, key=lambda k: (
                PLEX_Media.OBJ_BY_ID[k].get('library', ''),
                PLEX_Media.OBJ_BY_ID[k].get('id', 0)
            ))
            return (dup_key, sorted_keys)
        return [sort_duplicate_keys(item) for item in sorted(items_with_duplicates.items())]

    @staticmethod
    def _filter_by_watch_and_audio(obj_keys, library_name, watched_only, unwatched_only, audio_filter, no_audio_language):
        filtered_keys = []
        for key in obj_keys:
            obj = PLEX_Media.OBJ_BY_ID.get(key)
            if not obj: continue
            obj_type = obj.get('type')
            if obj_type in ('Show', 'Season'):
                continue
            if watched_only or unwatched_only:
                view_count = obj.get('viewCount', 0)
                if watched_only and view_count == 0:
                    continue
                if unwatched_only and view_count > 0:
                    continue
            if audio_filter:
                audio_languages = obj.get('audio_languages', [])
                if not audio_languages or audio_filter not in audio_languages:
                    continue
            if no_audio_language:
                audio_languages = obj.get('audio_languages', [])
                if audio_languages:
                    continue
            filtered_keys.append(key)

        if not filtered_keys:
            filter_parts = []
            if watched_only:        filter_parts.append("watched")
            elif unwatched_only:    filter_parts.append("unwatched")
            if audio_filter:        filter_parts.append(f"{audio_filter} audio")
            if no_audio_language:   filter_parts.append("no-audio-language")
            filter_desc = " ".join(filter_parts)
            scope = f" in library '{library_name}'" if library_name else ""
            print(f"No {filter_desc} items found{scope}.")
            return None
        return filtered_keys

    @staticmethod
    def list(args, obj_args, library_name, media_type, duplicates_only=False, resolve_mode=False, broken_only=False, watched_only=False, unwatched_only=False, audio_filter=None, no_audio_language=False, excess_versions=None):
        global FORMAT
        if DBG: print(f"{DBGPFX}PLEX_Media.list( library_name = {library_name}', media_type = '{media_type}', duplicates_only = {duplicates_only}, resolve_mode = {resolve_mode}, broken_only = {broken_only}, watched_only = {watched_only}, unwatched_only = {unwatched_only}, audio_filter = {audio_filter}, no_audio_language = {no_audio_language}, excess_versions = {excess_versions} )")

        audio_filter, media_type, should_continue = PLEX_Media._normalize_list_args(audio_filter, media_type, library_name, duplicates_only, broken_only, watched_only, unwatched_only, no_audio_language, excess_versions)
        if not should_continue:
            return

        PLEX_Media._print_list_header(library_name, media_type, broken_only, duplicates_only, watched_only, unwatched_only, audio_filter, no_audio_language)

        # Collect keys
        # When checking duplicates, broken files, or excess versions, always collect from ALL libraries so we can filter properly
        if duplicates_only or broken_only or excess_versions:
            obj_keys = collect_library_keys(library_name=None, media_type=media_type)
        else:
            obj_keys = collect_library_keys(library_name=library_name, media_type=media_type)

        if DBG: print(f"{DBGPFX}PLEX_Media.list(): obj_keys = {obj_keys}")

        # Filter for broken files if requested
        if broken_only:
            PLEX_Media._list_broken_files(obj_keys, library_name)
            return

        # List entries with excess versions if requested
        if excess_versions:
            PLEX_Media._list_excess_versions(obj_keys, library_name, excess_versions)
            return

        # Filter for duplicates if requested
        elif duplicates_only:
            items_with_duplicates, multi_version_keys, true_multiversion_keys, ignored_count = PLEX_Media._find_duplicates(obj_keys, library_name)

            if not items_with_duplicates:
                print(f"No duplicates{f' in {chr(39)}{library_name}{chr(39)}' if library_name else ''} found.")
                return

            sorted_duplicates = PLEX_Media._sort_duplicates(items_with_duplicates)

            if not resolve_mode:
                PLEX_Media._print_duplicate_list(sorted_duplicates, multi_version_keys, true_multiversion_keys, ignored_count)

            # Interactive resolution mode
            if resolve_mode:
                print("\n" + "="*76)
                print("INTERACTIVE RESOLUTION MODE")
                print("="*76)
                print("\nNOTE: If files are not found locally, the script will automatically attempt")
                print("to access them via SSH on host 'my-plex'. Please ensure:")
                print("  - SSH host 'my-plex' is configured in ~/.ssh/config")
                print("  - You can connect without password: ssh my-plex")
                print("  - SSH keys are properly set up")
                print("="*76)

                # Create resolution log file (JSON format)
                timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
                log_filename = f"/tmp/my-plex_--duplicates_--resolve_{timestamp}.json"

                try:
                    resolution_log_data = {
                        "session": {
                            "started": datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                            "command": ' '.join(sys.argv),
                            "timestamp": timestamp,
                            "log_format_version": "1.0"
                        },
                        "operations": []
                    }
                    print(f"\n📝 Resolution log: {log_filename}\n")
                except Exception as e:
                    print(f"⚠ Warning: Could not initialize resolution log: {e}")
                    resolution_log_data = None

                operation_counter = 0
                pending_operations = []  # Track pending operations (not yet applied)
                operations_all_succeeded = True  # Track if all applied operations succeeded

                # DEBUG: Show how many duplicates we're going to process
                total_duplicates = len(sorted_duplicates)
                if DBG:
                    print(f"{DBGPFX}Total duplicate groups to process: {total_duplicates}")

                try:
                    for dup_idx, (dup_key, keys) in enumerate(sorted_duplicates, 1):
                        if DBG:
                            print(f"{DBGPFX}Processing duplicate {dup_idx}/{total_duplicates}: {dup_key}")

                        # Check if this is a multi-version item (single Plex entry with multiple file versions)
                        is_multi_version = False
                        multi_version_files = []
                        if len(keys) == 1 and keys[0] in PLEX_Media.OBJ_BY_ID:
                            files_dict = PLEX_Media.OBJ_BY_ID[keys[0]].get('files', {})
                            if len(files_dict) > 1:
                                is_multi_version = True
                                # Store (version_str, filepath) for each version
                                # Handle both old format (ver -> filepath string) and new format (ver -> dict with 'filepath' key)
                                multi_version_files = []
                                for ver, file_info in files_dict.items():
                                    if isinstance(file_info, str):
                                        # Old cache format: files_dict = {ver: filepath_string}
                                        multi_version_files.append((ver, file_info))
                                    elif isinstance(file_info, dict):
                                        # New cache format: files_dict = {ver: {'filepath': ..., 'filesize': ...}}
                                        multi_version_files.append((ver, file_info['filepath']))
                                    else:
                                        print(f"[WARNING] Unexpected file_info type: {type(file_info)}")
                                if DBG:
                                    print(f"{DBGPFX}This is a multi-version item with {len(files_dict)} file versions in single Plex entry")

                        # Skip only if we have less than 2 keys AND it's not a multi-version item
                        if len(keys) < 2 and not is_multi_version:
                            if DBG:
                                print(f"{DBGPFX}Skipping duplicate {dup_idx} - only {len(keys)} item(s) remaining (likely already resolved)")
                            continue  # Skip if not actually duplicates

                        # Format the duplicate key for display (add parentheses around year for movies)
                        display_key = dup_key
                        if dup_key.startswith('movie:'):
                            parts = dup_key.split(':')
                            if len(parts) == 3:
                                display_key = f"{parts[0]}:{parts[1]} ({parts[2]})"

                        # Display the duplicate pair/group
                        print(f"\n{'='*76}")
                        print(f"RESOLVING DUPLICATES FOR: {display_key}")
                        print(f"{'='*76}")

                        # For multi-version items, expand into separate virtual entries
                        # Create temporary objects for each version so the rest of the code can handle them uniformly
                        if is_multi_version:
                            print(f"\n[INFO] This Plex entry (ID: {keys[0]}) contains {len(multi_version_files)} file versions.")
                            print(f"       Expanding into separate entries for resolution.\n")

                            # Get the original object
                            original_obj = PLEX_Media.OBJ_BY_ID[keys[0]]
                            original_key = keys[0]

                            # Create synthetic objects for each file version
                            synthetic_keys = []
                            for idx, (version_str, filepath) in enumerate(sorted(multi_version_files, key=lambda x: x[1]), 1):
                                # Create a synthetic key
                                synthetic_key = f"{original_key}_version{idx}"

                                # Create a copy of the original object but with updated file info
                                synthetic_obj = dict(original_obj)
                                synthetic_obj['file'] = filepath
                                synthetic_obj['version'] = version_str

                                # Get filesize for this specific version from files dict
                                files_dict = original_obj.get('files', {})
                                if version_str in files_dict:
                                    file_info = files_dict[version_str]
                                    # BUG FIX: Handle both old and new cache formats
                                    if isinstance(file_info, dict):
                                        # New format: filesize is stored in the dict
                                        synthetic_obj['filesize'] = file_info.get('filesize', original_obj.get('filesize'))
                                    else:
                                        # Old format: file_info is just a filepath string, no filesize stored per version
                                        # Need to get actual filesize from Plex server for accurate display
                                        # For now, use None to indicate filesize is unknown (will show "N/A")
                                        # This will be corrected when cache is updated with --update-cache
                                        synthetic_obj['filesize'] = None

                                synthetic_obj['_is_synthetic'] = True
                                synthetic_obj['_original_key'] = original_key
                                synthetic_obj['_version_index'] = idx

                                # Temporarily add to OBJ_BY_ID so display/resolution code can access it
                                PLEX_Media.OBJ_BY_ID[synthetic_key] = synthetic_obj
                                synthetic_keys.append(synthetic_key)

                            # Replace keys with synthetic keys
                            keys = synthetic_keys
                        else:
                            # Always sort keys by file path for consistent display
                            # This ensures entries are shown in alphabetical order by file location
                            keys = sorted(keys, key=lambda k: PLEX_Media.OBJ_BY_ID[k].get('file', ''))
    
                        # Check if both files point to the same physical file (Plex database corruption)
                        same_file = False
                        if len(keys) == 2:
                            file1_path = PLEX_Media.OBJ_BY_ID[keys[0]].get('file', 'N/A')
                            file2_path = PLEX_Media.OBJ_BY_ID[keys[1]].get('file', 'N/A')
                            same_file = (file1_path == file2_path)

                        # Check if directories are different (for option 7)
                        # Option 7 should be available when there are 2+ files in different directories
                        show_rename_option = False
                        if len(keys) >= 2:
                            # Get all directories
                            dirs = []
                            all_files_valid = True
                            for key in keys:
                                file_path = PLEX_Media.OBJ_BY_ID[key].get('file', 'N/A')
                                if file_path == 'N/A':
                                    all_files_valid = False
                                    break
                                dirs.append(os.path.dirname(file_path))
    
                            # Show rename option if all files are valid and at least 2 are in different directories
                            if all_files_valid and len(set(dirs)) > 1:
                                show_rename_option = True
    
                        # Get file paths and library info for menu
                        file1_path = PLEX_Media.OBJ_BY_ID[keys[0]].get('file', 'N/A') if len(keys) > 0 else 'N/A'
                        file2_path = PLEX_Media.OBJ_BY_ID[keys[1]].get('file', 'N/A') if len(keys) > 1 else 'N/A'
    
                        # Get library names and directories for options 5 and 6
                        lib1_name = PLEX_Media.OBJ_BY_ID[keys[0]].get('library', '') if len(keys) > 0 else ''
                        lib2_name = PLEX_Media.OBJ_BY_ID[keys[1]].get('library', '') if len(keys) > 1 else ''
                        lib1_dir = get_library_dir_from_path(file1_path, lib1_name) if file1_path != 'N/A' and lib1_name else ''
                        lib2_dir = get_library_dir_from_path(file2_path, lib2_name) if file2_path != 'N/A' and lib2_name else ''
    
                        # Get movie directories (directory directly within library) for display in menu
                        # Always call get_movie_dir_from_path even if lib_name is empty - it has a fallback
                        movie_dir1 = get_movie_dir_from_path(file1_path, lib1_name) if file1_path != 'N/A' else file1_path
                        movie_dir2 = get_movie_dir_from_path(file2_path, lib2_name) if file2_path != 'N/A' else file2_path
                        file1_folder = os.path.basename(movie_dir1) if movie_dir1 != 'N/A' else ''
                        file2_folder = os.path.basename(movie_dir2) if movie_dir2 != 'N/A' else ''

                        # Play options - use two-stage menu for 4+ files
                        num_files = len(keys)

                        while True:
                            # Display menu inside loop so it refreshes after each undo
                            # Show file information each time
                            print()
                            for nr, key in enumerate(keys, 1):
                                obj = PLEX_Media.OBJ_BY_ID[key]
                                display_duplicate_details(nr, obj)

                            print("\nChoose action:")

                            if num_files <= 3:
                                # Direct play options for 1-3 files
                                for i in range(num_files):
                                    print(f"  {i+1} = Play file [{i+1}] (mpv/Plex/Infuse)")
                            else:
                                # Two-stage menu for 4+ files
                                print(f"  1 = Play file (select from {num_files} files)")

                            # Trash options
                            if num_files <= 3:
                                # Direct trash options for files 1-3
                                for i in range(num_files):
                                    option_num = i + 1 + num_files  # Offset by number of play options
                                    if same_file:
                                        print(f"  {option_num} = Remove Plex entry [{i+1}] (database only - file will NOT be trashed)")
                                    else:
                                        # Get file path and directory info for this file
                                        file_key = keys[i]
                                        file_obj = PLEX_Media.OBJ_BY_ID[file_key]
                                        file_path = file_obj.get('file', 'N/A')
                                        lib_name = file_obj.get('library', '')
                                        movie_dir = get_movie_dir_from_path(file_path, lib_name) if file_path != 'N/A' and lib_name else os.path.dirname(file_path)

                                        # Check if file is in a subdirectory (movie_dir != file's parent dir)
                                        file_parent = os.path.dirname(file_path)
                                        is_in_subdir = (movie_dir != file_parent) if file_path != 'N/A' else False

                                        # For multi-version items with 2 files, check the relationship
                                        other_file_in_subdir = False
                                        subdir_name = ""
                                        if is_multi_version and num_files == 2:
                                            other_idx = 1 - i  # Get the other file index (0->1, 1->0)
                                            other_key = keys[other_idx]
                                            other_obj = PLEX_Media.OBJ_BY_ID[other_key]
                                            other_path = other_obj.get('file', 'N/A')
                                            other_parent = os.path.dirname(other_path)

                                            # Check if other file is in a subdirectory relative to this file
                                            if i == 1:  # This is file [2]
                                                # Check if file [1] is in subdirectory of file [2]'s directory
                                                file1_parent = os.path.dirname(file1_path)
                                                file2_parent = os.path.dirname(file2_path)
                                                if file1_parent.startswith(file2_parent + os.sep) and file1_parent != file2_parent:
                                                    other_file_in_subdir = True
                                                    subdir_name = os.path.basename(file1_parent)

                                        if is_in_subdir:
                                            # This file is in a subdirectory - will be trashed with subdirectory
                                            subdir_name = os.path.basename(file_parent)
                                            print(f"  {option_num} = Trash file [{i+1}] (including subdirectory '{subdir_name}')")
                                        elif other_file_in_subdir:
                                            # Other file is in subdirectory - trashing this will move other file up
                                            print(f"  {option_num} = Trash file [{i+1}] and move file [{1-i+1}] from subdirectory '{subdir_name}' to parent (then remove subdirectory)")
                                        else:
                                            print(f"  {option_num} = Trash file [{i+1}]")
                            else:
                                # For 4+ files, only offer trash via two-stage menu
                                print(f"  2 = Trash file (select from {num_files} files)")

                            if len(keys) == 2:
                                if same_file:
                                    print(f"  NOTE: Both entries point to the SAME file (Plex database corruption)")
                                    print(f"        Options 5 & 6 are not available. Use option 3 or 4 to remove the duplicate Plex entry.")
                                elif is_multi_version:
                                    print(f"  NOTE: This is a multi-version item (single Plex entry with multiple file versions)")
                                    print(f"        Options 5 & 6 are not available. Use option 3 or 4 to remove a specific version.")
                                else:
                                    print(f"  5 = Trash [1] and move [2] to library of [1]. Trash \"{file1_folder}\" && mv \"{file2_folder}\" \"{lib1_dir}/\"")
                                    print(f"  6 = Trash [2] and move [1] to library of [2]. Trash \"{file2_folder}\" && mv \"{file1_folder}\" \"{lib2_dir}/\"")
                            if show_rename_option:
                                print("  7 = Rename all files using directory name")
                            if pending_operations:
                                last_pending = pending_operations[-1]
                                last_choice = last_pending.get('choice', '')

                                # Get the filename from the pending operation
                                file1 = last_pending.get('file1', '')
                                file2 = last_pending.get('file2', '')
                                if last_choice == '3':
                                    filename = os.path.basename(file1)
                                    undo_desc = f"Remove 'Trash file {filename}'"
                                elif last_choice == '4':
                                    filename = os.path.basename(file2)
                                    undo_desc = f"Remove 'Trash file {filename}'"
                                elif last_choice == '5':
                                    file1_name = os.path.basename(file1)
                                    file2_name = os.path.basename(file2)
                                    undo_desc = f"Remove 'Trash {file1_name} and move {file2_name}'"
                                elif last_choice == '6':
                                    file1_name = os.path.basename(file1)
                                    file2_name = os.path.basename(file2)
                                    undo_desc = f"Remove 'Trash {file2_name} and move {file1_name}'"
                                elif last_choice == '7':
                                    undo_desc = "Remove 'Rename files using directory name'"
                                else:
                                    undo_desc = f"Remove operation"

                                print(f"  U = Undo last pending operation ({len(pending_operations)} pending): {undo_desc}")
                            print("  N = Next (skip this pair)")
                            if pending_operations:
                                print(f"  A = Apply all {len(pending_operations)} pending operation(s) and quit")
                            print("  Q = Quit resolution mode (without applying pending operations)")
                            try:
                                print("\nYour choice: ", end='', flush=True)
                                choice = readchar.readchar()
                                # Echo the choice as entered (user must type uppercase)
                                print(choice)

                                if choice == 'Q':
                                    if pending_operations:
                                        print(f"\n⚠ Warning: You have {len(pending_operations)} pending operation(s) that will NOT be applied!")
                                        print("Are you sure you want to quit without applying them?")
                                        print("  Y = Yes, quit without applying")
                                        print("  N = No, go back")
                                        print("\nYour choice: ", end='', flush=True)
                                        confirm = readchar.readchar()
                                        print(confirm)
                                        if confirm != 'Y':
                                            print("Cancelled. Returning to resolution mode.")
                                            continue

                                    # CRITICAL: Clean up ALL synthetic objects from OBJ_BY_ID before exiting
                                    # Synthetic objects are temporary and should NEVER be saved to cache
                                    print(f"\nCleaning up synthetic objects...", end=' ', flush=True)
                                    synthetic_keys_to_remove = [
                                        key for key, obj in PLEX_Media.OBJ_BY_ID.items()
                                        if obj.get('_is_synthetic')
                                    ]
                                    for key in synthetic_keys_to_remove:
                                        del PLEX_Media.OBJ_BY_ID[key]
                                    if synthetic_keys_to_remove:
                                        print(f"✓ (removed {len(synthetic_keys_to_remove)} synthetic objects)")
                                    else:
                                        print("✓ (none found)")

                                    print("Exiting resolution mode without applying pending operations.")
                                    return

                                if choice == 'A':
                                    if not pending_operations:
                                        print("No pending operations to apply.")
                                        continue

                                    # First, clean up synthetic objects for the CURRENT duplicate being displayed
                                    # (before applying operations)
                                    if is_multi_version and keys:
                                        for key in keys:
                                            if key in PLEX_Media.OBJ_BY_ID and PLEX_Media.OBJ_BY_ID[key].get('_is_synthetic'):
                                                del PLEX_Media.OBJ_BY_ID[key]

                                    print(f"\n{'='*76}")
                                    print(f"APPLYING {len(pending_operations)} PENDING OPERATION(S)")
                                    print(f"{'='*76}")
                                    # Apply all pending operations
                                    all_success = apply_pending_operations(pending_operations, resolution_log_data, remote_host)
                                    if not all_success:
                                        operations_all_succeeded = False
                                    num_ops = len(pending_operations)
                                    # Clear pending operations since they've been applied
                                    pending_operations.clear()

                                    # CRITICAL: Clean up ALL synthetic objects from OBJ_BY_ID before exiting
                                    # Synthetic objects are temporary and should NEVER be saved to cache
                                    print(f"\n  Cleaning up synthetic objects...", end=' ', flush=True)
                                    synthetic_keys_to_remove = [
                                        key for key, obj in PLEX_Media.OBJ_BY_ID.items()
                                        if obj.get('_is_synthetic')
                                    ]
                                    for key in synthetic_keys_to_remove:
                                        del PLEX_Media.OBJ_BY_ID[key]
                                    if synthetic_keys_to_remove:
                                        print(f"✓ (removed {len(synthetic_keys_to_remove)} synthetic objects)")
                                    else:
                                        print("✓ (none found)")

                                    if all_success:
                                        print(f"\n✓ All {num_ops} operation(s) successfully applied.")
                                    else:
                                        print(f"\n⚠ Some operations failed. Check output above for details.")
                                    print("Exiting resolution mode.")
                                    return

                                if choice == 'N':
                                    print("Skipping this duplicate pair.")
                                    break

                                if choice == 'U':
                                    if not pending_operations:
                                        print("No pending operations to undo.")
                                        continue

                                    # Remove the last pending operation
                                    last_pending = pending_operations.pop()
                                    operation_counter -= 1

                                    choice_desc = {
                                        '3': f'Trash file [1]',
                                        '4': f'Trash file [2]',
                                        '5': f'Trash [1] and move [2] to library of [1]',
                                        '6': f'Trash [2] and move [1] to library of [2]',
                                        '7': 'Rename files using directory name'
                                    }.get(last_pending['choice'], f'Unknown choice: {last_pending["choice"]}')

                                    print(f"\n✓ Removed pending operation #{last_pending['operation_number']}: {choice_desc}")
                                    print(f"  (Total pending: {len(pending_operations)})")
                                    print("\nReturning to current duplicate pair...\n")

                                    # Don't break - stay on current duplicate pair
                                    continue
    
                                # Build list of valid choices based on number of files
                                valid_choices = []
                                if num_files <= 3:
                                    # Direct options: 1-N for play, (N+1)-(2N) for trash
                                    for i in range(1, num_files + 1):
                                        valid_choices.append(str(i))  # Play options
                                    for i in range(num_files + 1, 2 * num_files + 1):
                                        valid_choices.append(str(i))  # Trash options
                                else:
                                    # Two-stage menu: 1 = play, 2 = trash
                                    valid_choices = ['1', '2']
    
                                if len(keys) == 2 and not same_file:
                                    valid_choices.extend(['5', '6'])
                                if show_rename_option:
                                    valid_choices.append('7')
    
                                if choice not in valid_choices:
                                    valid_str = ', '.join(valid_choices)
                                    print(f"Invalid choice. Please enter {valid_str}, N, or Q.")
                                    continue
    
                                # Handle two-stage menu for 4+ files
                                if num_files > 3 and choice in ['1', '2']:
                                    action = 'play' if choice == '1' else 'trash'
                                    print(f"\nSelect file to {action} (1-{min(num_files, 9)}):")
                                    for i in range(min(num_files, 9)):
                                        file_path = PLEX_Media.OBJ_BY_ID[keys[i]].get('file', 'N/A')
                                        print(f"  {i+1} = {os.path.basename(file_path)}")
                                    if num_files > 9:
                                        print(f"  (Only showing first 9 of {num_files} files)")
    
                                    print("\nYour selection: ", end='', flush=True)
                                    file_choice = readchar.readchar()
                                    print(file_choice)
    
                                    if file_choice not in [str(i) for i in range(1, min(num_files, 9) + 1)]:
                                        print(f"Invalid selection. Please enter 1-{min(num_files, 9)}.")
                                        continue
    
                                    # Map to direct choice number
                                    file_idx = int(file_choice) - 1
                                    if action == 'play':
                                        choice = file_choice  # Play is 1-9
                                    else:
                                        # Trash: need to map to appropriate choice
                                        # For now, we'll handle this differently
                                        choice = str(num_files + file_idx + 1)
    
                                # Handle choices for pairs only (5 and 6 require exactly 2 files)
                                # Option 7 works for 2+ files
                                if choice in ['5', '6'] and len(keys) != 2:
                                    print(f"Options 5 and 6 only work with pairs (2 files), but this group has {len(keys)} files.")
                                    continue
    
                                # Prevent options 5 and 6 when both entries point to the same file
                                if choice in ['5', '6'] and same_file:
                                    print(f"Options 5 and 6 are not available when both entries point to the same file.")
                                    print(f"This is a Plex database corruption. Use option 3 or 4 to trash the duplicate entry.")
                                    continue

                                # Prevent options 5 and 6 for multi-version items
                                if choice in ['5', '6'] and is_multi_version:
                                    print(f"Options 5 and 6 are not available for multi-version items (single Plex entry with multiple file versions).")
                                    print(f"Use option 3 or 4 to remove a specific version.")
                                    continue
    
                                # Handle option 7 only when directories are different
                                if choice == '7' and not show_rename_option:
                                    print("Option 7 is only available when files are in different directories.")
                                    continue
    
                                # Determine which files are involved based on choice
                                file1 = PLEX_Media.OBJ_BY_ID[keys[0]].get('file', 'N/A')
                                file2 = PLEX_Media.OBJ_BY_ID[keys[1]].get('file', 'N/A') if len(keys) >= 2 else 'N/A'
    
                                # Check if this is a play action for file 3 (when we have 3 files)
                                if num_files == 3 and choice == '3':
                                    # This is "Play file [3]"
                                    file_to_play = PLEX_Media.OBJ_BY_ID[keys[2]].get('file', 'N/A')
                                    remote_host_play, exists_play, resolved_file_to_play = determine_remote_host(file_to_play)
                                    if exists_play:
                                        print(f"Playing file [3]: {file_to_play}")
                                        play_media_file(resolved_file_to_play, remote_host_play)
                                        print("\nFile player launched. You can continue with other actions on this pair.")
                                    else:
                                        print(f"ERROR: Cannot find file: {file_to_play}")
                                    continue  # Go back to menu for next choice
    
                                # Check if this is a trash action for file 3
                                if num_files == 3 and choice == '6':
                                    # This is "Trash file [3]"
                                    file1 = PLEX_Media.OBJ_BY_ID[keys[2]].get('file', 'N/A')  # Use keys[2] as file1
                                    file2 = 'N/A'  # Not needed for single file trash
                                    # Remap choice to '3' or '4' for execute_resolution_action
                                    choice = '3'  # Will trash file1 (which is actually file [3])
    
                                # Get all files for option 7 (when there are 3+ files)
                                all_files = None
                                if choice == '7' and len(keys) > 2:
                                    all_files = [PLEX_Media.OBJ_BY_ID[key].get('file', 'N/A') for key in keys]
    
                                # Determine if files are local or remote, and resolve file paths
                                remote_host, exists, resolved_file1 = determine_remote_host(file1)
                                if not exists:
                                    print(f"ERROR: Cannot find file locally or on remote host: {file1}")
                                    print("Skipping this pair.")
                                    break

                                # For play actions with file2, resolve file2 as well
                                resolved_file2 = file2
                                if choice == '2' and file2 != 'N/A':
                                    _, exists2, resolved_file2 = determine_remote_host(file2)
                                    if not exists2:
                                        print(f"ERROR: Cannot find file locally or on remote host: {file2}")
                                        print("Skipping this pair.")
                                        break

                                # Handle the chosen action
                                # Play actions: 1, 2 (and 3 for 3-file case, but handled above)
                                is_play_action = choice in ['1', '2']

                                if is_play_action:
                                    # Execute play actions immediately (not recorded)
                                    # Use resolved paths for play actions
                                    success = execute_resolution_action(choice, resolved_file1, resolved_file2, remote_host, all_files, keys, None, None, same_file)
                                    print("\nFile player launched. You can continue with other actions on this pair.")
                                    # Continue loop to allow more choices
                                else:
                                    # Record non-play actions for later execution
                                    operation_counter += 1

                                    # For multi-version items, replace synthetic keys with original key
                                    # This is because synthetic objects are cleaned up after each duplicate
                                    actual_keys = keys
                                    if is_multi_version and len(keys) > 0:
                                        # Get the original key from the first synthetic object
                                        first_obj = PLEX_Media.OBJ_BY_ID.get(keys[0], {})
                                        original_key = first_obj.get('_original_key')
                                        if original_key:
                                            # For multi-version, store original key only (not synthetic keys)
                                            # The file paths in file1/file2 tell us which version to operate on
                                            actual_keys = [original_key]

                                    pending_op = {
                                        'operation_number': operation_counter,
                                        'choice': choice,
                                        'file1': file1,
                                        'file2': file2,
                                        'remote_host': remote_host,
                                        'all_files': all_files,
                                        'keys': actual_keys,
                                        'same_file': same_file,
                                        'dup_key': dup_key,
                                        'is_multi_version': is_multi_version
                                    }
                                    pending_operations.append(pending_op)

                                    # Show confirmation
                                    choice_desc = {
                                        '3': f'Trash file [1]: {os.path.basename(file1)}',
                                        '4': f'Trash file [2]: {os.path.basename(file2)}',
                                        '5': f'Trash [1] and move [2] to library of [1]',
                                        '6': f'Trash [2] and move [1] to library of [2]',
                                        '7': 'Rename files using directory name'
                                    }.get(choice, f'Unknown choice: {choice}')
                                    print(f"\n✓ Operation #{operation_counter} recorded: {choice_desc}")
                                    print(f"  (Total pending: {len(pending_operations)})")

                                    # Move to next duplicate pair
                                    break

                            except KeyboardInterrupt:
                                print("\n\nInterrupted by user. Exiting resolution mode.")
                                break  # Break out of duplicate pairs loop, will still save cache
                            except Exception as e:
                                print(f"ERROR: {e}")
                                print("Skipping this pair.")
                                break

                        # DEBUG: Confirm we finished processing this duplicate
                        if DBG:
                            print(f"{DBGPFX}Finished processing duplicate {dup_idx}/{total_duplicates}, moving to next...")

                        # Cleanup: Remove synthetic objects from OBJ_BY_ID to prevent them from being saved to cache
                        if is_multi_version:
                            for key in keys:
                                if key in PLEX_Media.OBJ_BY_ID and PLEX_Media.OBJ_BY_ID[key].get('_is_synthetic'):
                                    del PLEX_Media.OBJ_BY_ID[key]
                            if DBG:
                                print(f"{DBGPFX}Cleaned up {len(keys)} synthetic objects for multi-version item")

                    # After processing all duplicates, prompt user for final action if there are pending operations
                    # Also check if no duplicates were actually processed (all skipped)
                    if not pending_operations and dup_idx == total_duplicates:
                        # Check if all duplicates were skipped
                        # This happens when the cache is stale and contains duplicates that were already resolved
                        print(f"\n{'='*139}")
                        print(f"ALL DUPLICATES ALREADY RESOLVED")
                        print(f"{'='*139}")
                        print(f"\nAll {total_duplicates} duplicate(s) in the list have already been resolved (only 1 item remaining).")
                        print(f"This means your cache is stale and needs to be refreshed from the Plex server.")
                        print(f"\nTo update the cache and see only current duplicates, run:")
                        print(f"  my-plex --update-cache")
                    elif pending_operations:
                        print(f"\n{'='*139}")
                        print(f"ALL DUPLICATES PROCESSED")
                        print(f"{'='*139}")
                        print(f"\nYou have {len(pending_operations)} pending operation(s) that need to be applied.")
                        print("Choose final action:")
                        print(f"  A = Apply all {len(pending_operations)} pending operation(s) and quit")
                        print("  Q = Quit without applying pending operations")

                        while True:
                            try:
                                print("\nYour choice: ", end='', flush=True)
                                final_choice = readchar.readchar()
                                print(final_choice)

                                if final_choice == 'A':
                                    print(f"\n{'='*76}")
                                    print(f"APPLYING {len(pending_operations)} PENDING OPERATION(S)")
                                    print(f"{'='*76}")
                                    # Apply all pending operations
                                    all_success = apply_pending_operations(pending_operations, resolution_log_data, remote_host)
                                    if not all_success:
                                        operations_all_succeeded = False
                                    num_ops = len(pending_operations)
                                    # Clear pending operations since they've been applied
                                    pending_operations.clear()
                                    if all_success:
                                        print(f"\n✓ All {num_ops} operation(s) successfully applied.")
                                    else:
                                        print(f"\n⚠ Some operations failed. Check output above for details.")
                                    break
                                elif final_choice == 'Q':
                                    print(f"\n⚠ Warning: {len(pending_operations)} pending operation(s) will NOT be applied!")
                                    print("Are you sure you want to quit without applying them?")
                                    print("  Y = Yes, quit without applying")
                                    print("  N = No, go back")
                                    print("\nYour choice: ", end='', flush=True)
                                    confirm = readchar.readchar()
                                    print(confirm)
                                    if confirm == 'Y':
                                        print("Exiting without applying pending operations.")
                                        break
                                    else:
                                        print("Cancelled. Choose A or Q.")
                                        continue
                                else:
                                    print(f"Invalid choice. Please enter A or Q.")
                                    continue
                            except KeyboardInterrupt:
                                print("\n\nInterrupted by user.")
                                break

                except KeyboardInterrupt:
                    # Ctrl+C pressed during resolution
                    print("\n\n⚠ Resolution interrupted by user.")
                finally:
                    # DEBUG: Show loop completion info
                    if DBG:
                        print(f"{DBGPFX}For loop exited. Expected {total_duplicates} duplicates, processed through dup_idx={locals().get('dup_idx', 'N/A')}")

                    # Write resolution log to JSON file
                    if resolution_log_data:
                        resolution_log_data["session"]["ended"] = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                        resolution_log_data["session"]["total_operations"] = len(resolution_log_data.get("operations", []))

                        try:
                            with open(log_filename, 'w') as f:
                                # Use default handler to convert datetime objects to strings
                                json.dump(resolution_log_data, f, indent=2, default=str)
                            print(f"\n📝 Resolution log saved: {log_filename}")
                        except Exception as e:
                            print(f"\n⚠ Warning: Could not write resolution log: {e}")

                    print("\n" + "="*76)
                    print("RESOLUTION MODE COMPLETE")
                    print("="*76)

                    # Show summary
                    if pending_operations:
                        print(f"\n⚠ Warning: {len(pending_operations)} pending operation(s) were NOT applied.")
                        print(f"   To apply them, re-run resolution mode and press 'A' to apply and quit.")
                    elif operation_counter > 0:
                        if operations_all_succeeded:
                            print(f"\n✓ All {operation_counter} operation(s) were successfully applied.")
                        else:
                            print(f"\n⚠ Some operations failed. Check output above for details.")
                    else:
                        print(f"\n   No operations were performed.")
        else:
            if watched_only or unwatched_only or audio_filter or no_audio_language:
                filtered = PLEX_Media._filter_by_watch_and_audio(obj_keys, library_name, watched_only, unwatched_only, audio_filter, no_audio_language)
                if filtered is None:
                    return
                obj_keys = filtered

            saved_format = None
            if no_audio_language and FORMAT in ('tsv_labeled', 'tsv'):
                saved_format = FORMAT
                FORMAT = '{ID}\t{LIBRARY}\t{TITLE}\t{VERSION}\t{FILE}'

            for key in obj_keys: PLEX_Media.print_OBJ_BY_ID( key )

            if saved_format is not None:
                FORMAT = saved_format

            if no_audio_language and resolve_mode:
                resolve_no_audio_language(obj_keys, args)

    @staticmethod
    def list_collections(library_name):
        """List all collections in a specific library."""
        collections = []
        for col_key, col_dict in PLEX_Media.OBJ_BY_COLLECTION.items():
            if col_dict.get('library') == library_name:
                collections.append(col_dict)

        if not collections:
            print(f"No collections found in library '{library_name}'.")
            return

        collections.sort(key=lambda c: c.get('title', '').lower())

        if VRB: print(f"\nCollections in '{library_name}':")
        for col in collections:
            member_count = len(col.get('member_ids', []))
            print(f"  {col['title']} ({member_count} items)")
        print(f"\nTotal: {len(collections)} collections")

    @staticmethod
    def print_OBJ_BY_ID( key ):
        global DBG, VRB, FORMAT, LIST_MEDIA_DEFAULT_TSV_FORMAT

        if DBG: print(f"{DBGPFX}PLEX_Media.print_OBJ_BY_ID( key={key} )")

        labeled = False
        replace_w_bar = None
        match FORMAT:
            case 'pretty':
                PLEX_Media.print_OBJ_BY_ID___pretty( key )
                return
            case 'details'|'detailed':
                PLEX_Media.print_OBJ_BY_ID___details( key )
                return
            case 'tsv':         (replace_w_bar, format_str)          = ('\t', LIST_MEDIA_DEFAULT_TSV_FORMAT)
            case 'tsv_labeled': (replace_w_bar, format_str, labeled) = ('\t', LIST_MEDIA_DEFAULT_TSV_FORMAT, True)
            case _:     format_str = FORMAT

        # set all available variables in dict 'var'
        obj = PLEX_Media.OBJ_BY_ID[key]
        var = {}
        label = ''
        for k, v in obj.items():
            #print(f"k={k.upper()} : v={v}'''")
            #if v is None: v = 'n/a'
            k = k.upper()

            # Convert duration from milliseconds to minutes
            if k == 'DURATION' and v is not None:
                v = format_duration(v, 'm')

            if isinstance(v, list):
                match k:
                    case 'LABELS':              label = 'LABEL:' if labeled else ''
                    case 'ACTORS':              label = 'ACTOR:' if labeled else ''
                    case 'COLLECTIONS':         label = 'COLLECTION:' if labeled else ''
                    case 'DIRECTORS':           label = 'DIRECTOR:' if labeled else ''
                    case 'COUNTRIES':           label = 'COUNTRY:' if labeled else ''
                    case 'GENRES':              label = 'GENRE:' if labeled else ''
                    case 'AUDIO_LANGUAGES':     label = 'AUDIO-LANG:' if labeled else ''
                    case 'SUBTITLE_LANGUAGES':  label = 'SUBTITLE-LANG:' if labeled else ''
                    case 'WRITERS':             label = 'WRITER:' if labeled else ''
                    case 'VERSIONS':            label = 'VERSION:' if labeled else ''
                    case 'MEMBER_IDS':          label = 'MEMBER:' if labeled else ''
                    case 'MEMBERS':             label = 'MEMBER:' if labeled else ''
                    case 'ONDISK_LABELS':       label = 'ONDISK-LABEL:' if labeled else ''
                    case _:                     err(1058, f"Unknown list type (k={k})")
                v = (label if len(v)>0 else'') + (','+label).join(str(x) for x in v)
            else:
                if labeled: v = f"{k}:{v}"

            # ensure for instance for 'tsv' format, that we do NOT have tabs in the value:
            if replace_w_bar is not None: v.replace(replace_w_bar, '|')

            var[k] = v

        # prepare format_str: introduce var[..]
        #pattern = r"\{([A-Z_][A-Z0-9_]*)\}" # Regular expression to find uppercase words inside curly braces
        #format_str = re.sub(pattern, r"{var['\1']}", format_str) # Replace matches with the desired format

        # Pre-fill any format variables not present in obj with '' so format() won't KeyError
        for match in re.finditer(r'\{([A-Z_][A-Z0-9_]*)\}', format_str):
            if match.group(1) not in var:
                var[match.group(1)] = ''

        if DBG: print(f"{DBGPFX}PLEX_Media.print_OBJ_BY_ID(): format_str = '{format_str}'\n{DBGPFX}PLEX_Media.print_OBJ_BY_ID(): var = {var}")
        try:
            print( format_str.format(**var) )
        except KeyError as e:
            err(1046, f"You used an invalid variable name '{e.args[0]}' in the format string. See --format for more info.")

    @staticmethod
    def print_OBJ_BY_ID___pretty( key ):
        obj = PLEX_Media.OBJ_BY_ID[key]
        match obj['type']:
            case "Show": # key = show_key
                year_str = f"\t({obj['year']})" if obj['year']>0 else ""
                season_plural = "s" if obj['S_count']>1 else ""
                print(f"> SERIES\t{obj['title']}{year_str}\t: {obj['S_count']} season{season_plural}")
                # Season table
                print(f"\n  {'SEASON':<8} {'KEY':<16} {'EPISODES':>8}")
                for S_str in obj['members']:
                    season_obj_id = PLEX_Media.OBJ_BY_SHOW[ key ][ S_str ]
                    # Count episodes in this season
                    ep_count = 0
                    season_episodes = PLEX_Media.OBJ_BY_SHOW_EPISODES.get(key, {}).get(S_str, {})
                    for e_str, versions in season_episodes.items():
                        for version_str, ep_keys in versions.items():
                            ep_count += len(ep_keys)
                    print(f"  {S_str:<8} {season_obj_id:<16} {ep_count:>8}")
                if VRB:
                    print(f"\n{obj['file']}")
                    for S_str in obj['members']:
                        season_obj_id = PLEX_Media.OBJ_BY_SHOW[ key ][ S_str ]
                        season = PLEX_Media.OBJ_BY_ID[ season_obj_id ]
                        print(f"SERIES\t{obj['title']} Season {season['S_idx']}: {season['title']}")
                        for E_str in season['members']:
                            for version,partList in PLEX_Media.OBJ_BY_SHOW_EPISODES[ key ][S_str][ E_str ].items():
                                for part in partList:
                                    episode = PLEX_Media.OBJ_BY_ID[ part ]
                                    if VERYVRB:
                                        print(f"SERIES\t{obj['title']} {episode['E_str_full']} [{version}] {{{part}}}: {episode['title']}")
                                    else:
                                        print(f"SERIES\t{obj['title']} {episode['E_str_full']}: {episode['title']}")
                                    print(f"'{episode['file']}'")
            case "Movie":
                if VRB:
                    for version,obj_keys in obj['members'].items():
                        for key in obj_keys:
                            obj = PLEX_Media.OBJ_BY_ID[ key ]
                            if VERYVRB:
                                print(f"MOVIE\t{obj['title']} ({obj['year']}) [{version}] {{{key}}}\t'{obj['file']}'")
                            else:
                                print(f"MOVIE\t{obj['title']} ({obj['year']}) [{version}]\t'{obj['file']}'")
                else:
                    print(f"MOVIE\t{obj['title']} ({obj['year']})")
            case "Collection":
                member_count = len(obj.get('member_ids', []))
                print(f"COLLECTION\t{obj['title']}\t({member_count} items)")



    @staticmethod
    def print_OBJ_BY_ID___details( key ):
        obj = PLEX_Media.OBJ_BY_ID[key]
