#### EPISODE TSV INFRASTRUCTURE — for --missing and --sort-new
###########################################################################################

# Standardized episodes.tsv format:
#   # source: fernsehserien.de
#   # slug: die-millionenshow
#   # show_id: 22952
#   # updated: 2026-03-11
#   # DO NOT edit or remove the header comments above
#   season	episode	date	title
#
# The TSV is the source of truth for what episodes EXIST (aired).
# Plex cache tells us what episodes we HAVE (on disk).
# Diff = missing episodes.

EPISODES_TSV_FILENAME = 'episodes.tsv'
EPISODES_TSV_MAX_AGE = 86400  # 1 day in seconds

# ---------------------------------------------------------------------------
# Episode TSV read/write
# ---------------------------------------------------------------------------

def _file_exists_local_or_remote(filepath):
    """Check if a file exists locally or on the remote server via SSH.
    Returns True if the file exists in either location.
    Note: For bulk checks, use _batch_file_exists_remote() instead to avoid N SSH calls."""
    import os, subprocess
    if os.path.isfile(filepath):
        return True
    # Try SSH: translate to server path and check
    server_dir = get_server_path(os.path.dirname(filepath))
    server_file = os.path.join(server_dir, os.path.basename(filepath))
    escaped = escape_path_for_ssh(server_file)
    try:
        r = subprocess.run(
            ["ssh", PLEX_DB_REMOTE_HOST, f'[ -f "{escaped}" ] && echo YES'],
            capture_output=True, text=True, timeout=10
        )
        return r.returncode == 0 and 'YES' in r.stdout
    except Exception:
        return False


def _batch_file_exists_remote(filepaths):
    """Check which files exist on the remote server in a single SSH call.
    Args: filepaths - list of local paths to check (translated to server paths)
    Returns: set of local paths that exist on the server."""
    import os, subprocess
    if not filepaths:
        return set()
    # Build a shell script that checks each file and prints the index if it exists
    checks = []
    path_map = {}  # index -> local_path
    for i, fp in enumerate(filepaths):
        server_dir = get_server_path(os.path.dirname(fp))
        server_file = os.path.join(server_dir, os.path.basename(fp))
        escaped = escape_path_for_ssh(server_file)
        checks.append(f'[ -f "{escaped}" ] && echo {i}')
        path_map[i] = fp
    cmd = '; '.join(checks)
    try:
        r = subprocess.run(
            ["ssh", PLEX_DB_REMOTE_HOST, cmd],
            capture_output=True, text=True, timeout=30
        )
        if r.returncode in (0, 1):  # 1 is ok — means some files don't exist
            existing = set()
            for line in r.stdout.strip().splitlines():
                idx = int(line.strip())
                if idx in path_map:
                    existing.add(path_map[idx])
            return existing
    except Exception:
        pass
    return set()


def read_episodes_tsv(tsv_path):
    """Read episodes.tsv from local or remote path (falls back to SSH if local file missing).

    Returns: (metadata_dict, episodes_list) where
        metadata_dict: {'source': str, 'slug': str, 'show_id': str, 'updated': str,
                        'specials_pattern': str}
        episodes_list: [{'season': int, 'episode': int, 'date': str, 'title': str,
                         'original_title': str, 'date_local': str, 'sender_local': str,
                         'date_original': str, 'sender_original': str}, ...]
    Returns (None, None) if file doesn't exist.
    """
    import os, subprocess
    lines_iter = None
    if os.path.isfile(tsv_path):
        lines_iter = open(tsv_path, 'r', encoding='utf-8')
    else:
        # Try reading via SSH from server path
        server_path = get_server_path(os.path.dirname(tsv_path))
        server_tsv = os.path.join(server_path, EPISODES_TSV_FILENAME)
        escaped = escape_path_for_ssh(server_tsv)
        try:
            result = subprocess.run(
                ["ssh", PLEX_DB_REMOTE_HOST, f'cat "{escaped}"'],
                capture_output=True, text=True, timeout=10
            )
            if result.returncode == 0 and result.stdout.strip():
                lines_iter = result.stdout.splitlines(keepends=True)
            else:
                return None, None
        except Exception:
            return None, None

    metadata = {}
    episodes = []
    header_cols = None

    try:
        for line in lines_iter:
            line = line.rstrip('\n')
            if not line:
                continue

            # Parse header comments
            if line.startswith('#'):
                line = line.lstrip('#').strip()
                if ':' in line:
                    key, _, val = line.partition(':')
                    key = key.strip().lower()
                    val = val.strip()
                    if key in ('source', 'slug', 'show_id', 'updated', 'specials_pattern', 'show_title'):
                        metadata[key] = val
                continue

            # Parse column header
            if header_cols is None:
                header_cols = line.split('\t')
                # Normalize column names
                header_cols = [c.strip().lower().replace('-', '_').replace('release_date', 'date') for c in header_cols]
                continue

            # Parse data row
            parts = line.split('\t')
            if header_cols and len(parts) >= len(header_cols):
                row = {}
                for i, col in enumerate(header_cols):
                    row[col] = parts[i].strip() if i < len(parts) else ''
                # Normalize to standardized column names
                ep = {}
                ep['season'] = int(row.get('season', 0) or 0)
                ep['episode'] = int(row.get('episode', 0) or 0)
                ep['date'] = row.get('date', '')
                ep['title'] = row.get('title', '')
                ep['original_title'] = row.get('original_title', '')
                ep['date_local'] = row.get('date_local', '')
                ep['sender_local'] = row.get('sender_local', '')
                ep['date_original'] = row.get('date_original', '')
                ep['sender_original'] = row.get('sender_original', '')
                episodes.append(ep)
    finally:
        if hasattr(lines_iter, 'close'):
            lines_iter.close()

    return metadata, episodes


def write_episodes_tsv(tsv_path, metadata, episodes):
    """Write standardized episodes.tsv via SSH to the Plex server.

    If the file already exists, it is renamed to episodes.tsv.<updated-date> first.

    Args:
        tsv_path: Local file path (translated to server path for SSH)
        metadata: dict with keys: source, slug, show_id, updated, specials_pattern (all optional)
        episodes: list of dicts with keys: season, episode, date, title,
                  original_title, date_local, sender_local, date_original, sender_original
    """
    from datetime import datetime
    import subprocess

    # Update timestamp
    metadata['updated'] = datetime.now().strftime('%Y-%m-%d')

    # Build TSV content
    lines = []
    lines.append(f"# source: {metadata.get('source', '')}")
    lines.append(f"# slug: {metadata.get('slug', '')}")
    if metadata.get('show_id'):
        lines.append(f"# show_id: {metadata['show_id']}")
    if metadata.get('show_title'):
        lines.append(f"# show_title: {metadata['show_title']}")
    if metadata.get('specials_pattern'):
        lines.append(f"# specials_pattern: {metadata['specials_pattern']}")
    lines.append(f"# updated: {metadata['updated']}")
    lines.append("# DO NOT edit or remove the header comments above")
    lines.append("season\tepisode\tdate\ttitle\toriginal_title\tdate_local\tsender_local\tdate_original\tsender_original")

    for ep in sorted(episodes, key=lambda e: (e.get('season', 0), e.get('episode', 0))):
        s = ep.get('season', 0)
        e = ep.get('episode', 0)
        d = ep.get('date', '')
        t = ep.get('title', '')
        ot = ep.get('original_title', '')
        dl = ep.get('date_local', '')
        sl = ep.get('sender_local', '')
        do = ep.get('date_original', '')
        so = ep.get('sender_original', '')
        lines.append(f"{s}\t{e}\t{d}\t{t}\t{ot}\t{dl}\t{sl}\t{do}\t{so}")

    content = '\n'.join(lines) + '\n'

    # Translate local path to server path
    server_path = get_server_path(os.path.dirname(tsv_path))
    server_tsv = os.path.join(server_path, EPISODES_TSV_FILENAME)
    escaped_tsv = escape_path_for_ssh(server_tsv)

    # Backup existing TSV via SSH (rename to episodes.tsv.<updated-date>)
    # Read the old 'updated' date from the existing file header
    old_updated = metadata.get('_prev_updated', '')
    if not old_updated:
        # Try to get it from the file we just read (passed in via metadata by caller)
        # If not available, we'll use 'prev' as suffix
        old_updated = ''
    backup_suffix = f'.{old_updated}' if old_updated else '.prev'
    escaped_backup = escape_path_for_ssh(server_tsv + backup_suffix)

    # SSH: if file exists, rename it; then write new content via cat
    rename_cmd = f'[ -f "{escaped_tsv}" ] && mv "{escaped_tsv}" "{escaped_backup}"; cat > "{escaped_tsv}"'
    result = subprocess.run(
        ["ssh", PLEX_DB_REMOTE_HOST, rename_cmd],
        input=content, capture_output=True, text=True
    )
    if result.returncode != 0:
        print(f"  WARNING: Failed to write {server_tsv} via SSH: {result.stderr.strip()}")
        # Fallback: try local write
        try:
            with open(tsv_path, 'w', encoding='utf-8') as f:
                f.write(content)
        except Exception as e2:
            print(f"  WARNING: Local fallback also failed: {e2}")


def is_episodes_tsv_stale(tsv_path, max_age=EPISODES_TSV_MAX_AGE):
    """Check if episodes.tsv is missing or older than max_age seconds."""
    import os, time, subprocess
    if os.path.isfile(tsv_path):
        age = time.time() - os.path.getmtime(tsv_path)
        return age > max_age
    # Try SSH: check file age on server
    server_dir = get_server_path(os.path.dirname(tsv_path))
    server_tsv = os.path.join(server_dir, EPISODES_TSV_FILENAME)
    escaped = escape_path_for_ssh(server_tsv)
    try:
        r = subprocess.run(
            ["ssh", PLEX_DB_REMOTE_HOST, f'stat -f %m "{escaped}"'],
            capture_output=True, text=True, timeout=10
        )
        if r.returncode == 0 and r.stdout.strip():
            mtime = int(r.stdout.strip())
            age = time.time() - mtime
            return age > max_age
    except Exception:
        pass
    return True  # can't determine → treat as stale


def get_episodes_tsv_path(show_dir):
    """Return path to episodes.tsv for a given show directory (local path)."""
    import os
    return os.path.join(show_dir, EPISODES_TSV_FILENAME)


EPISODES_ERR_FILENAME = 'episodes.err'

def get_episodes_err_path(show_dir):
    """Return path to episodes.err for a given show directory (local path)."""
    import os
    return os.path.join(show_dir, EPISODES_ERR_FILENAME)


def write_episodes_err(show_dir, error_type, source, message):
    """Write an episodes.err file via SSH to the Plex server.
    Args:
        show_dir: local show directory path
        error_type: machine-readable type (no_external_ids, source_not_found, etc.)
        source: data source that failed (tmdb, tvdb, fernsehserien.de, etc.)
        message: human-readable description
    """
    import os, subprocess
    from datetime import date
    content = '# my-plex episode data error\n'
    content += f'# updated: {date.today().isoformat()}\n'
    content += f'error_type: {error_type}\n'
    content += f'source: {source}\n'
    content += f'message: {message}\n'

    server_dir = get_server_path(show_dir)
    server_err = os.path.join(server_dir, EPISODES_ERR_FILENAME)
    escaped_dir = escape_path_for_ssh(server_dir)
    escaped_err = escape_path_for_ssh(server_err)

    result = subprocess.run(
        ["ssh", PLEX_DB_REMOTE_HOST, f'mkdir -p "{escaped_dir}" && cat > "{escaped_err}"'],
        input=content, capture_output=True, text=True, timeout=10
    )
    if result.returncode != 0:
        # Fallback: try local write
        try:
            os.makedirs(show_dir, exist_ok=True)
            with open(os.path.join(show_dir, EPISODES_ERR_FILENAME), 'w', encoding='utf-8') as f:
                f.write(content)
        except Exception:
            pass  # Best effort


def read_episodes_err(show_dir):
    """Read an episodes.err file (local or via SSH). Returns dict or None."""
    import os, subprocess
    err_path = get_episodes_err_path(show_dir)
    lines = None
    if os.path.isfile(err_path):
        with open(err_path, 'r', encoding='utf-8') as f:
            lines = f.readlines()
    else:
        # Try reading via SSH
        server_dir = get_server_path(show_dir)
        server_err = os.path.join(server_dir, EPISODES_ERR_FILENAME)
        escaped = escape_path_for_ssh(server_err)
        try:
            r = subprocess.run(
                ["ssh", PLEX_DB_REMOTE_HOST, f'cat "{escaped}"'],
                capture_output=True, text=True, timeout=10
            )
            if r.returncode == 0 and r.stdout.strip():
                lines = r.stdout.splitlines()
        except Exception:
            pass
    if not lines:
        return None
    result = {}
    for line in lines:
        line = line.strip()
        if not line or line.startswith('#'):
            continue
        if ':' in line:
            key, _, value = line.partition(':')
            result[key.strip()] = value.strip()
    return result if result else None


def clear_episodes_err(show_dir):
    """Delete episodes.err if it exists locally or on server (problem resolved)."""
    import os, subprocess
    err_path = get_episodes_err_path(show_dir)
    if os.path.isfile(err_path):
        os.remove(err_path)
    # Also remove on server via SSH
    server_dir = get_server_path(show_dir)
    server_err = os.path.join(server_dir, EPISODES_ERR_FILENAME)
    escaped = escape_path_for_ssh(server_err)
    try:
        subprocess.run(
            ["ssh", PLEX_DB_REMOTE_HOST, f'rm -f "{escaped}"'],
            capture_output=True, text=True, timeout=10
        )
    except Exception:
        pass


def get_local_path(server_path):
    """Translate a server path to local path using ALTERNATIVE_ROOTPATHS.
    Returns the first alternative path that exists locally, or the original path if none exist."""
    resolved, _ = resolve_path(server_path, check='dir')
    return resolved


def get_server_path(local_path):
    """Translate a local path to server path using ALTERNATIVE_ROOTPATHS.
    Returns the first alternative path, or the original path."""
    import os
    for alt in get_alternative_paths(local_path):
        return alt  # first alternative = server path
    return local_path


# ---------------------------------------------------------------------------
# Filename date extraction interface
# ---------------------------------------------------------------------------

_custom_extractors_loaded = False
_custom_extractors = {}  # {'format_name': extract_function}

def _load_custom_date_extractors():
    """Load custom date extractors from the module specified in CUSTOM_DATE_EXTRACTORS config."""
    global _custom_extractors_loaded, _custom_extractors
    if _custom_extractors_loaded:
        return
    _custom_extractors_loaded = True

    if not CUSTOM_DATE_EXTRACTORS:
        return

    import importlib.util, os
    module_path = CUSTOM_DATE_EXTRACTORS
    if not os.path.isfile(module_path):
        print(f"WARNING: CUSTOM_DATE_EXTRACTORS module not found: {module_path}")
        return

    try:
        spec = importlib.util.spec_from_file_location("custom_date_extractors", module_path)
        mod = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(mod)
        if hasattr(mod, 'EXTRACTORS') and isinstance(mod.EXTRACTORS, dict):
            _custom_extractors.update(mod.EXTRACTORS)
            if VRB:
                print(f"  Loaded {len(mod.EXTRACTORS)} custom date extractor(s) from {module_path}")
        else:
            print(f"WARNING: CUSTOM_DATE_EXTRACTORS module has no EXTRACTORS dict: {module_path}")
    except Exception as e:
        print(f"WARNING: Failed to load CUSTOM_DATE_EXTRACTORS: {e}")


# Built-in extractors registry
_BUILTIN_EXTRACTORS = {
    'TVOON': None,  # filled after function definitions below
    'ISO': None,
}

def extract_episode_date(filename, format_type='auto'):
    """Extract air date from a video filename.

    Args:
        filename: basename of the video file
        format_type: 'auto' (try all), 'TVOON', 'ISO', or any custom format name

    Returns: datetime.date or None

    Custom extractors can be added via the CUSTOM_DATE_EXTRACTORS config variable,
    pointing to a Python module with: EXTRACTORS = {'format_name': extract_function, ...}
    Each extract_function takes a filename string and returns datetime.date or None.
    """
    _load_custom_date_extractors()

    # Build combined extractors dict (builtins + custom, custom can override builtins)
    all_extractors = dict(_BUILTIN_EXTRACTORS)
    all_extractors.update(_custom_extractors)

    if format_type == 'auto':
        # Try all known formats: builtins first, then custom
        for name, func in all_extractors.items():
            if func:
                result = func(filename)
                if result:
                    return result
        return None

    # Specific format requested
    func = all_extractors.get(format_type)
    if func:
        return func(filename)

    print(f"WARNING: Unknown date extractor format: '{format_type}'")
    return None


def _extract_date_TVOON(filename):
    """Extract date from TVOON-style filename: Show_Name_YY.MM.DD_HH-MM_channel_..."""
    import re
    from datetime import date
    m = re.search(r'(\d{2})\.(\d{2})\.(\d{2})_\d{2}-\d{2}_', filename)
    if not m:
        return None
    yy, mm, dd = int(m.group(1)), int(m.group(2)), int(m.group(3))
    year = 2000 + yy if yy < 50 else 1900 + yy
    try:
        return date(year, mm, dd)
    except ValueError:
        return None


def _extract_date_ISO(filename):
    """Extract date from YYYY-MM-DD pattern in filename."""
    import re
    from datetime import date
    m = re.search(r'(\d{4})-(\d{2})-(\d{2})', filename)
    if not m:
        return None
    try:
        return date(int(m.group(1)), int(m.group(2)), int(m.group(3)))
    except ValueError:
        return None

# Register built-in extractors
_BUILTIN_EXTRACTORS['TVOON'] = _extract_date_TVOON
_BUILTIN_EXTRACTORS['ISO'] = _extract_date_ISO


# ---------------------------------------------------------------------------
# Special episode detection
# ---------------------------------------------------------------------------

import re as _re
_DEFAULT_SPECIALS_PATTERN = _re.compile(
    r'(promi|faschings|spezial|weihnachts|sportler|jubil|xxl|quizmarathon|marathon|special)',
    _re.IGNORECASE
)

def is_special_episode(filename, specials_pattern=None):
    """Check if filename matches special episode patterns.

    Args:
        filename: basename of the video file
        specials_pattern: regex string from TSV metadata, or None for default

    Returns: True if special
    """
    if specials_pattern:
        return bool(_re.search(specials_pattern, filename, _re.IGNORECASE))
    return bool(_DEFAULT_SPECIALS_PATTERN.search(filename))


# ---------------------------------------------------------------------------
# Episode scraper interface
# ---------------------------------------------------------------------------

def scrape_episodes(show_title, show_dir, source=None, force=False, external_ids=None, library_name=None, year=None):
    """Main scraper dispatcher. Updates episodes.tsv for a show.

    1. Read existing episodes.tsv for metadata (slug, show_id, source)
    2. If no slug: try to discover it
    3. Dispatch to source-specific scraper
    4. Write updated episodes.tsv

    Args:
        show_title: Plex show title
        show_dir: local directory containing the show
        source: scraper source name ('tvdb', 'tmdb', 'fernsehserien.de')
        force: force update even if TSV is fresh
        external_ids: dict with external IDs from cache, e.g. {'tvdb': '79168', 'tmdb': '1668', 'imdb': 'tt0108778'}
        library_name: Plex library name (for log prefix)

    Returns: (metadata, episodes) or (None, None) on failure
    """
    import os

    tsv_path = get_episodes_tsv_path(show_dir)

    # Read existing TSV
    metadata, existing_episodes = read_episodes_tsv(tsv_path)
    if metadata is None:
        metadata = {}
        existing_episodes = []

    # Check if update needed
    if not force and not is_episodes_tsv_stale(tsv_path):
        return metadata, existing_episodes

    # The passed-in source parameter takes priority (it's the current auto-detected or CLI choice).
    # Only fall back to TSV metadata source if no source was passed in.
    if not source:
        source = metadata.get('source', 'fernsehserien.de')

    match source:
        case 'fernsehserien.de':
            result = _scrape_fernsehserien_de(show_title, metadata, existing_episodes, year=year)
        case 'tvdb':
            result = _scrape_tvdb(show_title, metadata, existing_episodes, external_ids)
        case 'tmdb':
            result = _scrape_tmdb(show_title, metadata, existing_episodes, external_ids)
        case _:
            if VRB: print(f"  WARNING: Unknown scraper source '{source}' for '{show_title}'")
            return metadata, existing_episodes

    # Fallback chain: if primary source failed or returned 0 episodes, try alternatives
    original_source = source
    result_empty = result is not None and isinstance(result, tuple) and not result[1]
    if (result is None or result_empty) and external_ids:
        fallback_sources = []
        if source != 'tmdb' and external_ids.get('tmdb'):
            fallback_sources.append('tmdb')
        if source != 'tvdb' and external_ids.get('tvdb'):
            fallback_sources.append('tvdb')
        # fernsehserien.de has no ID-based lookup, so not a useful fallback

        for fb_source in fallback_sources:
            if VRB: print(f"    Fallback: trying {fb_source} for '{show_title}'...")
            match fb_source:
                case 'tvdb':
                    result = _scrape_tvdb(show_title, metadata, existing_episodes, external_ids)
                case 'tmdb':
                    result = _scrape_tmdb(show_title, metadata, existing_episodes, external_ids)
            if result is not None and (not isinstance(result, tuple) or result[1]):
                source = fb_source
                metadata['_fallback_from'] = original_source  # record original source that failed
                break

    if result is None:
        return metadata, existing_episodes

    new_metadata, new_episodes = result

    # Preserve old 'updated' date for backup filename
    metadata['_prev_updated'] = metadata.get('updated', '')

    # Merge metadata
    metadata.update(new_metadata)
    metadata['source'] = source

    # Write updated TSV
    write_episodes_tsv(tsv_path, metadata, new_episodes)

    return metadata, new_episodes


def _tvdb_login(api_key):
    """Authenticate with TVDB v4 API and return bearer token.

    Token is cached for reuse (valid ~1 month).
    Returns: token string, or None on failure.
    """
    import urllib.request, json

    if not api_key:
        return None

    # Cache token on module level
    if hasattr(_tvdb_login, '_cached_token') and _tvdb_login._cached_token:
        return _tvdb_login._cached_token

    url = 'https://api4.thetvdb.com/v4/login'
    payload = json.dumps({'apikey': api_key}).encode('utf-8')
    req = urllib.request.Request(url, data=payload, headers={'Content-Type': 'application/json'})

    try:
        with urllib.request.urlopen(req, timeout=30) as resp:
            data = json.loads(resp.read().decode('utf-8'))
            token = data.get('data', {}).get('token')
            if token:
                _tvdb_login._cached_token = token
                return token
            err(1100, "TVDB login succeeded but no token in response.\n"
                "  Possible reasons:\n"
                "  - TVDB API changed their response format\n"
                "  - Temporary server issue — try again later")
    except Exception as e:
        err(1101, f"TVDB login failed: {e}\n"
            "  Possible reasons:\n"
            "  - TVDB_API_KEY is invalid or expired\n"
            "  - Network issue connecting to thetvdb.com\n"
            "  Fix: Check/renew at https://thetvdb.com/dashboard → API Keys\n"
            "  Then update TVDB_API_KEY in ~/.my-plex.conf")

    return None


def _scrape_tvdb(show_title, metadata, existing_episodes, external_ids=None):
    """Scrape TVDB v4 API for episode data.

    Uses the TVDB v4 API (https://api4.thetvdb.com/v4) with bearer token auth.
    Endpoint: /series/{id}/episodes/default?page=0

    Args:
        show_title: Plex show title
        metadata: existing TSV metadata dict
        existing_episodes: existing episode list from TSV
        external_ids: dict with 'tvdb' key for TVDB series ID

    Returns: (metadata_updates, episodes_list) or None on failure
    """
    import urllib.request, json

    global TVDB_API_KEY

    if not TVDB_API_KEY:
        print()
        print("  ╔══════════════════════════════════════════════════════════════════╗")
        print("  ║  TVDB API key required (free, one-time setup, takes 2 minutes)  ║")
        print("  ╚══════════════════════════════════════════════════════════════════╝")
        print()
        print("  Step 1: Go to https://thetvdb.com/dashboard")
        print("          (Create a free account if you don't have one)")
        print()
        print("  Step 2: In your dashboard, go to 'API Keys' tab under your project")
        print("          (or create a project first: any name will do)")
        print()
        print("  Step 3: Copy the API key and add it to your config file:")
        print()
        print("          echo \"TVDB_API_KEY = 'paste-your-key-here'\" >> ~/.my-plex.conf")
        print()
        print("  Step 4: Re-run this command. Done!")
        print()
        print("  Alternative: use --source tmdb or --source fernsehserien.de instead.")
        print()
        return None

    # Get TVDB series ID from external_ids or metadata
    tvdb_id = None
    if external_ids and 'tvdb' in external_ids:
        tvdb_id = external_ids['tvdb']
    elif metadata.get('tvdb_id'):
        tvdb_id = metadata['tvdb_id']

    if not tvdb_id:
        if VRB:
            print(f"  WARNING: No TVDB ID found for '{show_title}' — cannot scrape TVDB")
            print(f"  Possible reasons: show not matched in Plex, or missing external ID in Plex DB")
        return None

    # Authenticate
    token = _tvdb_login(TVDB_API_KEY)
    if not token:
        return None

    # Fetch all episodes (paginated)
    all_episodes = []
    page = 0
    while True:
        url = f'https://api4.thetvdb.com/v4/series/{tvdb_id}/episodes/default?page={page}'
        req = urllib.request.Request(url, headers={'Authorization': f'Bearer {token}'})

        try:
            with urllib.request.urlopen(req, timeout=30) as resp:
                data = json.loads(resp.read().decode('utf-8'))
        except Exception as e:
            if VRB: print(f"  WARNING: TVDB API request failed (page {page}): {e}")
            if page == 0:
                return None  # First page failed — fatal
            break  # Subsequent pages — use what we have

        episodes_data = data.get('data', {}).get('episodes', [])
        if not episodes_data:
            break

        # Capture series name from first page response
        if page == 0:
            series_info = data.get('data', {}).get('series', {})
            if series_info and isinstance(series_info, dict):
                _scrape_tvdb._series_name = series_info.get('name', '')
            else:
                _scrape_tvdb._series_name = ''

        for ep in episodes_data:
            season_num = ep.get('seasonNumber')
            ep_num = ep.get('number')
            if season_num is None or ep_num is None:
                continue
            # Skip specials (season 0) by default — they have irregular numbering
            if season_num == 0:
                continue
            all_episodes.append({
                'season': int(season_num),
                'episode': int(ep_num),
                'date': ep.get('aired', '') or '',
                'title': ep.get('name', '') or '',
                'original_title': '',
                'date_local': '',
                'sender_local': '',
                'date_original': ep.get('aired', '') or '',
                'sender_original': '',
            })

        # Check if more pages
        # TVDB v4 returns empty episodes array when past last page
        page += 1

    if not all_episodes:
        if VRB: print(f"  WARNING: TVDB returned 0 episodes for '{show_title}' (tvdb:{tvdb_id})")
        return None

    new_metadata = {'tvdb_id': str(tvdb_id)}
    # Store the show title as reported by TVDB (may differ from Plex title)
    if hasattr(_scrape_tvdb, '_series_name') and _scrape_tvdb._series_name:
        new_metadata['show_title'] = _scrape_tvdb._series_name
    max_s = max(ep['season'] for ep in all_episodes)
    if max_s:
        new_metadata['latest_season'] = str(max_s)

    w_prefix = _get_worker_prefix()
    print(f"  {w_prefix}>> TVDB: {len(all_episodes)} episodes in {max_s} seasons for '{show_title}'")

    return new_metadata, all_episodes


def _scrape_tmdb(show_title, metadata, existing_episodes, external_ids=None):
    """Scrape TMDB API v3 for episode data.

    Uses TMDB API v3:
    1. GET /tv/{series_id} → get number_of_seasons
    2. GET /tv/{series_id}/season/{n} → get episodes per season

    Args:
        show_title: Plex show title
        metadata: existing TSV metadata dict
        existing_episodes: existing episode list from TSV
        external_ids: dict with 'tmdb' key for TMDB series ID

    Returns: (metadata_updates, episodes_list) or None on failure
    """
    import urllib.request, json

    global TMDB_API_KEY

    if not TMDB_API_KEY:
        print()
        print("  ╔══════════════════════════════════════════════════════════════════╗")
        print("  ║  TMDB API key required (free, one-time setup, takes 2 minutes)  ║")
        print("  ╚══════════════════════════════════════════════════════════════════╝")
        print()
        print("  Step 1: Go to https://www.themoviedb.org/signup")
        print("          (Create a free account if you don't have one)")
        print()
        print("  Step 2: Go to https://www.themoviedb.org/settings/api")
        print("          Click 'Request an API Key' → choose 'Developer'")
        print("          Fill in any name/URL (personal use is fine)")
        print()
        print("  Step 3: Copy the 'API Read Access Token' (the long string,")
        print("          NOT the short 'API Key') and add to your config file:")
        print()
        print("          echo \"TMDB_API_KEY = 'paste-your-token-here'\" >> ~/.my-plex.conf")
        print()
        print("  Step 4: Re-run this command. Done!")
        print()
        print("  Alternative: use --source tvdb or --source fernsehserien.de instead.")
        print()
        return None

    # Get TMDB series ID from external_ids or metadata
    tmdb_id = None
    if external_ids and 'tmdb' in external_ids:
        tmdb_id = external_ids['tmdb']
    elif metadata.get('tmdb_id'):
        tmdb_id = metadata['tmdb_id']

    if not tmdb_id:
        if VRB:
            print(f"  WARNING: No TMDB ID found for '{show_title}' — cannot scrape TMDB")
            print(f"  Possible reasons: show not matched in Plex, or missing external ID in Plex DB")
        return None

    headers = {
        'Authorization': f'Bearer {TMDB_API_KEY}',
        'Accept': 'application/json'
    }

    # Step 1: Get series details to find number of seasons
    url = f'https://api.themoviedb.org/3/tv/{tmdb_id}'
    req = urllib.request.Request(url, headers=headers)

    try:
        with urllib.request.urlopen(req, timeout=30) as resp:
            series_data = json.loads(resp.read().decode('utf-8'))
    except urllib.error.HTTPError as e:
        if e.code == 401:
            err(1102, f"TMDB authentication failed for '{show_title}' (tmdb:{tmdb_id}).\n"
                "  Possible reasons:\n"
                "  - TMDB_API_KEY is invalid or expired\n"
                "  - TMDB_API_KEY should be the 'API Read Access Token' (long string), not the short 'API Key'\n"
                "  Fix: Update TMDB_API_KEY in ~/.my-plex.conf")
        elif VRB:
            print(f"  WARNING: TMDB series request failed for '{show_title}' (tmdb:{tmdb_id}): {e}")
        return None
    except Exception as e:
        if VRB: print(f"  WARNING: TMDB series request failed for '{show_title}' (tmdb:{tmdb_id}): {e}")
        return None

    num_seasons = series_data.get('number_of_seasons', 0)
    if not num_seasons:
        # Try counting from seasons array
        seasons_list = series_data.get('seasons', [])
        num_seasons = max((s.get('season_number', 0) for s in seasons_list), default=0)

    if not num_seasons:
        if VRB: print(f"  WARNING: TMDB reports 0 seasons for '{show_title}' (tmdb:{tmdb_id})")
        return None

    # Step 2: Fetch episodes for each season
    all_episodes = []
    for season_num in range(1, num_seasons + 1):
        url = f'https://api.themoviedb.org/3/tv/{tmdb_id}/season/{season_num}'
        req = urllib.request.Request(url, headers=headers)

        try:
            with urllib.request.urlopen(req, timeout=30) as resp:
                season_data = json.loads(resp.read().decode('utf-8'))
        except Exception as e:
            if VRB: print(f"  WARNING: TMDB season {season_num} request failed: {e}")
            continue

        for ep in season_data.get('episodes', []):
            ep_num = ep.get('episode_number')
            if ep_num is None:
                continue
            all_episodes.append({
                'season': int(season_num),
                'episode': int(ep_num),
                'date': ep.get('air_date', '') or '',
                'title': ep.get('name', '') or '',
                'original_title': '',
                'date_local': '',
                'sender_local': '',
                'date_original': ep.get('air_date', '') or '',
                'sender_original': '',
            })

    if not all_episodes:
        if VRB: print(f"  WARNING: TMDB returned 0 episodes for '{show_title}' (tmdb:{tmdb_id})")
        return None

    new_metadata = {'tmdb_id': str(tmdb_id)}
    # Store the show title as reported by TMDB (may differ from Plex title)
    tmdb_name = series_data.get('name', '')
    if tmdb_name:
        new_metadata['show_title'] = tmdb_name
    max_s = max(ep['season'] for ep in all_episodes)
    if max_s:
        new_metadata['latest_season'] = str(max_s)

    w_prefix = _get_worker_prefix()
    print(f"  {w_prefix}>> TMDB: {len(all_episodes)} episodes in {max_s} seasons for '{show_title}'")

    return new_metadata, all_episodes


def _discover_fernsehserien_slug(show_title, year=None):
    """Search fernsehserien.de for the show's slug and ID.

    Strategy:
    1. Try direct URL from title-to-slug heuristic (with and without year suffix)
    2. Fall back to search page

    Returns: (slug, show_id) or (None, None)
    """
    import urllib.request, urllib.parse, re

    def _try_slug(slug_candidate):
        """Try a slug and return (slug, show_id, has_episodenguide) or None."""
        url = f"https://www.fernsehserien.de/{slug_candidate}"
        req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
        try:
            resp = urllib.request.urlopen(req, timeout=10)
            html = resp.read().decode("utf-8")
            if '/episodenguide' in html or '/sendetermine' in html:
                m = re.search(r'/episodenguide/staffel-\d+/(\d+)', html)
                show_id = m.group(1) if m else None
                has_epguide = '/episodenguide' in html
                return (slug_candidate, show_id, has_epguide)
        except Exception:
            pass
        return None

    # Heuristic: title → slug  (e.g. "Wer weiß denn sowas?" → "wer-weiss-denn-sowas")
    slug_guess = show_title.lower()
    # German umlauts
    for old, new in [('ä', 'ae'), ('ö', 'oe'), ('ü', 'ue'), ('ß', 'ss'),
                     ('é', 'e'), ('è', 'e'), ('ê', 'e'), ('à', 'a'), ('ô', 'o'),
                     ('î', 'i'), ('ç', 'c'), ('ï', 'i'), ('â', 'a'), ('û', 'u')]:
        slug_guess = slug_guess.replace(old, new)
    # Remove punctuation, collapse whitespace to hyphens
    slug_guess = re.sub(r'[^a-z0-9\s-]', '', slug_guess)
    slug_guess = re.sub(r'[\s]+', '-', slug_guess).strip('-')

    # Build candidate list: base slug first, then with year suffix
    candidates = [slug_guess]
    if year and year > 0:
        slug_with_year = f"{slug_guess}-{year}"
        candidates.append(slug_with_year)

    # Try each candidate; prefer one with episodenguide (structured data)
    best = None
    for candidate in candidates:
        result = _try_slug(candidate)
        if result:
            slug, show_id, has_epguide = result
            if has_epguide:
                return slug, show_id  # best possible match
            if not best:
                best = (slug, show_id)  # remember sendetermine-only match as fallback

    if best:
        return best

    # Fall back to search
    search_url = f"https://www.fernsehserien.de/suche?q={urllib.parse.quote(show_title)}"
    req = urllib.request.Request(search_url, headers={"User-Agent": "Mozilla/5.0"})
    try:
        html = urllib.request.urlopen(req, timeout=10).read().decode("utf-8")
        # Look for first result link
        matches = re.findall(r'<a href="/([^"/]+)"[^>]*class="[^"]*"[^>]*>.*?</a>', html, re.DOTALL)
        if matches:
            slug = matches[0]
            # Verify it's a show page by checking for episodenguide
            verify_url = f"https://www.fernsehserien.de/{slug}"
            req2 = urllib.request.Request(verify_url, headers={"User-Agent": "Mozilla/5.0"})
            try:
                html2 = urllib.request.urlopen(req2, timeout=10).read().decode("utf-8")
                if '/episodenguide' in html2 or '/sendetermine' in html2:
                    m = re.search(r'/episodenguide/staffel-\d+/(\d+)', html2)
                    show_id = m.group(1) if m else None
                    return slug, show_id
            except Exception:
                pass
    except Exception:
        pass

    return None, None


def _scrape_fernsehserien_de(show_title, metadata, existing_episodes, year=None):
    """Scrape fernsehserien.de for episode data.

    Uses two strategies:
    1. episodenguide/staffel-N pages (structured, per-season, needs show_id)
    2. sendetermine pages (broadcast dates with episode links, works without show_id)

    Returns: (metadata_updates, episodes_list) or None on failure
    """
    import urllib.request, re, time

    slug = metadata.get('slug')
    show_id = metadata.get('show_id')

    # Discover slug if not known
    if not slug:
        if VRB: print(f"  Discovering fernsehserien.de slug for '{show_title}'...")
        slug, show_id = _discover_fernsehserien_slug(show_title, year=year)
        if not slug:
            if VRB: print(f"  WARNING: Could not find '{show_title}' on fernsehserien.de")
            return None

    new_metadata = {'slug': slug}
    if show_id:
        new_metadata['show_id'] = show_id

    # Build existing episodes lookup: (season, episode) -> {'date': ..., 'title': ...}
    existing_by_key = {}
    for ep in existing_episodes:
        key = (ep['season'], ep['episode'])
        existing_by_key[key] = ep

    new_count = 0

    if show_id:
        # Strategy 1: episodenguide/staffel-N (structured data)
        # Split HTML by itemprop="episode" sections — each section contains all data
        # for one episode, avoiding cross-episode regex mismatches.
        # Start from season 1 (or last known - 1 for updates) and keep going until
        # two consecutive empty pages (some shows skip season numbers).
        max_existing = max((ep['season'] for ep in existing_episodes), default=0)
        start_season = max(0, max_existing - 1) if existing_episodes else 0
        consecutive_empty = 0

        s = start_season
        while consecutive_empty < 2:
            # Paginate within each season: page 1 = no suffix, page 2+ = /2, /3, ...
            season_had_episodes = False
            page = 1
            while True:
                if page == 1:
                    url = f"https://www.fernsehserien.de/{slug}/episodenguide/staffel-{s}/{show_id}"
                else:
                    url = f"https://www.fernsehserien.de/{slug}/episodenguide/{s}/{show_id}/{page}"
                req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
                try:
                    html = urllib.request.urlopen(req, timeout=10).read().decode("utf-8")
                except Exception:
                    break  # no more pages for this season

                # Extract show title from first page (from <title> tag: "Show Name – Episodenguide ...")
                if 'show_title' not in new_metadata:
                    m_page_title = re.search(r'<title>([^–<]+)', html)
                    if m_page_title:
                        new_metadata['show_title'] = m_page_title.group(1).strip()

                # Split by episode sections — first split chunk is before any episode
                ep_sections = re.split(r'itemprop="episode"', html)[1:]
                if not ep_sections:
                    break  # empty page, no more episodes for this season

                season_had_episodes = True

                for section in ep_sections:
                    m_num = re.search(r'itemprop="episodeNumber" content="(\d+)"', section)
                    if not m_num:
                        continue
                    ep_num = int(m_num.group(1))
                    key = (s, ep_num)

                    # German title (itemprop="name")
                    m_title = re.search(r'itemprop="name">([^<]*)<', section)
                    title = m_title.group(1).strip() if m_title else ''

                    # Original title (in parentheses after originaltitel class)
                    m_orig = re.search(r'episode-output-originaltitel[^>]*>\(([^)]+)\)', section)
                    original_title = m_orig.group(1).strip() if m_orig else ''

                    # Air dates: <ea-angabe data-sort="0-YYYY-MM-DD">...<ea-angabe-sender>SENDER
                    # sort prefix 0 = local (German), 1 = original
                    dates = re.findall(
                        r'<ea-angabe data-sort="(\d+)-(\d{4}-\d{2}-\d{2})">'
                        r'<ea-angabe-titel>[^<]*</ea-angabe-titel>\s*'
                        r'<ea-angabe-datum>[^<]*</ea-angabe-datum>\s*'
                        r'<ea-angabe-sender>([^<]*)</ea-angabe-sender>',
                        section
                    )
                    date_local = ''
                    date_original = ''
                    sender_local = ''
                    sender_original = ''
                    for sort_idx, date_val, sender in dates:
                        if sort_idx == '0':     # local (German) premiere
                            if not date_local or date_val < date_local:
                                date_local = date_val
                                sender_local = sender.strip()
                        elif sort_idx == '1':   # original premiere
                            if not date_original or date_val < date_original:
                                date_original = date_val
                                sender_original = sender.strip()

                    # Use earliest date available (prefer local, fall back to original)
                    date = date_local or date_original

                    ep_data = {
                        'season': s, 'episode': ep_num, 'date': date, 'title': title,
                        'original_title': original_title,
                        'date_local': date_local, 'sender_local': sender_local,
                        'date_original': date_original, 'sender_original': sender_original,
                    }
                    if key not in existing_by_key or date < existing_by_key[key].get('date', 'Z'):
                        existing_by_key[key] = ep_data
                        new_count += 1
                    else:
                        # Update fields that may be missing in existing data
                        existing = existing_by_key[key]
                        for field in ('original_title', 'date_local', 'sender_local', 'date_original', 'sender_original'):
                            if not existing.get(field) and ep_data.get(field):
                                existing[field] = ep_data[field]
                        if not existing.get('title') and title:
                            existing['title'] = title

                # Check for next page link (site uses both formats)
                next_page_url_a = f"/{slug}/episodenguide/staffel-{s}/{show_id}/{page + 1}"
                next_page_url_b = f"/{slug}/episodenguide/{s}/{show_id}/{page + 1}"
                if next_page_url_a in html or next_page_url_b in html:
                    page += 1
                    time.sleep(0.3)
                else:
                    break  # no next page

            if season_had_episodes:
                consecutive_empty = 0
            else:
                consecutive_empty += 1
            s += 1
            time.sleep(0.3)

    if not show_id or not existing_by_key:
        # Strategy 2: sendetermine pages (broadcast schedule)
        # Also used as fallback when Strategy 1 returned 0 episodes (e.g. 404 on staffel URLs)
        for offset in [0, -1, -2, -3]:
            url = f"https://www.fernsehserien.de/{slug}/sendetermine/{offset}"
            req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
            try:
                html = urllib.request.urlopen(req, timeout=10).read().decode("utf-8")
            except Exception as e:
                print(f"  fetch offset {offset} failed: {e}")
                break

            # Extract show title from first page
            if 'show_title' not in new_metadata:
                m_page_title = re.search(r'<title>([^–<]+)', html)
                if m_page_title:
                    new_metadata['show_title'] = m_page_title.group(1).strip()

            pairs = re.findall(
                r'role=rowgroup\s+href="/' + re.escape(slug) + r'/folgen/(\d+)-([^"]*)".*?datetime="(\d{4}-\d{2}-\d{2})T',
                html, re.DOTALL
            )

            for ep_str, title_slug, date in pairs:
                ep = int(ep_str)
                title = title_slug.split('-')[:-1]  # remove trailing ID
                title = ' '.join(title).strip()
                # For sendetermine-based shows, episode is global; season needs derivation
                # We'll store season=0 here and derive later
                key = (0, ep)
                if key not in existing_by_key or date < existing_by_key[key].get('date', 'Z'):
                    existing_by_key[key] = {'season': 0, 'episode': ep, 'date': date, 'title': title}
                    new_count += 1

            time.sleep(0.3)

        # Try to get season info from episodenguide main page
        url = f"https://www.fernsehserien.de/{slug}/episodenguide"
        req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
        try:
            html = urllib.request.urlopen(req, timeout=10).read().decode("utf-8")
            title_pairs = re.findall(
                r'href="/' + re.escape(slug) + r'/folgen/(\d+)-[^"]*"\s*title="(\d+)\.(\d+)',
                html
            )
            for global_ep, season, season_ep in title_pairs:
                ep = int(global_ep)
                key = (0, ep)
                if key in existing_by_key:
                    if existing_by_key[key]['season'] == 0:
                        existing_by_key[key]['season'] = int(season)
        except Exception:
            pass

        # Derive missing seasons from known season start dates
        _derive_missing_seasons(existing_by_key)

    episodes = list(existing_by_key.values())

    # If 0 episodes and slug came from TSV metadata (not freshly discovered),
    # re-discover with year suffix — the cached slug may point to the wrong show
    if not episodes and metadata.get('slug'):
        if VRB: print(f"  0 episodes with cached slug '{slug}' — re-discovering with year...")
        new_slug, new_show_id = _discover_fernsehserien_slug(show_title, year=year)
        if new_slug and new_slug != slug:
            if VRB: print(f"  Re-discovered slug: {new_slug} (was: {slug})")
            return _scrape_fernsehserien_de(show_title, {'slug': new_slug, 'show_id': new_show_id}, existing_episodes, year=year)

    # Detect latest season
    max_s = max((ep['season'] for ep in episodes if ep['season'] > 0), default=0)
    if max_s:
        new_metadata['latest_season'] = str(max_s)

    w_prefix = _get_worker_prefix()
    print(f"  {w_prefix}>> fernsehserien.de: {len(episodes)} episodes in {max_s} seasons for '{show_title}'")

    return new_metadata, episodes


def _derive_missing_seasons(episodes_by_key):
    """For shows using sendetermine (global episode numbers), derive season from known season assignments.
    Modifies episodes_by_key in place."""
    # Collect known season start dates
    season_starts = {}  # season_num -> earliest date
    for key, ep in episodes_by_key.items():
        s = ep['season']
        if s > 0:
            d = ep['date']
            if s not in season_starts or d < season_starts[s]:
                season_starts[s] = d

    if not season_starts:
        return

    def get_season(date):
        best = 0
        for s in sorted(season_starts):
            if date >= season_starts[s]:
                best = s
        return best

    for key, ep in episodes_by_key.items():
        if ep['season'] == 0 and ep['date']:
            derived = get_season(ep['date'])
            if derived > 0:
                ep['season'] = derived


