def _determine_episode_source(show_dict, source_override=None):
    """Determine the episode data source for a show.

    Priority:
    1. CLI override (--source tvdb|tmdb|fernsehserien.de)
    2. Config file: MISSING_EPISODES_SOURCE per library
    3. Auto-detect from library agent + language in cache

    Auto-detection logic:
    - German libraries (language starts with 'de') → fernsehserien.de
    - Otherwise: match the Plex agent (TMDB-based agent → tmdb, TVDB agent → tvdb)
    - Fallback: whichever API key is configured

    Returns: source name string ('tvdb', 'tmdb', 'fernsehserien.de')
    """
    global MISSING_EPISODES_SOURCE, TVDB_API_KEY, TMDB_API_KEY

    # 1. CLI override
    if source_override:
        return source_override

    library_name = show_dict.get('library', '')

    # 2. Config file per-library override
    if MISSING_EPISODES_SOURCE and library_name in MISSING_EPISODES_SOURCE:
        return MISSING_EPISODES_SOURCE[library_name]

    # 3. Auto-detect from cached library stats
    lib_language = CACHE.get('library_stats', {}).get('language', {}).get(library_name, '')

    if lib_language.startswith('de'):
        return 'fernsehserien.de'

    # 4. Match the Plex-configured agent
    lib_agent = CACHE.get('library_stats', {}).get('agent', {}).get(library_name, '')
    if lib_agent:
        # TMDB-based agents: tv.plex.agents.series, tv.plex.agents.movie, com.plexapp.agents.themoviedb
        if lib_agent in ('tv.plex.agents.series', 'tv.plex.agents.movie', 'com.plexapp.agents.themoviedb'):
            if TMDB_API_KEY:
                return 'tmdb'
        # TVDB-based agent
        elif lib_agent == 'com.plexapp.agents.thetvdb':
            if TVDB_API_KEY:
                return 'tvdb'

    # 5. Fallback: whichever API key is configured
    if TVDB_API_KEY:
        return 'tvdb'
    if TMDB_API_KEY:
        return 'tmdb'

    # No API keys configured — fall through to tmdb which will show setup instructions
    return 'tmdb'


def cmd_missing(show_ref, source_override=None):
    """Show missing episodes for a series.
    Compares episodes.tsv (all aired episodes) against Plex cache (episodes on disk).
    """
    import os
    from datetime import datetime

    show_key, show_dict = resolve_show_for_episodes(show_ref)
    show_title = show_dict.get('title', '?')
    show_dir_server = show_dict.get('file', '')

    if not show_dir_server:
        err(1088, f"Show '{show_title}' ({show_key}) has no directory path in cache.\n"
            "  Run my-plex --update-cache to refresh.")

    show_dir = get_local_path(show_dir_server)

    # Determine episode source for this show
    source = _determine_episode_source(show_dict, source_override)
    external_ids = show_dict.get('external_ids', {})

    print(f" >>> MISSING EPISODES: {show_title}")
    print(f"  >> Show:      {show_key} — {show_title}")
    print(f"  >> Directory: {show_dir_server}")
    print(f"  >> Source:    {source}" + (f" (tvdb:{external_ids.get('tvdb', '?')}, tmdb:{external_ids.get('tmdb', '?')})" if source in ('tvdb', 'tmdb') else ''))

    # Load or update episodes.tsv
    tsv_path = get_episodes_tsv_path(show_dir)

    existing_meta, _ = read_episodes_tsv(tsv_path)
    if existing_meta is not None:
        old_source = existing_meta.get('source', '')
        if old_source and old_source != source:
            print(f"  >> Re-scraping: source changed ({old_source} → {source})...")
            metadata, all_episodes = scrape_episodes(show_title, show_dir, source=source, force=True, external_ids=external_ids)
        elif is_episodes_tsv_stale(tsv_path):
            print(f"  >> Updating episodes.tsv (stale)...")
            metadata, all_episodes = scrape_episodes(show_title, show_dir, source=source, external_ids=external_ids)
        else:
            metadata, all_episodes = read_episodes_tsv(tsv_path)
    else:
        print(f"  >> No episodes.tsv found — scraping {source}...")
        metadata, all_episodes = scrape_episodes(show_title, show_dir, source=source, force=True, external_ids=external_ids)

    if not all_episodes:
        print(f"  >> No episode data available for '{show_title}'.")
        if source == 'tvdb':
            print(f"  >> Check TVDB_API_KEY in ~/.my-plex.conf and TVDB ID: {external_ids.get('tvdb', 'not found')}")
        elif source == 'tmdb':
            print(f"  >> Check TMDB_API_KEY in ~/.my-plex.conf and TMDB ID: {external_ids.get('tmdb', 'not found')}")
        else:
            print(f"  >> Create {tsv_path} or ensure the show exists on {source}.")
        return

    print(f"  >> TSV:       {len(all_episodes)} episodes (source: {metadata.get('source', '?')})")

    # Get cached episodes from OBJ_BY_SHOW_EPISODES
    cached_episodes = PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key, {})

    # Build set of (season, episode) tuples we HAVE
    # Plex stores episode.index as-is from the metadata agent / filename scanner (per plexapi
    # source: Episode.index is the episode number within the season).  Some shows use "absolute"
    # numbering in filenames (e.g. "Boston Legal 101" → Plex stores index=101 for S01E01).
    # Detect per-season: if ALL episodes in a season have index // 100 == season_num, normalise.
    have_set = set()
    for s_str, eps in cached_episodes.items():
        try:
            s_num = int(s_str[1:])
        except (ValueError, IndexError):
            continue
        e_nums = []
        for e_str in eps:
            try:
                e_nums.append(int(e_str[1:]))
            except (ValueError, IndexError):
                continue
        # Detect absolute numbering: ALL episodes in this season have index // 100 == season_num
        uses_absolute = (s_num > 0 and e_nums
                         and all(e >= 100 and e // 100 == s_num for e in e_nums))
        for e_num in e_nums:
            if uses_absolute:
                e_num = e_num % 100
            have_set.add((s_num, e_num))

    print(f"  >> Cache:     {len(have_set)} episodes on disk")

    # Build set of (season, episode) from TSV
    tsv_set = {}  # (season, episode) -> {'date': ..., 'title': ...}
    for ep in all_episodes:
        key = (ep['season'], ep['episode'])
        tsv_set[key] = ep

    # Find missing: in TSV but not in cache
    missing = []
    for key, ep in sorted(tsv_set.items()):
        if key not in have_set:
            missing.append(ep)

    # Also count episodes we have but aren't in TSV (extras)
    extras = have_set - set(tsv_set.keys())

    # Group missing by season to detect fully missing seasons
    from collections import defaultdict
    missing_by_season = defaultdict(list)
    tsv_by_season = defaultdict(int)
    for ep in all_episodes:
        tsv_by_season[ep['season']] += 1
    for ep in missing:
        missing_by_season[ep['season']].append(ep)

    today = datetime.now().strftime('%Y-%m-%d')

    # Filter out future-only seasons/episodes to get real missing count
    missing_lines = []
    for season in sorted(missing_by_season):
        season_missing = missing_by_season[season]
        season_total = tsv_by_season[season]
        if len(season_missing) == season_total:
            first_date = min(ep['date'] for ep in season_missing)
            if first_date > today:
                continue
            missing_lines.append(f"  S{season:02d}        {first_date}  (entire season — {season_total} episodes)")
        else:
            for ep in sorted(season_missing, key=lambda e: e['episode']):
                if ep['date'] > today:
                    continue
                title_str = f"  {ep['title']}" if ep.get('title') else ""
                missing_lines.append(f"  S{season:02d}E{ep['episode']:02d}    {ep['date']}{title_str}")

    # Build extras lines — map (season, ep) back to Plex episode info
    extras_lines = []
    for (s_num, e_num) in sorted(extras):
        s_str = f"S{s_num:02d}"
        e_str = f"E{e_num:02d}"
        # Look up in cache for filepath/title
        ep_keys = (PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key, {})
                   .get(f"S{s_num:02d}", {}).get(f"E{e_num:02d}", {}).get('default', [])
                   or next(iter((PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key, {})
                                 .get(f"S{s_num:02d}", {}).get(f"E{e_num:02d}", {}) or {}).values()), []))
        title = ''
        for ek in (ep_keys if isinstance(ep_keys, list) else [ep_keys]):
            obj = PLEX_Media.OBJ_BY_ID.get(ek, {})
            if obj.get('title'):
                title = f"  {obj['title']}"
                break
        extras_lines.append(f"  {s_str}{e_str}    {title.strip()}")

    if not missing_lines:
        print(f"  >> No missing episodes! All {len(tsv_set)} TSV episodes are on disk.")
        if extras_lines:
            print(f"  >> Extra on disk, not in TSV: {len(extras_lines)}")
            for line in extras_lines:
                print(f"   > {line.strip()}")
        return

    print(f"  >> Missing: {len(missing_lines)} episode(s)")
    for line in missing_lines:
        print(f"   > {line.strip()}")

    if extras_lines:
        print(f"  >> Extra on disk, not in TSV: {len(extras_lines)}")
        for line in extras_lines:
            print(f"   > {line.strip()}")


# ---------------------------------------------------------------------------
# --plex2disk / --disk2plex commands (aliases: --map-to-filename, --map-from-filename)
# ---------------------------------------------------------------------------

def _get_disk_map_scope(target):
    """Determine which cache entries to process for --map-to-filename / --map-from-filename.

    Args:
        target: None (all), library name (string), or media identifier

    Returns:
        list of (cache_key, obj_dict) tuples
    """
    items = []
    if target is None:
        # All media items with files
        for key, obj in PLEX_Media.OBJ_BY_ID.items():
            if obj.get('file') or obj.get('files'):
                items.append((key, obj))
    elif target in PLEX_Library.OBJ_DICT:
        # Library scope — all items in that library
        lib_types = PLEX_Media.OBJ_BY_LIBRARY.get(target, {})
        for type_str, keys in lib_types.items():
            for key in keys:
                obj = PLEX_Media.OBJ_BY_ID.get(key)
                if obj and (obj.get('file') or obj.get('files')):
                    items.append((key, obj))
    else:
        # Single media item by cache key or title
        obj = PLEX_Media.OBJ_BY_ID.get(target)
        if not obj:
            # Try title search
            target_lower = target.lower()
            for key, o in PLEX_Media.OBJ_BY_ID.items():
                title = o.get('title', '')
                if title and target_lower in title.lower():
                    if o.get('file') or o.get('files'):
                        items.append((key, o))
        elif obj.get('type_str') == 'Show':
            # Expand Show → all episodes + the Show itself (for series dir markers)
            items.append((target, obj))
            show_key = target
            episodes = PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key, {})
            for s_str, eps in episodes.items():
                for e_str, versions in eps.items():
                    for version, ep_keys in versions.items():
                        for ek in ep_keys:
                            ep_obj = PLEX_Media.OBJ_BY_ID.get(ek)
                            if ep_obj and (ep_obj.get('file') or ep_obj.get('files')):
                                items.append((ek, ep_obj))
            # Also add Season objects for season dir markers
            show_seasons = PLEX_Media.OBJ_BY_SHOW.get(show_key, {})
            for s_str, season_key in show_seasons.items():
                s_obj = PLEX_Media.OBJ_BY_ID.get(season_key)
                if s_obj:
                    items.append((season_key, s_obj))
        elif obj.get('type_str') == 'Season':
            # Expand Season → all episodes in this season + the Season itself
            items.append((target, obj))
            show_key = obj.get('show_key', '')
            season_raw = str(obj.get('season', ''))
            # Extract number from "Season 3" or "3" or "S03"
            season_match = re.search(r'(\d+)', season_raw)
            S_str = f"S{int(season_match.group(1)):02d}" if season_match else ''
            episodes = PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key, {}).get(S_str, {})
            for e_str, versions in episodes.items():
                for version, ep_keys in versions.items():
                    for ek in ep_keys:
                        ep_obj = PLEX_Media.OBJ_BY_ID.get(ek)
                        if ep_obj and (ep_obj.get('file') or ep_obj.get('files')):
                            items.append((ek, ep_obj))
        elif obj.get('file') or obj.get('files'):
            items.append((target, obj))
    return items

def _get_all_filepaths(obj):
    """Get all file paths from a cache entry.

    Returns:
        list of filepath strings
    """
    paths = []
    files = obj.get('files')
    if files and isinstance(files, dict):
        for version_str, file_info in files.items():
            if isinstance(file_info, dict):
                fp = file_info.get('filepath', '')
            else:
                fp = file_info
            if fp:
                paths.append(fp)
    elif obj.get('file'):
        paths.append(obj['file'])
    return paths

def _extract_legacy_vu_marker(name):
    """Detect [vu] or [vu@TIMESTAMP] marker in a file/dir name (legacy migration helper).

    Case-insensitive: matches [vu], [VU], [Vu], [vu@2026-03-22], [VU@2026-03-22], etc.

    Args:
        name: Filename or dirname to search for legacy marker

    Returns:
        str or None: The full marker string (e.g. '[vu@2026-03-22]', '[VU]') or None
    """
    match = re.search(r'\[vu(?:@[^\]]+)?\]', name, re.IGNORECASE)
    return match.group(0) if match else None

def _migrate_legacy_vu_sidecar(name, is_dir=False, obj=None):
    """Create synthetic sidecar entry from legacy [vu] marker on a file/dir.

    Args:
        name: Filename or dirname with a legacy [vu...] marker
        is_dir: True if this is a directory name
        obj: Optional Plex cache entry — used to get lastViewedAt for bare [vu] markers

    Returns:
        tuple: (sidecar_entry_or_None, timestamp_source_str)
               timestamp_source is 'plex', 'marker', 'today', or '' (no migration)
    """
    from datetime import datetime as _datetime, date as _date
    vu_marker = _extract_legacy_vu_marker(name)
    if not vu_marker:
        return None, ''
    # For bare [vu]/[VU] without timestamp: prefer Plex lastViewedAt, fallback to today
    if '@' not in vu_marker:
        last_viewed = obj.get('lastViewedAt') if obj else None
        if last_viewed:
            try:
                dt = _datetime.fromtimestamp(last_viewed)
                migrated_marker = f'[vu@{dt.strftime("%Y-%m-%d")}]'
                ts_source = 'plex'
            except (OSError, ValueError):
                migrated_marker = f'[vu@{_date.today().isoformat()}]'
                ts_source = 'today'
        else:
            migrated_marker = f'[vu@{_date.today().isoformat()}]'
            ts_source = 'today'
    else:
        migrated_marker = vu_marker.lower()  # normalize [VU@...] → [vu@...]
        # Pad incomplete dates: [vu@2022-12] → [vu@2022-12-01]
        incomplete_date = re.search(r'\[vu@(\d{4}-\d{2})\]', migrated_marker, re.IGNORECASE)
        if incomplete_date:
            padded_date = f'{incomplete_date.group(1)}-01'
            # If Plex has a date in the same month or newer, use Plex's precise date
            last_viewed = obj.get('lastViewedAt') if obj else None
            if last_viewed:
                try:
                    plex_dt = _datetime.fromtimestamp(last_viewed)
                    plex_date_str = plex_dt.strftime('%Y-%m-%d')
                    if plex_date_str >= padded_date:  # Plex date is in same month or newer
                        migrated_marker = f'[vu@{plex_date_str}]'
                        ts_source = 'plex'
                    else:
                        migrated_marker = f'[vu@{padded_date}]'
                        ts_source = 'marker'
                except (OSError, ValueError):
                    migrated_marker = f'[vu@{padded_date}]'
                    ts_source = 'marker'
            else:
                migrated_marker = f'[vu@{padded_date}]'
                ts_source = 'marker'
        else:
            ts_source = 'marker'
    if is_dir:
        clean = name.replace(f' {vu_marker}', '').replace(f'.{vu_marker}', '').replace(vu_marker, '')
    else:
        clean = name.replace(f'.{vu_marker}', '').replace(f' {vu_marker}', '').replace(vu_marker, '')
    clean = clean.rstrip('. ')  # remove trailing dots/spaces from stripping
    # Store bare value without brackets (brackets are added by apply_markers/apply_markers_to_dir)
    bare_value = migrated_marker.strip('[]')
    entry = {'markers': {'watched': bare_value}, 'clean_name': clean}
    if is_dir:
        entry['is_dir'] = True
    return entry, ts_source

def _plex2disk_process_scope(scope_name, disk_map_config, items_with_paths, sidecar, dry_run,
                              is_dir=False, apply_fn=None, strip_fn=None, force=False):
    """Process one scope (files, movie dirs, season dirs, series dirs) for --plex2disk.

    Args:
        scope_name: Human-readable scope name for logging
        disk_map_config: The DISK_MAP / DISK_MAP_*_DIR config dict
        items_with_paths: list of (path, cache_key, obj) tuples
        sidecar: The sidecar dict (mutated in place)
        dry_run: If True, show changes without renaming
        is_dir: True if processing directories
        apply_fn: Function to apply markers (apply_markers or apply_markers_to_dir)
        strip_fn: Function to strip markers (strip_our_markers or strip_markers_from_dir)
        force: If True, remove markers when Plex has no value (destructive)

    Returns:
        tuple: (renamed_count, skipped_count, warning_count, error_count, renames_dict)
    """
    if not disk_map_config:
        return (0, 0, 0, 0, {})

    errors = validate_disk_map(disk_map_config)
    if errors:
        print(f"ERROR: Invalid {scope_name} configuration:")
        for e in errors:
            print(f"  {e}")
        return (0, 0, 0, 0, {})

    renamed_count = 0
    renames = {}  # old_path → new_path (for updating child paths in other scopes)
    skipped_count = 0
    warning_count = 0
    error_count = 0

    # Deduplicate paths — for dir scopes, prefer Season/Show objects over Episode objects
    seen_paths = {}  # path → (cache_key, obj)
    for path, cache_key, obj in items_with_paths:
        type_str = obj.get('type_str', '')
        if path in seen_paths:
            # Prefer the "owner" object for this scope (Season/Show over Episode)
            existing_type = seen_paths[path][1].get('type_str', '')
            if scope_name == 'DISK_MAP_SEASON_DIR' and type_str == 'Season' and existing_type != 'Season':
                seen_paths[path] = (cache_key, obj)
            elif scope_name == 'DISK_MAP_SERIES_DIR' and type_str == 'Show' and existing_type != 'Show':
                seen_paths[path] = (cache_key, obj)
            continue
        seen_paths[path] = (cache_key, obj)

    for path, (cache_key, obj) in seen_paths.items():
        name = os.path.basename(path)
        if name.startswith('.'):
            skipped_count += 1
            continue
        parent = os.path.dirname(path)

        # Build log prefix: LIBRARY|CACHE_KEY|
        lib = obj.get('library', '?')
        prefix = f"{lib}|{cache_key}| "

        # Get existing sidecar entry
        sidecar_entry = sidecar.get(path)

        # Legacy VU migration
        legacy_migrated = False
        if not sidecar_entry:
            sidecar_entry, ts_source = _migrate_legacy_vu_sidecar(name, is_dir=is_dir, obj=obj)
            if sidecar_entry:
                legacy_migrated = True
                if VRB or dry_run:
                    watched_val = sidecar_entry['markers'].get('watched', '')
                    if ts_source == 'plex':
                        print(f"{prefix}Registered marker (bare [vu] → {watched_val} from Plex): {name}")
                    elif ts_source == 'today':
                        print(f"{prefix}Registered marker (bare [vu] → {watched_val} using today): {name}")
                    elif ts_source == 'marker':
                        print(f"{prefix}Registered marker ({watched_val}): {name}")

        # Strip existing markers to get clean name
        # For legacy migration: use clean_name directly (disk has old [vu], sidecar has migrated [vu@...])
        if legacy_migrated and 'clean_name' in sidecar_entry:
            clean = sidecar_entry['clean_name']
        else:
            clean = strip_fn(name, sidecar_entry)

        # Compute new markers from Plex metadata
        new_markers = compute_markers(obj, cache_key, disk_map_config)

        # Apply merge strategy: compare new (Plex) vs existing (disk) per aspect
        if sidecar_entry and 'markers' in sidecar_entry:
            for aspect in set(list(new_markers.keys()) + list(sidecar_entry['markers'].keys())):
                new_val = new_markers.get(aspect, '')
                old_val = sidecar_entry['markers'].get(aspect, '')
                if force:
                    # --force: Plex is authoritative — always use Plex value (even empty)
                    new_markers[aspect] = new_val
                else:
                    merged = _merge_marker(aspect, new_val, old_val, DISK_MAP_MERGE)
                    if aspect in new_markers:
                        new_markers[aspect] = merged
                    elif merged:
                        new_markers[aspect] = merged

        # Handle previously-filled markers that are now empty
        if sidecar_entry and 'markers' in sidecar_entry:
            for aspect, old_val in sidecar_entry['markers'].items():
                if old_val and aspect in new_markers and not new_markers[aspect]:
                    if force:
                        print(f"{prefix}Removing [{aspect}] (was {old_val}): {name}")
                    else:
                        # Additive mode: preserve existing marker, don't remove
                        new_markers[aspect] = old_val
                        if VRB or dry_run:
                            print(f"{prefix}Preserving [{aspect}] ({old_val}): {name}  (Plex empty; use --force to remove)")

        # Build new name
        new_name = apply_fn(clean, new_markers)

        if new_name == name:
            skipped_count += 1
            continue

        new_path = os.path.join(parent, new_name)

        if dry_run:
            print(f"{prefix}Rename: {path} → {new_name}")
            renamed_count += 1
            renames[path] = new_path
        else:
            success, _ = rename_file(path, new_name, PLEX_DB_REMOTE_HOST)
            if success:
                renamed_count += 1
                renames[path] = new_path
                update_sidecar_entry(sidecar, path, new_path, new_markers, clean, is_dir=is_dir)
                # Update child paths in sidecar and cache after directory rename
                if is_dir:
                    _update_sidecar_child_paths(sidecar, path, new_path)
                    _update_cache_child_paths(path, new_path)
                else:
                    _update_cache_filepath(obj, path, new_path)
                if VRB:
                    print(f"{prefix}Rename: {path} → {new_name}")
            else:
                error_count += 1
                print(f"{prefix}ERROR renaming: {path}")

    return (renamed_count, skipped_count, warning_count, error_count, renames)

def _update_cache_child_paths(old_dir, new_dir):
    """After renaming a directory, update all file paths in the cache that reference old_dir (exact match or children)."""
    old_prefix = old_dir + os.sep
    new_prefix = new_dir + os.sep
    for key, obj in PLEX_Media.OBJ_BY_ID.items():
        # Update 'file' field — exact match (dir objects) or child paths
        f = obj.get('file', '')
        if f == old_dir:
            obj['file'] = new_dir
        elif f.startswith(old_prefix):
            obj['file'] = new_prefix + f[len(old_prefix):]
        # Update 'files' dict
        files = obj.get('files')
        if files and isinstance(files, dict):
            for version_str, file_info in files.items():
                if isinstance(file_info, dict):
                    fp = file_info.get('filepath', '')
                    if fp == old_dir:
                        file_info['filepath'] = new_dir
                    elif fp.startswith(old_prefix):
                        file_info['filepath'] = new_prefix + fp[len(old_prefix):]
                elif isinstance(file_info, str):
                    if file_info == old_dir:
                        files[version_str] = new_dir
                    elif file_info.startswith(old_prefix):
                        files[version_str] = new_prefix + file_info[len(old_prefix):]
    # Update OBJ_BY_FILEPATH
    if hasattr(PLEX_Media, 'OBJ_BY_FILEPATH') and PLEX_Media.OBJ_BY_FILEPATH:
        updates = {}
        removals = []
        for fp, val in PLEX_Media.OBJ_BY_FILEPATH.items():
            if fp == old_dir:
                removals.append(fp)
                updates[new_dir] = val
            elif fp.startswith(old_prefix):
                removals.append(fp)
                updates[new_prefix + fp[len(old_prefix):]] = val
        for fp in removals:
            del PLEX_Media.OBJ_BY_FILEPATH[fp]
        PLEX_Media.OBJ_BY_FILEPATH.update(updates)

def _update_sidecar_child_paths(sidecar, old_dir, new_dir):
    """After renaming a directory, update all child paths in the sidecar."""
    old_prefix = old_dir + os.sep
    new_prefix = new_dir + os.sep
    updates = {}
    removals = []
    for path in list(sidecar.keys()):
        if path.startswith(old_prefix):
            new_path = new_prefix + path[len(old_prefix):]
            removals.append(path)
            updates[new_path] = sidecar[path]
    for path in removals:
        del sidecar[path]
    sidecar.update(updates)

def cmd_plex2disk(target, dry_run=False, force=False):
    """Sync Plex metadata to disk markers (files + directories) using DISK_MAP config.

    Processes 4 scopes in order: series dirs → season dirs → movie dirs → files.
    (Outermost first so child paths stay valid during rename.)

    For each item in scope:
    1. Strip existing markers (from sidecar)
    2. Compute new markers from Plex metadata via eval() expressions
    3. Apply merge strategy (DISK_MAP_MERGE) to resolve conflicts
    4. Rename file/dir if markers changed
    5. Update sidecar

    Without --force (default, additive): existing markers on disk are preserved even
    if Plex has no value for that aspect. Only a WARNING is shown.

    With --force (destructive): Plex is authoritative. If Plex has no value for an
    aspect, the marker is actively REMOVED from disk.

    Args:
        target: None (all), library name, or media identifier
        dry_run: If True, show changes without renaming
        force: If True, Plex is authoritative — remove markers when Plex has no value
    """
    any_config = DISK_MAP or DISK_MAP_MOVIE_DIR or DISK_MAP_SERIES_DIR or DISK_MAP_SEASON_DIR
    if not any_config:
        print("ERROR: No DISK_MAP is configured.")
        print(f"  Configure it in your config file ({DISK_MAP_FILE.replace('/disk_map.json', '/my-plex.conf')})")
        print(f"  Example:")
        print(f"    DISK_MAP = {{'watched': \"'vu@' + WATCHED_DATE if WATCHED else ''\"}}")
        print(f"  Use --help plex2disk for details.")
        return

    items = _get_disk_map_scope(target)
    if not items:
        print("No media items found for the given target.")
        return

    sidecar = load_disk_map_sidecar()
    total_renamed = 0
    total_skipped = 0
    total_warnings = 0
    total_errors = 0

    scope_count = sum(1 for m in [DISK_MAP, DISK_MAP_MOVIE_DIR, DISK_MAP_SERIES_DIR, DISK_MAP_SEASON_DIR] if m)
    force_label = " --force" if force else ""
    if VRB:
        if dry_run:
            print(f"DRY RUN: --plex2disk{force_label} ({len(items)} items, {scope_count} scope(s))")
        else:
            print(f"Syncing Plex metadata to disk{force_label} ({len(items)} items, {scope_count} scope(s))...")

    # --- Collect paths for each scope ---
    file_items = []       # (filepath, cache_key, obj)
    movie_dir_items = []  # (dirpath, cache_key, obj)
    season_dir_items = [] # (dirpath, cache_key, obj)
    series_dir_items = [] # (dirpath, cache_key, obj)

    for cache_key, obj in items:
        obj_type = obj.get('type', '')
        type_str = obj.get('type_str', '')
        filepaths = _get_all_filepaths(obj)

        for filepath in filepaths:
            # File scope — only actual media files (Movie, Episode), not dir-only types
            if DISK_MAP and type_str in ('Movie', 'Episode'):
                file_items.append((filepath, cache_key, obj))

            # Movie directory scope
            if DISK_MAP_MOVIE_DIR and obj_type == 'Movie':
                movie_dir = get_movie_dir(obj)
                if movie_dir and os.path.basename(movie_dir) != os.path.basename(filepath):
                    movie_dir_items.append((movie_dir, cache_key, obj))

            # Season directory scope (from Season cache object, or Season object directly)
            if DISK_MAP_SEASON_DIR:
                if obj_type == 'Episode':
                    season_dir = get_season_dir(obj)
                    if season_dir:
                        season_dir_items.append((season_dir, cache_key, obj))
                elif type_str == 'Season':
                    season_dir_items.append((filepath, cache_key, obj))

            # Series directory scope (from Show cache object, or Show object directly)
            if DISK_MAP_SERIES_DIR:
                if obj_type == 'Episode':
                    series_dir = get_show_dir(obj)
                    if series_dir:
                        series_dir_items.append((series_dir, cache_key, obj))
                elif type_str == 'Show':
                    series_dir_items.append((filepath, cache_key, obj))

    # --- Process scopes: files → season dirs → series dirs → movie dirs ---
    # Innermost first: renaming a child doesn't affect parent paths.
    # After each dir rename, update child paths in cache + sidecar.

    # Per-scope stats for summary
    scope_stats = []

    # Files
    if DISK_MAP:
        n_files = len(set(p for p,_,_ in file_items))
        if VRB:
            print(f"\nFiles ({n_files}):")
        if file_items:
            r, s, w, e, _ = _plex2disk_process_scope('DISK_MAP', DISK_MAP,
                                                   file_items, sidecar, dry_run,
                                                   is_dir=False, apply_fn=apply_markers,
                                                   strip_fn=strip_our_markers, force=force)
            total_renamed += r; total_skipped += s; total_warnings += w; total_errors += e
            scope_stats.append(f"Files: {r} renamed, {s} unchanged (of {n_files})")

    # Season dirs
    if DISK_MAP_SEASON_DIR:
        n_seasons = len(set(p for p,_,_ in season_dir_items))
        if VRB:
            print(f"\nSeason directories ({n_seasons} unique):")
        if season_dir_items:
            r, s, w, e, _ = _plex2disk_process_scope('DISK_MAP_SEASON_DIR', DISK_MAP_SEASON_DIR,
                                                   season_dir_items, sidecar, dry_run,
                                                   is_dir=True, apply_fn=apply_markers_to_dir,
                                                   strip_fn=strip_markers_from_dir, force=force)
            total_renamed += r; total_skipped += s; total_warnings += w; total_errors += e
            scope_stats.append(f"Season dirs: {r} renamed, {s} unchanged (of {n_seasons})")

    # Series dirs
    if DISK_MAP_SERIES_DIR:
        n_series = len(set(p for p,_,_ in series_dir_items))
        if VRB:
            print(f"\nSeries directories ({n_series} unique):")
        if series_dir_items:
            r, s, w, e, _ = _plex2disk_process_scope('DISK_MAP_SERIES_DIR', DISK_MAP_SERIES_DIR,
                                                   series_dir_items, sidecar, dry_run,
                                                   is_dir=True, apply_fn=apply_markers_to_dir,
                                                   strip_fn=strip_markers_from_dir, force=force)
            total_renamed += r; total_skipped += s; total_warnings += w; total_errors += e
            scope_stats.append(f"Series dirs: {r} renamed, {s} unchanged (of {n_series})")

    # Movie dirs
    if DISK_MAP_MOVIE_DIR:
        n_movies = len(set(p for p,_,_ in movie_dir_items))
        if VRB:
            print(f"\nMovie directories ({n_movies} unique):")
        if movie_dir_items:
            r, s, w, e, _ = _plex2disk_process_scope('DISK_MAP_MOVIE_DIR', DISK_MAP_MOVIE_DIR,
                                                   movie_dir_items, sidecar, dry_run,
                                                   is_dir=True, apply_fn=apply_markers_to_dir,
                                                   strip_fn=strip_markers_from_dir, force=force)
            total_renamed += r; total_skipped += s; total_warnings += w; total_errors += e
            scope_stats.append(f"Movie dirs: {r} renamed, {s} unchanged (of {n_movies})")

    # Save sidecar and cache
    if not dry_run and total_renamed > 0:
        save_disk_map_sidecar(sidecar)
        update_and_save_cache(CACHE)

    # Summary (only with -V)
    if VRB:
        label = "Would rename" if dry_run else "Renamed"
        print(f"\n{label}: {total_renamed}, unchanged: {total_skipped}, warnings: {total_warnings}, errors: {total_errors}")
        for stat in scope_stats:
            print(f"  {stat}")

def _plex2disk_clean_scope(sidecar, paths, strip_fn, dry_run, is_dir=False):
    """Strip markers from a set of paths using sidecar data.

    Args:
        sidecar: Sidecar dict (mutated)
        paths: set of paths to clean
        strip_fn: strip_our_markers or strip_markers_from_dir
        dry_run: Preview mode
        is_dir: True if processing directories

    Returns:
        tuple: (renamed_count, skipped_count, error_count)
    """
    renamed = 0
    skipped = 0
    errors = 0
    for path in sorted(paths):
        sidecar_entry = sidecar.get(path)
        if not sidecar_entry:
            skipped += 1
            continue
        name = os.path.basename(path)
        clean = strip_fn(name, sidecar_entry)
        if clean == name:
            if path in sidecar:
                del sidecar[path]
            skipped += 1
            continue
        new_path = os.path.join(os.path.dirname(path), clean)
        if dry_run:
            print(f"  {name}")
            print(f"    → {clean}")
            renamed += 1
        else:
            success, _ = rename_file(path, clean, PLEX_DB_REMOTE_HOST)
            if success:
                renamed += 1
                if is_dir:
                    _update_sidecar_child_paths(sidecar, path, new_path)
                if path in sidecar:
                    del sidecar[path]
                if VRB:
                    print(f"  {name} → {clean}")
            else:
                errors += 1
                print(f"  ERROR renaming: {name}")
    return (renamed, skipped, errors)

def cmd_plex2disk_clean(target, dry_run=False):
    """Strip all disk markers from files and directories, clear sidecar entries.

    Processing order: innermost first (files → movie dirs → season dirs → series dirs)
    to prevent broken parent paths.

    Args:
        target: None (all), library name, or media identifier
        dry_run: If True, show changes without renaming
    """
    sidecar = load_disk_map_sidecar()
    if not sidecar:
        print("No disk map sidecar found — nothing to undo.")
        return

    items = _get_disk_map_scope(target)
    if not items:
        print("No media items found for the given target.")
        return

    if dry_run:
        print(f"DRY RUN: --plex2disk --clean ({len(items)} items)")
    else:
        print(f"Removing disk markers ({len(items)} items)...")

    total_renamed = 0
    total_skipped = 0
    total_errors = 0

    # Collect paths for each scope
    file_paths = set()
    movie_dir_paths = set()
    season_dir_paths = set()
    series_dir_paths = set()

    for cache_key, obj in items:
        obj_type = obj.get('type', '')
        filepaths = _get_all_filepaths(obj)
        for filepath in filepaths:
            file_paths.add(filepath)
            if obj_type == 'Movie':
                movie_dir = get_movie_dir(obj)
                if movie_dir and os.path.basename(movie_dir) != os.path.basename(filepath):
                    movie_dir_paths.add(movie_dir)
            if obj_type == 'Episode':
                season_dir = get_season_dir(obj)
                if season_dir:
                    season_dir_paths.add(season_dir)
                series_dir = get_show_dir(obj)
                if series_dir:
                    series_dir_paths.add(series_dir)

    # Process innermost first: files → movie dirs → season dirs → series dirs
    r, s, e = _plex2disk_clean_scope(sidecar, file_paths, strip_our_markers, dry_run)
    total_renamed += r; total_skipped += s; total_errors += e

    r, s, e = _plex2disk_clean_scope(sidecar, movie_dir_paths, strip_markers_from_dir, dry_run, is_dir=True)
    total_renamed += r; total_skipped += s; total_errors += e

    r, s, e = _plex2disk_clean_scope(sidecar, season_dir_paths, strip_markers_from_dir, dry_run, is_dir=True)
    total_renamed += r; total_skipped += s; total_errors += e

    r, s, e = _plex2disk_clean_scope(sidecar, series_dir_paths, strip_markers_from_dir, dry_run, is_dir=True)
    total_renamed += r; total_skipped += s; total_errors += e

    if not dry_run:
        save_disk_map_sidecar(sidecar)

    prefix = "Would strip" if dry_run else "Stripped"
    print(f"\n  {prefix}: {total_renamed}, unchanged: {total_skipped}, errors: {total_errors}")

def _disk2plex_push_watched(media, marker_value, dry_run):
    """Push watched status from disk marker to Plex.

    Extracts @TIMESTAMP from marker value (e.g. '[vu@2026-03-22]') and sets lastViewedAt.

    Returns:
        bool: True if push was performed/would be performed
    """
    from datetime import datetime
    if dry_run:
        print(f"    Would mark watched: {media.title}")
        return True
    media.markWatched()
    # Try to extract and set the watched date from the marker
    ts_match = re.search(r'@(\d{4}-\d{2}-\d{2})(?:[-_](\d{4}))?', str(marker_value))
    if ts_match and hasattr(media, 'lastViewedAt'):
        try:
            date_str = ts_match.group(1)
            time_str = ts_match.group(2)
            if time_str:
                dt = datetime.strptime(f"{date_str}_{time_str}", '%Y-%m-%d_%H%M')
            else:
                dt = datetime.strptime(date_str, '%Y-%m-%d')
            media.lastViewedAt = dt
            media.save()
        except (ValueError, Exception):
            pass  # markWatched() already succeeded, date is best-effort
    print(f"  Pushed watched to Plex: {media.title}")
    return True

def cmd_disk2plex(target, dry_run=False, force=False):
    """Sync disk markers to Plex metadata using DISK_MAP_PUSH config.

    For each item with sidecar entries:
    1. Read marker values from sidecar
    2. Resolve current Plex metadata
    3. Apply merge strategy (DISK_MAP_MERGE)
    4. If disk wins → push to Plex API (only writable fields)

    Without --force (default, additive): items without disk markers are skipped.
    No metadata is ever removed from Plex.

    With --force (destructive): disk is authoritative. If disk has NO marker for
    an aspect, the corresponding value is actively REMOVED from Plex (e.g. mark
    as unwatched, remove rating, remove labels/collections).

    Args:
        target: None (all), library name, or media identifier
        dry_run: If True, show what would be pushed without making changes
        force: If True, disk is authoritative — clear Plex values when no marker
    """
    if not DISK_MAP_PUSH:
        print("ERROR: DISK_MAP_PUSH is not configured — nothing to push.")
        return

    sidecar = load_disk_map_sidecar()
    if not sidecar and not force:
        print("No disk map sidecar found — nothing to push.")
        return
    if not sidecar:
        sidecar = {}

    items = _get_disk_map_scope(target)
    if not items:
        print("No media items found for the given target.")
        return

    if not dry_run:
        ensure_plex_api()

    pushed_count = 0
    skipped_count = 0
    error_count = 0

    force_label = " --force" if force else ""
    if VRB:
        if dry_run:
            print(f"DRY RUN: --disk2plex{force_label} ({len(items)} items, {len(DISK_MAP_PUSH)} aspects)")
        else:
            print(f"Syncing disk markers to Plex{force_label} ({len(items)} items, {len(DISK_MAP_PUSH)} aspects)...")

    removed_count = 0

    for cache_key, obj in items:
        obj_type = obj.get('type', '')
        filepaths = _get_all_filepaths(obj)

        for filepath in filepaths:
            sidecar_entry = sidecar.get(filepath)

            # For each aspect in DISK_MAP_PUSH, compare disk vs Plex
            for aspect, plex_field in DISK_MAP_PUSH.items():
                disk_value = ''
                if sidecar_entry and 'markers' in sidecar_entry:
                    disk_value = sidecar_entry['markers'].get(aspect, '')
                if not disk_value and not force:
                    skipped_count += 1
                    continue  # Additive only: no disk marker → don't touch Plex

                # Check if field is writable for this object type
                writable = _PLEX_WRITABLE_FIELDS.get(obj_type, set())
                if plex_field not in writable:
                    print(f"  WARNING: Cannot push {plex_field} to Plex for {obj_type} objects")
                    continue

                # Resolve current Plex metadata for comparison
                variables = resolve_disk_map_variables(obj, cache_key)

                # Compute what Plex currently has for this aspect (bare value, no brackets)
                plex_value = ''
                if plex_field == 'WATCHED' and variables.get('WATCHED'):
                    plex_value = f"vu@{variables.get('WATCHED_DATE', '')}" if variables.get('WATCHED_DATE') else 'vu'
                elif plex_field == 'RATING_USER' and variables.get('RATING_USER') is not None:
                    plex_value = str(variables['RATING_USER'])
                elif plex_field == 'LABELS' and variables.get('LABELS'):
                    plex_value = variables['LABELS']
                elif plex_field == 'COLLECTIONS' and variables.get('COLLECTIONS'):
                    plex_value = variables['COLLECTIONS']

                # --force with no disk marker: remove value from Plex
                if not disk_value and force:
                    if not plex_value:
                        skipped_count += 1
                        continue  # Already empty in Plex, nothing to remove
                    title = obj.get('title', cache_key)
                    try:
                        if plex_field in ('WATCHED', 'WATCHED_DATE', 'WATCHED_TS'):
                            if not dry_run:
                                plex = ensure_plex_api()
                                item_id = obj.get('item_id')
                                if item_id:
                                    media = plex.fetchItem(int(item_id))
                                    media.markUnwatched()
                                    print(f"  Removed watched from Plex: {title}")
                                    removed_count += 1
                                else:
                                    error_count += 1
                            else:
                                print(f"  Would mark unwatched: {title}")
                                removed_count += 1
                        elif plex_field == 'RATING_USER':
                            if not dry_run:
                                plex = ensure_plex_api()
                                item_id = obj.get('item_id')
                                if item_id:
                                    media = plex.fetchItem(int(item_id))
                                    media.rate(None)
                                    print(f"  Removed rating from Plex: {title}")
                                    removed_count += 1
                                else:
                                    error_count += 1
                            else:
                                print(f"  Would remove rating: {title}")
                                removed_count += 1
                        elif plex_field == 'LABELS':
                            if not dry_run:
                                plex = ensure_plex_api()
                                item_id = obj.get('item_id')
                                if item_id:
                                    media = plex.fetchItem(int(item_id))
                                    for lbl in (media.labels or []):
                                        media.removeLabel(lbl.tag)
                                    print(f"  Removed labels from Plex: {title}")
                                    removed_count += 1
                                else:
                                    error_count += 1
                            else:
                                print(f"  Would remove labels: {title}")
                                removed_count += 1
                        elif plex_field == 'COLLECTIONS':
                            if not dry_run:
                                plex = ensure_plex_api()
                                item_id = obj.get('item_id')
                                if item_id:
                                    media = plex.fetchItem(int(item_id))
                                    for coll in (media.collections or []):
                                        media.removeCollection(coll.tag)
                                    print(f"  Removed collections from Plex: {title}")
                                    removed_count += 1
                                else:
                                    error_count += 1
                            else:
                                print(f"  Would remove collections: {title}")
                                removed_count += 1
                    except Exception as ex:
                        print(f"  ERROR removing {plex_field} from Plex for {cache_key}: {ex}")
                        error_count += 1
                    continue

                # No disk value (and not force) was already handled above
                if not disk_value:
                    continue

                # Apply merge strategy
                if force:
                    # --force: disk is authoritative, skip merge
                    merged = disk_value
                else:
                    merged = _merge_marker(aspect, plex_value, disk_value, DISK_MAP_MERGE)

                if merged == plex_value:
                    # Plex already has the winning value
                    skipped_count += 1
                    continue

                # Disk wins — push to Plex
                if plex_field in ('WATCHED', 'WATCHED_DATE', 'WATCHED_TS'):
                    try:
                        if not dry_run:
                            plex = ensure_plex_api()
                            item_id = obj.get('item_id')
                            if item_id:
                                media = plex.fetchItem(int(item_id))
                                _disk2plex_push_watched(media, disk_value, dry_run=False)
                                pushed_count += 1
                            else:
                                print(f"  WARNING: No item_id for {cache_key}")
                                error_count += 1
                        else:
                            print(f"  Would mark watched: {obj.get('title', cache_key)} (from {disk_value})")
                            pushed_count += 1
                    except Exception as ex:
                        print(f"  ERROR pushing watched for {cache_key}: {ex}")
                        error_count += 1

                elif plex_field == 'RATING_USER':
                    try:
                        # Bare numeric rating value e.g. '7.5'
                        rating_val = float(disk_value)
                        if not dry_run:
                            plex = ensure_plex_api()
                            item_id = obj.get('item_id')
                            if item_id:
                                media = plex.fetchItem(int(item_id))
                                media.userRating = rating_val
                                media.save()
                                print(f"  Pushed rating {rating_val} to Plex: {media.title}")
                                pushed_count += 1
                            else:
                                error_count += 1
                        else:
                            print(f"  Would set rating to {rating_val}: {obj.get('title', cache_key)}")
                            pushed_count += 1
                    except (ValueError, Exception) as ex:
                        print(f"  ERROR pushing rating for {cache_key}: {ex}")
                        error_count += 1

                elif plex_field == 'LABELS':
                    try:
                        # Bare label value e.g. 'my-label'
                        if disk_value:
                            if not dry_run:
                                plex = ensure_plex_api()
                                item_id = obj.get('item_id')
                                if item_id:
                                    media = plex.fetchItem(int(item_id))
                                    media.addLabel(disk_value)
                                    print(f"  Pushed label '{disk_value}' to Plex: {media.title}")
                                    pushed_count += 1
                                else:
                                    error_count += 1
                            else:
                                print(f"  Would add label '{disk_value}': {obj.get('title', cache_key)}")
                                pushed_count += 1
                    except Exception as ex:
                        print(f"  ERROR pushing label for {cache_key}: {ex}")
                        error_count += 1

                elif plex_field == 'COLLECTIONS':
                    try:
                        if disk_value:
                            if not dry_run:
                                plex = ensure_plex_api()
                                item_id = obj.get('item_id')
                                if item_id:
                                    media = plex.fetchItem(int(item_id))
                                    media.addCollection(disk_value)
                                    print(f"  Pushed collection '{disk_value}' to Plex: {media.title}")
                                    pushed_count += 1
                                else:
                                    error_count += 1
                            else:
                                print(f"  Would add collection '{disk_value}': {obj.get('title', cache_key)}")
                                pushed_count += 1
                    except Exception as ex:
                        print(f"  ERROR pushing collection for {cache_key}: {ex}")
                        error_count += 1

    if VRB:
        label = "Would push" if dry_run else "Pushed"
        removed_label = f", removed: {removed_count}" if removed_count or force else ""
        print(f"\n{label}: {pushed_count}, unchanged: {skipped_count}{removed_label}, errors: {error_count}")

def _update_cache_filepath(obj, old_path, new_path):
    """Update filepath in cache entry after rename.

    Args:
        obj: Cache entry dict (mutated in place)
        old_path: Previous filepath
        new_path: New filepath
    """
    if obj.get('file') == old_path:
        obj['file'] = new_path
    files = obj.get('files')
    if files and isinstance(files, dict):
        for version_str, file_info in files.items():
            if isinstance(file_info, dict) and file_info.get('filepath') == old_path:
                file_info['filepath'] = new_path
            elif file_info == old_path:
                files[version_str] = new_path

def transfer_disk_map_markers(src_path, dst_path, remote_host=None, sidecar=None):
    """Transfer disk map markers from one file to another (for duplicate resolution).

    Looks up src_path in sidecar, applies those markers to dst_path.
    Also handles legacy VU migration: if src has a [vu] marker but no sidecar entry,
    creates a synthetic entry before transferring.

    Args:
        src_path: Source filepath (being trashed/removed)
        dst_path: Destination filepath (being kept)
        remote_host: SSH host for rename operations
        sidecar: Optional pre-loaded sidecar dict. If None, loads/saves automatically.
                 If provided, caller is responsible for saving.

    Returns:
        tuple: (success, new_dst_path, sidecar) — success bool, updated dst path, sidecar dict
    """
    owns_sidecar = sidecar is None
    if owns_sidecar:
        sidecar = load_disk_map_sidecar()

    src_entry = sidecar.get(src_path)

    # Legacy VU migration: detect [vu] marker on source without sidecar entry
    if not src_entry:
        src_basename = os.path.basename(src_path)
        src_entry, ts_source = _migrate_legacy_vu_sidecar(src_basename)
        if src_entry and VRB:
            print(f"  Registered marker from {src_basename} ({ts_source})")

    if not src_entry:
        if owns_sidecar:
            save_disk_map_sidecar(sidecar)
        return (False, dst_path, sidecar)

    dst_basename = os.path.basename(dst_path)
    dst_dir = os.path.dirname(dst_path)

    # Strip any existing markers from destination
    dst_sidecar_entry = sidecar.get(dst_path)
    clean_dst = strip_our_markers(dst_basename, dst_sidecar_entry)

    # Apply source markers to destination
    new_basename = apply_markers(clean_dst, src_entry['markers'])

    new_dst_path = dst_path
    transfer_success = True
    if new_basename != dst_basename:
        new_dst_path = os.path.join(dst_dir, new_basename)
        rename_ok, _ = rename_file(dst_path, new_basename, remote_host)
        if rename_ok:
            update_sidecar_entry(sidecar, dst_path, new_dst_path, src_entry['markers'], clean_dst)
            print(f"  Transferred markers from {os.path.basename(src_path)} to {new_basename}")
        else:
            print(f"  WARNING: Failed to transfer markers to {dst_basename}")
            new_dst_path = dst_path
            transfer_success = False

    # Remove source entry
    if src_path in sidecar:
        del sidecar[src_path]

    if owns_sidecar:
        save_disk_map_sidecar(sidecar)

    return (transfer_success, new_dst_path, sidecar)

def transfer_disk_map_markers_dir(src_dir, dst_dir, remote_host=None, sidecar=None):
    """Transfer disk map markers from one directory to another (for duplicate resolution).

    Works like transfer_disk_map_markers but for directory names (space-separated markers).

    Args:
        src_dir: Source directory path (being trashed/removed)
        dst_dir: Destination directory path (being kept)
        remote_host: SSH host for rename operations
        sidecar: Optional pre-loaded sidecar dict

    Returns:
        tuple: (success, new_dst_dir, sidecar)
    """
    owns_sidecar = sidecar is None
    if owns_sidecar:
        sidecar = load_disk_map_sidecar()

    src_entry = sidecar.get(src_dir)

    # Legacy VU migration
    if not src_entry:
        src_dirname = os.path.basename(src_dir)
        src_entry, ts_source = _migrate_legacy_vu_sidecar(src_dirname, is_dir=True)
        if src_entry and VRB:
            print(f"  Registered marker from dir {src_dirname} ({ts_source})")

    if not src_entry:
        if owns_sidecar:
            save_disk_map_sidecar(sidecar)
        return (False, dst_dir, sidecar)

    dst_dirname = os.path.basename(dst_dir)
    dst_parent = os.path.dirname(dst_dir)

    # Strip any existing markers from destination
    dst_sidecar_entry = sidecar.get(dst_dir)
    clean_dst = strip_markers_from_dir(dst_dirname, dst_sidecar_entry)

    # Apply source markers to destination
    new_dirname = apply_markers_to_dir(clean_dst, src_entry['markers'])

    new_dst_dir = dst_dir
    transfer_success = True
    if new_dirname != dst_dirname:
        new_dst_dir = os.path.join(dst_parent, new_dirname)
        rename_ok, _ = rename_file(dst_dir, new_dirname, remote_host)
        if rename_ok:
            update_sidecar_entry(sidecar, dst_dir, new_dst_dir, src_entry['markers'], clean_dst, is_dir=True)
            _update_sidecar_child_paths(sidecar, dst_dir, new_dst_dir)
            print(f"  Transferred dir markers from {os.path.basename(src_dir)} to {new_dirname}")
        else:
            print(f"  WARNING: Failed to transfer dir markers to {dst_dirname}")
            new_dst_dir = dst_dir
            transfer_success = False

    # Remove source entry
    if src_dir in sidecar:
        del sidecar[src_dir]

    if owns_sidecar:
        save_disk_map_sidecar(sidecar)

    return (transfer_success, new_dst_dir, sidecar)


# ---------------------------------------------------------------------------
# --sort-new command
# ---------------------------------------------------------------------------

VIDEO_EXTENSIONS = {'.avi', '.mkv', '.mp4', '.mpg', '.ts', '.wmv', '.m4v', '.flv', '.mov'}

def cmd_sort_new(args, dry_run=False, target=None):
    """Sort unsorted recordings into season directories for all series.

    Scans all show directories in series-type libraries for unsorted video files
    (files in the show root, not in season subdirs, without S##E## prefix).
    Matches file dates to episodes.tsv, renames with S##E## prefix, moves to season dir.

    If target is a library name, only process that library.
    """
    import os, subprocess, shlex
    from datetime import timedelta

    shows = get_all_shows_in_series_libraries()
    if target:
        # target can be a library name, a show cache key (e.g. "Show:12345"), or a show title
        shows = [(k, d, lib) for k, d, lib in shows
                 if lib == target or k == target or d.get('title', '').lower() == target.lower()]
    if not shows and not target:
        print("No shows found in series-type libraries.")
        # Fall through to movie section below

    total_sorted = 0
    total_failed = 0
    total_shows_processed = 0
    show_summaries = []  # (library_name, show_title, unsorted_count, sorted_count, failed_count)

    remote_host = PLEX_DB_REMOTE_HOST

    for show_key, show_dict, library_name in shows:
        show_title = show_dict.get('title', '?')
        show_dir_server = show_dict.get('file', '')
        if not show_dir_server:
            continue

        # READ: try local alternative path first, SSH fallback
        show_dir_local = get_local_path(show_dir_server)
        use_local = os.path.isdir(show_dir_local)

        # Find unsorted video files in show root (not in subdirs)
        unsorted = []
        if use_local:
            try:
                for fn in os.listdir(show_dir_local):
                    if fn.startswith('.'):
                        continue
                    fp = os.path.join(show_dir_local, fn)
                    if not os.path.isfile(fp):
                        continue
                    ext = os.path.splitext(fn)[1].lower()
                    if ext not in VIDEO_EXTENSIONS:
                        continue
                    if _re.match(r'^S\d+E\d+', fn):
                        continue
                    if fn.endswith('.sh') or fn.endswith('.tsv'):
                        continue
                    unsorted.append((fn, os.path.join(show_dir_server, fn)))
            except OSError:
                continue
        else:
            # SSH fallback: list files on server
            success, file_list = my_plex_file_operation('LIST_DIR', show_dir_server, remote_host, maxdepth=1)
            if not success or not file_list:
                continue
            for server_fp in file_list:
                fn = os.path.basename(server_fp)
                if fn.startswith('.'):
                    continue
                ext = os.path.splitext(fn)[1].lower()
                if ext not in VIDEO_EXTENSIONS:
                    continue
                if _re.match(r'^S\d+E\d+', fn):
                    continue
                if fn.endswith('.sh') or fn.endswith('.tsv'):
                    continue
                unsorted.append((fn, os.path.join(show_dir_server, fn)))

        if not unsorted:
            continue

        total_shows_processed += 1
        show_dir = show_dir_server  # All paths are server paths; writes go via SSH

        print(f"\n{show_key}: [{library_name}] [{show_title}] {len(unsorted)} unsorted file(s)")

        # Determine episode source for this show
        source = _determine_episode_source(show_dict)
        external_ids = show_dict.get('external_ids', {})

        # Load / update episodes.tsv (reads via local path or SSH)
        tsv_path = get_episodes_tsv_path(show_dir_local if use_local else show_dir_server)
        metadata, all_episodes = None, None

        metadata, all_episodes = read_episodes_tsv(tsv_path)
        if metadata is not None and is_episodes_tsv_stale(tsv_path):
            metadata, all_episodes = scrape_episodes(show_title, show_dir, source=source, external_ids=external_ids)

        if not all_episodes:
            # Try scraping
            print(f"    No episodes.tsv — attempting to scrape...")
            metadata, all_episodes = scrape_episodes(show_title, show_dir, source=source, force=True, external_ids=external_ids)

        # Print episode data summary
        if all_episodes:
            ep_source = metadata.get('source', source) if metadata else source
            max_s = max((ep['season'] for ep in all_episodes), default=0)
            print(f"  {ep_source.upper()}: {len(all_episodes)} episodes in {max_s} season(s)")

        # Build date lookup: date_str -> (season, episode, title)
        date_lookup = {}
        if all_episodes:
            for ep in all_episodes:
                date_lookup[ep['date']] = (ep['season'], ep['episode'], ep.get('title', ''))

        # Get specials pattern from metadata
        specials_pattern = metadata.get('specials_pattern') if metadata else None

        # Check for sort_specials.sh (local or SSH)
        specials_script = os.path.join(show_dir_server, 'sort_specials.sh')
        if use_local:
            has_specials_script = os.path.isfile(os.path.join(show_dir_local, 'sort_specials.sh'))
        else:
            has_specials_script = False  # Can't run local scripts via SSH

        def _sort_move(src_server, target_dir_server, new_name):
            """mkdir + move via SSH. Returns True on success."""
            escaped_dir = escape_path_for_ssh(target_dir_server)
            mkdir_cmd = ["ssh", remote_host, f"mkdir -p \"{escaped_dir}\""]
            result = subprocess.run(mkdir_cmd, capture_output=True, text=True)
            if result.returncode != 0:
                print(f"    ERROR: mkdir {os.path.basename(target_dir_server)}/: {result.stderr.strip()}")
                return False
            dst_server = os.path.join(target_dir_server, new_name)
            success, _ = my_plex_file_operation('MOVE', src_server, remote_host, dest_path=dst_server)
            return success

        # Sort files by name (chronological for TVOON dates)
        unsorted.sort(key=lambda x: x[0])

        sorted_count = 0
        failed_count = 0
        dry_run_lines = []  # (sort_key, line) for sorted dry-run output

        # Determine max episode number per season from cache (for absolute numbering detection)
        show_episodes = PLEX_Media.OBJ_BY_SHOW_EPISODES.get(show_key, {})
        max_ep_per_season = {}
        for s_str, eps in show_episodes.items():
            for e_str in eps:
                try:
                    max_ep_per_season[s_str] = max(max_ep_per_season.get(s_str, 0), int(e_str[1:]))
                except (ValueError, IndexError):
                    pass
        # Also check TSV data for max episode numbers
        if all_episodes:
            for ep in all_episodes:
                s_str = f"S{ep['season']:02d}"
                max_ep_per_season[s_str] = max(max_ep_per_season.get(s_str, 0), ep['episode'])

        for fn, fp in unsorted:
            # 1. Check if filename already contains S##E## — use directly, no date needed
            sxex_match = _re.search(r'S(\d+)E(\d+)', fn, _re.IGNORECASE)
            if sxex_match:
                season = int(sxex_match.group(1))
                ep_num = int(sxex_match.group(2))
                target_dir = os.path.join(show_dir, f"s{season:02d}")
                new_name = f"S{season:02d}E{ep_num:02d} - {fn}"
                target_path = os.path.join(target_dir, new_name)

                if dry_run:
                    dry_run_lines.append((season, ep_num, f"    [dry-run] [filename] S{season:02d}E{ep_num:02d}: {fn}"))
                else:
                    if not _sort_move(fp, target_dir, new_name):
                        print(f"    ERROR: Failed to move {fn}")
                        failed_count += 1
                        continue
                    print(f"    [filename] {fn} -> s{season:02d}/{new_name}")
                sorted_count += 1
                continue

            # 1b. Check for NxNN format (e.g., "1x01", "12x05")
            nxnn_match = _re.search(r'(?<!\d)(\d{1,2})x(\d{2,})(?!\d)', fn, _re.IGNORECASE)
            if nxnn_match:
                season = int(nxnn_match.group(1))
                ep_num = int(nxnn_match.group(2))
                target_dir = os.path.join(show_dir, f"s{season:02d}")
                new_name = f"S{season:02d}E{ep_num:02d} - {fn}"
                target_path = os.path.join(target_dir, new_name)

                if dry_run:
                    dry_run_lines.append((season, ep_num, f"    [dry-run] [filename] S{season:02d}E{ep_num:02d}: {fn}"))
                else:
                    if not _sort_move(fp, target_dir, new_name):
                        print(f"    ERROR: Failed to move {fn}")
                        failed_count += 1
                        continue
                    print(f"    [filename] {fn} -> s{season:02d}/{new_name}")
                sorted_count += 1
                continue

            # 1c. Check for absolute numbering (e.g., "101" → S01E01, "1203" → S12E03)
            #     Standalone 3+ digit number, bounded by non-digits (or separators like - _ .)
            abs_match = _re.search(r'(?:^|[^0-9])(\d{3,4})(?:[^0-9]|$)', fn)
            if abs_match:
                abs_num = int(abs_match.group(1))
                if abs_num >= 100:
                    candidate_season = abs_num // 100
                    candidate_ep = abs_num % 100
                    if candidate_ep > 0:
                        # Check: does any season already have episodes numbered >= abs_num?
                        # If so, this is a true episode number, not absolute S##E## encoding
                        is_true_episode_num = False
                        for s_str, max_ep in max_ep_per_season.items():
                            if max_ep >= abs_num:
                                is_true_episode_num = True
                                break
                        if not is_true_episode_num:
                            season = candidate_season
                            ep_num = candidate_ep
                            target_dir = os.path.join(show_dir, f"s{season:02d}")
                            new_name = f"S{season:02d}E{ep_num:02d} - {fn}"
                            target_path = os.path.join(target_dir, new_name)

                            if dry_run:
                                dry_run_lines.append((season, ep_num, f"    [dry-run] [absolute] S{season:02d}E{ep_num:02d}: {fn}"))
                            else:
                                if not _sort_move(fp, target_dir, new_name):
                                    print(f"    ERROR: Failed to move {fn}")
                                    failed_count += 1
                                    continue
                                print(f"    [absolute] {fn} -> s{season:02d}/{new_name}")
                            sorted_count += 1
                            continue

            # 1d. Check for bare leading episode number (e.g., "1.manimal.avi", "8.night of the beast.avi")
            #     Filename starts with 1-2 digit number followed by dot/separator, assume S01E##
            #     Excludes 3+ digits to avoid collision with absolute numbering and years
            bare_num_match = _re.match(r'^(\d{1,2})[.\-_ ]', fn)
            if bare_num_match:
                ep_num = int(bare_num_match.group(1))
                if 1 <= ep_num <= 99:
                    season = 1
                    target_dir = os.path.join(show_dir, f"s{season:02d}")
                    new_name = f"S{season:02d}E{ep_num:02d} - {fn}"
                    target_path = os.path.join(target_dir, new_name)

                    if dry_run:
                        dry_run_lines.append((season, ep_num, f"    [dry-run] [leading-num] S{season:02d}E{ep_num:02d}: {fn}"))
                    else:
                        if not _sort_move(fp, target_dir, new_name):
                            print(f"    ERROR: Failed to move {fn}")
                            failed_count += 1
                            continue
                        print(f"    [leading-num] {fn} -> s{season:02d}/{new_name}")
                    sorted_count += 1
                    continue

            # 2. Parse date from filename
            file_date = extract_episode_date(fn)
            if file_date is None:
                # 2b. Try year-based matching: extract year from (YYYY) or [YYYY] and match by title in TSV
                year_match = _re.search(r'[\(\[]((?:19|20)\d{2})[\)\]]', fn)
                if year_match and all_episodes:
                    file_year = year_match.group(1)
                    # Find TSV entries with matching year
                    year_candidates = [ep for ep in all_episodes if ep['date'].startswith(file_year)]
                    matched_ep = None
                    if len(year_candidates) == 1:
                        matched_ep = year_candidates[0]
                    elif len(year_candidates) > 1:
                        # Multiple entries in same year — match by title
                        fn_norm = _normalize_alpha(fn)
                        for ep in year_candidates:
                            if _normalize_alpha(ep.get('title', '')) in fn_norm or fn_norm in _normalize_alpha(ep.get('title', '') or ''):
                                matched_ep = ep
                                break
                        if not matched_ep:
                            # Try: normalized title is substring of normalized filename
                            for ep in year_candidates:
                                ep_title_norm = _normalize_alpha(ep.get('title', ''))
                                if ep_title_norm and ep_title_norm in fn_norm:
                                    matched_ep = ep
                                    break
                    if matched_ep:
                        season = matched_ep['season']
                        ep_num = matched_ep['episode']
                        target_dir = os.path.join(show_dir, f"s{season:02d}")
                        new_name = f"S{season:02d}E{ep_num:02d} - {fn}"
                        target_path = os.path.join(target_dir, new_name)
                        if dry_run:
                            dry_run_lines.append((season, ep_num, f"    [dry-run] [year] {file_year} -> S{season:02d}E{ep_num:02d}: {fn}"))
                        else:
                            if not _sort_move(fp, target_dir, new_name):
                                print(f"    ERROR: Failed to move {fn}")
                                failed_count += 1
                                continue
                            print(f"    [year] {file_year} -> s{season:02d}/{new_name}")
                        sorted_count += 1
                        continue
                if dry_run:
                    dry_run_lines.append((9999, 0, f"    WARNING: Cannot parse date from: {fn}"))
                else:
                    print(f"    WARNING: Cannot parse date from: {fn}")
                failed_count += 1
                continue

            iso_date = file_date.strftime('%Y-%m-%d')

            # Check for special episodes
            if is_special_episode(fn, specials_pattern):
                if has_specials_script:
                    # Delegate to sort_specials.sh
                    if dry_run:
                        dry_run_lines.append((0, 0, f"    [dry-run] {fn} -> sort_specials.sh"))
                    else:
                        try:
                            subprocess.run(['bash', specials_script, fp], check=True, cwd=show_dir)
                            print(f"    {fn} -> sort_specials.sh")
                        except subprocess.CalledProcessError as e:
                            print(f"    ERROR: sort_specials.sh failed for {fn}: {e}")
                            failed_count += 1
                            continue
                else:
                    # Default: move to specials/ as S00Exx
                    target_dir = os.path.join(show_dir, 'specials')
                    ep_num = _next_episode_in_dir(target_dir, 0)
                    new_name = f"S00E{ep_num:02d} - {fn}"
                    target_path = os.path.join(target_dir, new_name)
                    if dry_run:
                        dry_run_lines.append((0, ep_num, f"    [dry-run] {fn} -> specials/{new_name}"))
                    else:
                        if not _sort_move(fp, target_dir, new_name):
                            print(f"    ERROR: Failed to move {fn}")
                            failed_count += 1
                            continue
                        print(f"    {fn} -> specials/{new_name}")
                sorted_count += 1
                continue

            # 3. Look up date in TSV (also try previous day for rebroadcasts)
            result = date_lookup.get(iso_date)
            lookup_info = iso_date

            if result is None:
                prev_date = file_date - timedelta(days=1)
                prev_iso = prev_date.strftime('%Y-%m-%d')
                result = date_lookup.get(prev_iso)
                if result:
                    lookup_info = f"{prev_iso} (rebroadcast)"

            if result:
                season, ep_num, title = result
                target_dir = os.path.join(show_dir, f"s{season:02d}")
                new_name = f"S{season:02d}E{ep_num:02d} - {fn}"
                target_path = os.path.join(target_dir, new_name)

                if dry_run:
                    dry_run_lines.append((season, ep_num, f"    [dry-run] [tsv] {lookup_info} -> S{season:02d}E{ep_num:02d}: {fn}"))
                else:
                    if not _sort_move(fp, target_dir, new_name):
                        print(f"    ERROR: Failed to move {fn}")
                        failed_count += 1
                        continue
                    print(f"    [tsv] {lookup_info} -> s{season:02d}/{new_name}")
                sorted_count += 1
            else:
                # No TSV match — use fallback (latest season + sequential numbering)
                if all_episodes:
                    latest_season = max((ep['season'] for ep in all_episodes if ep['season'] > 0), default=1)
                else:
                    latest_season = 1
                target_dir = os.path.join(show_dir, f"s{latest_season:02d}")
                ep_num = _next_episode_in_dir(target_dir, latest_season)
                new_name = f"S{latest_season:02d}E{ep_num:02d} - {fn}"

                if dry_run:
                    dry_run_lines.append((latest_season, ep_num, f"    [dry-run] [fallback] {iso_date} -> S{latest_season:02d}E{ep_num:02d}: {fn}"))
                else:
                    if not _sort_move(fp, target_dir, new_name):
                        print(f"    ERROR: Failed to move {fn}")
                        failed_count += 1
                        continue
                    print(f"    [fallback] {iso_date} -> s{latest_season:02d}/{new_name}")
                sorted_count += 1

        # Print collected dry-run lines sorted by S##E##
        if dry_run and dry_run_lines:
            dry_run_lines.sort(key=lambda x: (x[0], x[1]))
            for _, _, line in dry_run_lines:
                print(line)

        total_sorted += sorted_count
        total_failed += failed_count
        show_summaries.append((show_key, library_name, show_title, len(unsorted), sorted_count, failed_count))

    # --- Movie libraries: create directories for bare video files ---
    movie_sorted = 0
    movie_failed = 0
    movie_libs_processed = 0
    movie_summaries = []  # (lib_name, bare_count, sorted_count, failed_count)

    for lib_name, lib_type in PLEX_Library.OBJ_DICT_TYPE.items():
        if lib_type != 'Movie':
            continue
        if lib_name not in PLEX_Library.OBJ_DICT_SUPPORTED:
            continue
        if target and lib_name != target:
            continue

        # Get library root path(s) from cache
        lib_obj = PLEX_Library.OBJ_DICT.get(lib_name)
        if not lib_obj or not getattr(lib_obj, 'locations', []):
            continue
        lib_roots = lib_obj.locations

        remote_host = PLEX_DB_REMOTE_HOST
        lib_bare_count = 0
        lib_sorted_count = 0
        lib_failed_count = 0

        for lib_root_server in sorted(lib_roots):
            # READ: try local alternative path first, SSH fallback
            lib_root_local = get_local_path(lib_root_server)
            use_local = os.path.isdir(lib_root_local)

            if use_local:
                # List files locally via alternative path
                bare_files = []
                all_root_files = []
                try:
                    for fn in os.listdir(lib_root_local):
                        if fn.startswith('.'):
                            continue
                        fp = os.path.join(lib_root_local, fn)
                        if not os.path.isfile(fp):
                            continue
                        all_root_files.append(fn)
                        ext = os.path.splitext(fn)[1].lower()
                        if ext in VIDEO_EXTENSIONS:
                            bare_files.append(fn)
                except OSError:
                    continue
            else:
                # SSH fallback: list files on server
                success, file_list = my_plex_file_operation('LIST_DIR', lib_root_server, remote_host, maxdepth=1)
                if not success or not file_list:
                    continue
                all_root_files = []
                bare_files = []
                for fp in file_list:
                    fn = os.path.basename(fp)
                    if fn.startswith('.'):
                        continue
                    all_root_files.append(fn)
                    ext = os.path.splitext(fn)[1].lower()
                    if ext in VIDEO_EXTENSIONS:
                        bare_files.append(fn)

            if not bare_files:
                continue

            movie_libs_processed += 1
            lib_bare_count += len(bare_files)
            bare_files.sort()
            print(f"\n[{lib_name}] {len(bare_files)} movie file(s) without directory")

            for fn in bare_files:
                stem = os.path.splitext(fn)[0]
                # Directory name: lowercase, spaces/underscores → dots
                dir_name = stem.lower()
                dir_name = _re.sub(r'[\s_]+', '.', dir_name)

                # Collect sibling files (same stem, different extensions including .de.srt etc.)
                stem_dot = stem + '.'
                siblings = [s for s in all_root_files if s != fn and s.startswith(stem_dot)]
                all_files = [fn] + sorted(siblings)

                if dry_run:
                    print(f"    [dry-run] mkdir {dir_name}/")
                    for f in all_files:
                        print(f"    [dry-run]   mv {f} → {dir_name}/{f}")
                    movie_sorted += 1
                    lib_sorted_count += 1
                else:
                    # WRITE: always use SSH on server path
                    target_dir_server = os.path.join(lib_root_server, dir_name)
                    escaped_dir = escape_path_for_ssh(target_dir_server)
                    mkdir_cmd = ["ssh", remote_host, f"mkdir -p \"{escaped_dir}\""]
                    result = subprocess.run(mkdir_cmd, capture_output=True, text=True)
                    if result.returncode != 0:
                        print(f"    ERROR: mkdir {dir_name}/: {result.stderr.strip()}")
                        movie_failed += 1
                        lib_failed_count += 1
                        continue

                    move_ok = True
                    for f in all_files:
                        src_server = os.path.join(lib_root_server, f)
                        dst_server = os.path.join(target_dir_server, f)
                        success, _ = my_plex_file_operation('MOVE', src_server, remote_host, dest_path=dst_server)
                        if not success:
                            move_ok = False

                    if move_ok:
                        print(f"    {fn} → {dir_name}/ ({len(all_files)} file(s))")
                        movie_sorted += 1
                        lib_sorted_count += 1
                    else:
                        print(f"    ERROR: {fn}: some files failed to move")
                        movie_failed += 1
                        lib_failed_count += 1

        if lib_bare_count > 0:
            movie_summaries.append((lib_name, lib_bare_count, lib_sorted_count, lib_failed_count))

    # Skip summary when targeting a specific show (not a library)
    single_target = target and target not in PLEX_Library.OBJ_DICT

    if total_shows_processed > 0 or movie_libs_processed > 0:
        if not single_target:
            # Per-item summary
            if show_summaries or movie_summaries:
                print(f"\nSummary:")
                for s_key, lib_name, show_title, unsorted_count, sorted_count, failed_count in show_summaries:
                    status = f"{sorted_count} sorted"
                    if failed_count > 0:
                        status += f", {failed_count} failed"
                    print(f"  {s_key}: [{lib_name}] [{show_title}] {unsorted_count} unsorted file(s), {status}")
                for lib_name, bare_count, sorted_count, failed_count in movie_summaries:
                    status = f"{sorted_count} sorted"
                    if failed_count > 0:
                        status += f", {failed_count} failed"
                    print(f"  [{lib_name}] {bare_count} movie file(s) without directory, {status}")

            # Totals
            parts = []
            if total_shows_processed > 0:
                parts.append(f"{total_sorted} episodes sorted, {total_failed} failed across {total_shows_processed} show(s)")
            if movie_libs_processed > 0:
                parts.append(f"{movie_sorted} movies sorted, {movie_failed} failed across {movie_libs_processed} library(ies)")
            print(f"\nDone: {'; '.join(parts)}")
    else:
        print("\nNothing to sort.")


def _next_episode_in_dir(directory, season_num):
    """Find the next available episode number in a season directory."""
    import os
    spad = f"S{season_num:02d}"
    max_ep = 0
    if os.path.isdir(directory):
        for fn in os.listdir(directory):
            m = _re.search(rf'{spad}E(\d+)', fn)
            if m:
                ep = int(m.group(1))
                if ep > max_ep:
                    max_ep = ep
    return max_ep + 1


